        assert_eq!(bead["stale_state"], "conflicting_evidence");
        assert_eq!(bead["recommended_action"], "manual-review");
        assert!(
            bead["claim_blockers"]
                .as_array()
                .expect("claim blockers")
                .contains(&json!("recent-commit"))
        );
