#[allow(clippy::too_many_arguments)]
fn run_cli_search(
    query: &str,
    agents: &[String],
    workspaces: &[String],
    limit: &usize,
    offset: &usize,
    json: &bool,
    robot_format: Option<RobotFormat>,
    robot_meta: bool,
    fields: Option<Vec<String>>,
    max_content_length: Option<usize>,
    max_tokens: Option<usize>,
    request_id: Option<String>,
    cursor: Option<String>,
    display_format: Option<DisplayFormat>,
    data_dir_override: &Option<PathBuf>,
    db_override: Option<PathBuf>,
    wrap: WrapConfig,
    _progress: ProgressResolved,
    robot_auto: bool,
    time_filter: TimeFilter,
    aggregate: Option<Vec<String>>,
    explain: bool,
    dry_run: bool,
    timeout_ms: Option<u64>,
    highlight: bool,
    source: Option<String>,
    sessions_from: Option<String>,
    mode: Option<crate::search::query::SearchMode>,
    semantic_opts: SemanticSearchOptions,
) -> CliResult<()> {
    use crate::search::model_manager::{load_hash_semantic_context, load_semantic_context};
    use crate::search::query::{
        QueryExplanation, SearchClient, SearchClientOptions, SearchFilters, SearchMode,
    };

    use crate::sources::provenance::SourceFilter;
    use std::collections::HashSet;
    use std::sync::Arc;

    // Start timing for robot_meta elapsed_ms
    let start_time = Instant::now();

    let data_dir = data_dir_override.clone().unwrap_or_else(default_data_dir);
    let index_path = crate::search::tantivy::expected_index_dir(&data_dir);
    let db_path = db_override.unwrap_or_else(|| data_dir.join("agent_search.db"));
    let db_exists = db_path.exists();

    let mut filters = SearchFilters::default();
    if !agents.is_empty() {
        filters.agents = HashSet::from_iter(agents.iter().cloned());
    }
    if !workspaces.is_empty() {
        filters.workspaces = HashSet::from_iter(workspaces.iter().cloned());
    }
    filters.created_from = time_filter.since;
    filters.created_to = time_filter.until;

    // Apply source filter (P3.1)
    if let Some(ref source_str) = source {
        filters.source_filter = SourceFilter::parse(source_str);
    }

    // Apply session paths filter (for chained searches)
    if let Some(ref sessions_from_arg) = sessions_from {
        let session_paths = read_session_paths(sessions_from_arg).map_err(|e| CliError {
            code: 2,
            kind: CliErrorKind::SessionsFrom.kind_str(),
            message: format!("failed to read session paths: {e}"),
            hint: Some("Provide a file path or '-' for stdin".to_string()),
            retryable: false,
        })?;
        filters.session_paths = session_paths;
    }

    // Apply cursor overrides (base64-encoded JSON { "offset": usize, "limit": usize })
    let mut limit_val = *limit;
    let mut offset_val = *offset;
    if let Some(ref cursor_str) = cursor {
        let decoded = BASE64_STANDARD.decode(cursor_str).map_err(|e| CliError {
            code: 2,
            kind: CliErrorKind::CursorDecode.kind_str(),
            message: format!("invalid cursor: {e}"),
            hint: Some("Pass cursor returned in previous _meta.next_cursor".to_string()),
            retryable: false,
        })?;
        let cursor_json: serde_json::Value =
            serde_json::from_slice(&decoded).map_err(|e| CliError {
                code: 2,
                kind: CliErrorKind::CursorParse.kind_str(),
                message: format!("invalid cursor payload: {e}"),
                hint: Some("Cursor should be base64 of {\"offset\":N,\"limit\":M}".to_string()),
                retryable: false,
            })?;
        if let Some(o) = cursor_json
            .get("offset")
            .and_then(serde_json::Value::as_u64)
        {
            offset_val = o as usize;
        }
        if let Some(l) = cursor_json.get("limit").and_then(serde_json::Value::as_u64) {
            limit_val = l as usize;
        }
    }

    // Determine the effective output format
    // Priority: robot_format CLI > json flag > CASS_OUTPUT_FORMAT > TOON_DEFAULT_FORMAT > robot_auto > None
    let effective_robot = robot_format
        .or(if *json { Some(RobotFormat::Json) } else { None })
        .or_else(robot_format_from_env)
        .or(if robot_auto {
            Some(RobotFormat::Json)
        } else {
            None
        });
    let field_mask_visible_limit = token_budget_field_mask_visible_limit(max_tokens, limit_val);
    let field_mask = resolve_field_mask(
        &fields,
        max_content_length,
        max_tokens,
        field_mask_visible_limit,
        effective_robot,
        display_format,
    );

    // Parse aggregate fields if provided
    let agg_fields = aggregate
        .as_ref()
        .map(|f| parse_aggregate_fields(f))
        .transpose()?
        .unwrap_or_default();
    let has_aggregation = !agg_fields.is_empty();

    // Handle dry-run mode before touching derived search assets. A dry run is
    // query analysis only, so it must work on a fresh data dir with no DB/index.
    if dry_run {
        let explanation = QueryExplanation::analyze(query, &filters);
        let elapsed_ms = start_time.elapsed().as_millis();
        let meta = search_dry_run_meta(robot_meta, elapsed_ms);

        let output = serde_json::json!({
            "dry_run": true,
            "valid": explanation.warnings.iter().all(|w| !w.contains("error") && !w.contains("invalid")),
            "query": query,
            "explanation": explanation,
            "estimated_cost": format!("{:?}", explanation.estimated_cost),
            "warnings": explanation.warnings,
            "request_id": request_id,
            "_meta": meta,
        });

        println!(
            "{}",
            serde_json::to_string_pretty(&output).unwrap_or_else(|_| output.to_string())
        );
        return Ok(());
    }

    let search_self_heal = ensure_lexical_assets_for_search(
        &data_dir,
        &db_path,
        &index_path,
        timeout_ms,
        start_time,
        dry_run,
    )?;
    if search_self_heal.action != "skipped" {
        tracing::info!(
            action = search_self_heal.action,
            reason = search_self_heal.reason.as_deref(),
            indexed_docs = search_self_heal.indexed_docs,
            "search lexical self-heal completed"
        );
    }
    let tantivy_index_initialized = crate::search::tantivy::searchable_index_exists(&index_path);
    let rebuild_active = probe_index_run_lock(&data_dir, &db_path).active;

    let client = SearchClient::open_with_options(
        &index_path,
        Some(&db_path),
        SearchClientOptions {
            enable_reload: false,
            enable_warm: false,
        },
    )
    .map_err(|e| CliError {
        code: 9,
        kind: CliErrorKind::OpenIndex.kind_str(),
        message: format!("failed to open index: {e}"),
        hint: Some("try cass index --full".to_string()),
        retryable: true,
    })?
    .ok_or_else(|| {
        let (message, hint) = if rebuild_active && !tantivy_index_initialized {
            (
                format!(
                    "cass is already building the initial search index in {}. Search will become available when that index run finishes.",
                    data_dir.display()
                ),
                Some("Wait for the active 'cass index' run to finish, or inspect progress with 'cass status --json'.".to_string()),
            )
        } else if cass_not_initialized(db_exists, tantivy_index_initialized, rebuild_active) {
            (
                format!(
                    "cass has not been initialized in {} yet, so search cannot run until the first index completes.",
                    data_dir.display()
                ),
                Some(cass_not_initialized_recommended_action()),
            )
        } else if db_exists && !tantivy_index_initialized {
            (
                format!(
                    "Search index not found at {}. The archive database exists, but the Tantivy index has not been built yet.",
                    index_path.display()
                ),
                Some("Run 'cass index --full' to build the search index for this archive.".to_string()),
            )
        } else if !db_exists && tantivy_index_initialized {
            (
                format!(
                    "Search index exists at {}, but the archive database {} is missing.",
                    index_path.display(),
                    db_path.display()
                ),
                Some("Run 'cass index --full' to recreate the local archive database.".to_string()),
            )
        } else {
            (
                format!(
                    "Index not found at {}. Run 'cass index --full' first.",
                    index_path.display()
                ),
                Some("Run 'cass index --full' to create the local archive and search index.".to_string()),
            )
        };
        CliError {
            code: 3,
            kind: CliErrorKind::MissingIndex.kind_str(),
            message,
            hint,
            retryable: true,
        }
    })?;

    if !client.has_tantivy() {
        eprintln!(
            "Warning: Tantivy search index not found at {}. \
             Results will be severely limited. \
             Run `cass index --full` to rebuild the index.",
            index_path.display()
        );
    }

    // Hybrid is a preference for semantic refinement, not a strict dependency.
    // If semantic assets are unavailable, hybrid searches fail open to lexical
    // while robot metadata reports the realized mode and fallback reason.
    let mut mode_meta = SearchModeMeta::new(mode.unwrap_or_default(), mode.is_none());
    let hybrid_fail_open = mode_meta.fail_open_on_semantic_unavailable();

    if semantic_opts.tier_mode != crate::search::query::SemanticTierMode::Single
        && !matches!(mode_meta.requested, SearchMode::Semantic)
    {
        eprintln!("Warning: tier flags currently only affect --mode semantic.");
    }

    if matches!(
        mode_meta.requested,
        SearchMode::Semantic | SearchMode::Hybrid
    ) {
        use crate::search::embedder_registry::{EmbedderRegistry, HASH_EMBEDDER};

        // Use embedder registry for model selection (bd-2mbe)
        let registry = EmbedderRegistry::new(&data_dir);
        let requested_model = semantic_opts.model.as_deref();

        // Validate requested model if specified
        if let Some(model_name) = requested_model
            && let Err(e) = registry.validate(model_name)
        {
            return Err(CliError {
                code: 15,
                kind: CliErrorKind::EmbedderUnavailable.kind_str(),
                message: format!("Embedder validation failed: {e}"),
                hint: Some("Run 'cass models list' to see available embedders".to_string()),
                retryable: false,
            });
        }

        // Determine which embedder to use
        let embedder_info = match requested_model {
            Some(name) => registry.get(name),
            None => Some(registry.best_available()),
        };
        let prefer_hash = embedder_info.is_some_and(|e| e.name == HASH_EMBEDDER);

        let setup = if prefer_hash {
            load_hash_semantic_context(&data_dir, &db_path)
        } else {
            load_semantic_context(&data_dir, &db_path)
        };

        if let Some(context) = setup.context {
            let embedder = context.embedder;
            let index = context.index;
            let additional_indexes = context.additional_indexes;
            let filter_maps = context.filter_maps;
            let roles = context.roles;

            let embedder: Arc<dyn crate::search::embedder::Embedder> = if semantic_opts.use_daemon {
                use crate::search::daemon_client::{DaemonFallbackEmbedder, DaemonRetryConfig};

                #[cfg(unix)]
                {
                    let daemon = crate::daemon::client::try_connect()
                        .map(|d| d as Arc<dyn crate::search::daemon_client::DaemonClient>)
                        .unwrap_or_else(|| {
                            Arc::new(crate::search::daemon_client::NoopDaemonClient::new(
                                "daemon-unconfigured",
                            ))
                        });
                    let config = DaemonRetryConfig::from_env();
                    Arc::new(DaemonFallbackEmbedder::new(daemon, embedder, config))
                }
                #[cfg(not(unix))]
                {
                    let daemon = Arc::new(crate::search::daemon_client::NoopDaemonClient::new(
                        "daemon-unconfigured",
                    ));
                    let config = DaemonRetryConfig::from_env();
                    Arc::new(DaemonFallbackEmbedder::new(daemon, embedder, config))
                }
            } else {
                embedder
            };

            let ann_path = Some(
                data_dir
                    .join(crate::search::vector_index::VECTOR_INDEX_DIR)
                    .join(format!("hnsw-{}.chsw", embedder.id())),
            );
            let mut indexes = Vec::with_capacity(additional_indexes.len().saturating_add(1));
            indexes.push(index);
            indexes.extend(additional_indexes);
            if let Err(err) =
                client.set_semantic_indexes_context(embedder, indexes, filter_maps, roles, ann_path)
            {
                let hint = if prefer_hash {
                    "Run 'cass index --semantic --embedder hash' to rebuild the hash vector index, or use --mode lexical"
                        .to_string()
                } else {
                    "Run 'cass models install' and then 'cass index --semantic', or use --mode lexical"
                        .to_string()
                };
                if hybrid_fail_open {
                    mode_meta.fall_back_to_lexical(format!("semantic context rejected: {err}"));
                    let _ = client.clear_semantic_context();
                } else {
                    return Err(CliError {
                        code: 15,
                        kind: CliErrorKind::SemanticUnavailable.kind_str(),
                        message: format!("Semantic search not available: {err}"),
                        hint: Some(hint),
                        retryable: false,
                    });
                }
            }
        } else {
            let _ = client.clear_semantic_context();
            let summary = setup.availability.summary();
            let hint = if prefer_hash {
                "Run 'cass index --semantic --embedder hash' to build the hash vector index, or use --mode lexical"
                    .to_string()
            } else {
                "Run 'cass models install' and then 'cass index --semantic', or use --mode lexical"
                    .to_string()
            };
            if hybrid_fail_open {
                mode_meta.fall_back_to_lexical(format!("semantic context unavailable: {summary}"));
            } else {
                return Err(CliError {
                    code: 15,
                    kind: CliErrorKind::SemanticUnavailable.kind_str(),
                    message: format!("Semantic search not available: {summary}"),
                    hint: Some(hint),
                    retryable: false,
                });
            }
        }
    }

    let approximate =
        if semantic_opts.approximate && matches!(mode_meta.realized, SearchMode::Lexical) {
            eprintln!("Warning: --approximate has no effect in lexical mode.");
            false
        } else {
            semantic_opts.approximate
        };

    // Use search_with_fallback to get full metadata (wildcard_fallback, cache_stats)
    let sparse_threshold = 3; // Threshold for triggering wildcard fallback

    // When aggregating, we need more results for accurate counts.
    // For non-aggregation mode, overfetch by one so cursor pagination can reliably
    // signal whether additional pages exist without a second query.
    let token_budget_page_limit = token_budget_search_limit(max_tokens);
    let cursor_page_limit = if has_aggregation {
        limit_val
    } else if limit_val == 0 {
        token_budget_page_limit.unwrap_or(0)
    } else {
        limit_val
    };
    let (search_limit, search_offset) = if has_aggregation {
        (1000.max(limit_val + offset_val), 0)
    } else if limit_val == 0 {
        match token_budget_page_limit {
            Some(page_limit) => (page_limit.saturating_add(1), offset_val),
            None => (0, offset_val),
        }
    } else {
        (limit_val.saturating_add(1), offset_val)
    };
    let sparse_visible_limit = if limit_val == 0 && cursor_page_limit > 0 {
        cursor_page_limit
    } else {
        limit_val
    };
    let search_sparse_threshold =
        sparse_threshold_for_visible_limit(sparse_threshold, sparse_visible_limit, has_aggregation);

    // Check if we're already past timeout before starting search
    let timeout_duration = timeout_ms.map(Duration::from_millis);
    if let Some(timeout) = timeout_duration
        && start_time.elapsed() >= timeout
    {
        return Err(CliError {
            code: 10,
            kind: CliErrorKind::Timeout.kind_str(),
            message: format!(
                "Operation timed out after {}ms (before search started)",
                timeout.as_millis()
            ),
            hint: Some("Increase --timeout value or simplify query".to_string()),
            retryable: true,
        });
    }

    // Log semantic options if any are set (bd-3bbv: flags are wired, infra pending)
    if semantic_opts.model.is_some()
        || semantic_opts.rerank
        || semantic_opts.reranker.is_some()
        || semantic_opts.use_daemon
        || semantic_opts.approximate
        || semantic_opts.tier_mode != crate::search::query::SemanticTierMode::Single
    {
        tracing::debug!(
            model = ?semantic_opts.model,
            rerank = semantic_opts.rerank,
            reranker = ?semantic_opts.reranker,
            use_daemon = semantic_opts.use_daemon,
            approximate = semantic_opts.approximate,
            tier_mode = ?semantic_opts.tier_mode,
            "Semantic search options configured"
        );
    }

    // Track search timing breakdown (T7.4)
    let search_start = Instant::now();
    let result = match mode_meta.realized {
        SearchMode::Lexical => client
            .search_with_fallback(
                query,
                filters.clone(),
                search_limit,
                search_offset,
                search_sparse_threshold,
                field_mask,
            )
            .map_err(|e| CliError {
                code: 9,
                kind: CliErrorKind::Search.kind_str(),
                message: format!("search failed: {e}"),
                hint: None,
                retryable: true,
            })?,
        SearchMode::Semantic => {
            let (hits, ann_stats) = client
                .search_semantic_with_tier(
                    query,
                    filters.clone(),
                    search_limit,
                    search_offset,
                    field_mask,
                    approximate,
                    semantic_opts.tier_mode,
                )
                .map_err(|e| {
                    let err_str = e.to_string();
                    if err_str.contains("HNSW index") {
                        CliError {
                            code: 15,
                            kind: CliErrorKind::SemanticUnavailable.kind_str(),
                            message: "Approximate search unavailable (HNSW index missing)".to_string(),
                            hint: Some(
                                "Run 'cass index --semantic --build-hnsw' to build the ANN index, or omit --approximate"
                                    .to_string(),
                            ),
                            retryable: false,
                        }
                    } else if err_str.contains("unavailable") || err_str.contains("no embedder") {
                        CliError {
                            code: 15,
                            kind: CliErrorKind::SemanticUnavailable.kind_str(),
                            message: "Semantic search not available".to_string(),
                            hint: Some(
                                "Run 'cass tui' and press Alt+S to set up semantic search, or use --mode lexical"
                                    .to_string(),
                            ),
                            retryable: false,
                        }
                    } else {
                        CliError {
                            code: 9,
                            kind: CliErrorKind::Search.kind_str(),
                            message: format!("semantic search failed: {e}"),
                            hint: Some("Try --mode lexical as fallback".to_string()),
                            retryable: true,
                        }
                    }
                })?;
            crate::search::query::SearchResult {
                hits,
                wildcard_fallback: false,
                cache_stats: crate::search::query::CacheStats::default(),
                suggestions: Vec::new(),
                ann_stats,
                total_count: None,
            }
        }
        SearchMode::Hybrid => match client.search_hybrid(
            query,
            query,
            filters.clone(),
            search_limit,
            search_offset,
            search_sparse_threshold,
            field_mask,
            approximate,
        ) {
            Ok(result) => result,
            Err(e) => {
                let err_str = e.to_string();
                if hybrid_fail_open
                    && (err_str.contains("unavailable") || err_str.contains("no embedder"))
                {
                    mode_meta.fall_back_to_lexical(format!("hybrid execution unavailable: {e}"));
                    client
                        .search_with_fallback(
                            query,
                            filters.clone(),
                            search_limit,
                            search_offset,
                            search_sparse_threshold,
                            field_mask,
                        )
                        .map_err(|fallback_err| CliError {
                            code: 9,
                            kind: CliErrorKind::Search.kind_str(),
                            message: format!(
                                "hybrid search failed ({e}); lexical fallback failed: {fallback_err}"
                            ),
                            hint: None,
                            retryable: true,
                        })?
                } else if err_str.contains("unavailable") || err_str.contains("no embedder") {
                    return Err(CliError {
                        code: 15,
                        kind: CliErrorKind::SemanticUnavailable.kind_str(),
                        message: "Hybrid search not available (requires semantic search)".to_string(),
                        hint: Some(
                            "Run 'cass tui' and press Alt+S to set up semantic search, or use --mode lexical"
                                .to_string(),
                        ),
                        retryable: false,
                    });
                } else {
                    return Err(CliError {
                        code: 9,
                        kind: CliErrorKind::Search.kind_str(),
                        message: format!("hybrid search failed: {e}"),
                        hint: Some("Try --mode lexical as fallback".to_string()),
                        retryable: true,
                    });
                }
            }
        },
    };
    let search_ms = search_start.elapsed().as_millis() as u64;

    // Apply reranking if enabled (bd-2t2d)
    let rerank_start = Instant::now();
    let result = if semantic_opts.rerank && !result.hits.is_empty() {
        use crate::search::fastembed_reranker::FastEmbedReranker;
        use crate::search::reranker::{Reranker, rerank_texts};

        let model_dir = FastEmbedReranker::default_model_dir(&data_dir);
        let local_reranker: Option<Arc<dyn Reranker>> =
            match FastEmbedReranker::load_from_dir(&model_dir) {
                Ok(reranker) => Some(Arc::new(reranker)),
                Err(e) => {
                    if !semantic_opts.use_daemon {
                        tracing::debug!(error = %e, "Reranker not available, skipping rerank");
                    }
                    None
                }
            };

        let reranker: Option<Arc<dyn Reranker>> = if semantic_opts.use_daemon {
            use crate::search::daemon_client::{DaemonFallbackReranker, DaemonRetryConfig};

            #[cfg(unix)]
            {
                let daemon = crate::daemon::client::try_connect()
                    .map(|d| d as Arc<dyn crate::search::daemon_client::DaemonClient>)
                    .unwrap_or_else(|| {
                        Arc::new(crate::search::daemon_client::NoopDaemonClient::new(
                            "daemon-unconfigured",
                        ))
                    });
                let config = DaemonRetryConfig::from_env();
                Some(Arc::new(DaemonFallbackReranker::new(
                    daemon,
                    local_reranker,
                    config,
                )))
            }
            #[cfg(not(unix))]
            {
                let daemon = Arc::new(crate::search::daemon_client::NoopDaemonClient::new(
                    "daemon-unconfigured",
                ));
                let config = DaemonRetryConfig::from_env();
                Some(Arc::new(DaemonFallbackReranker::new(
                    daemon,
                    local_reranker,
                    config,
                )))
            }
        } else {
            local_reranker
        };

        if let Some(reranker) = reranker {
            // Extract content from hits for reranking (use snippet if content is empty)
            let docs: Vec<String> = result
                .hits
                .iter()
                .map(|hit| {
                    if hit.content.is_empty() {
                        hit.snippet.clone()
                    } else {
                        hit.content.clone()
                    }
                })
                .collect();

            // Skip reranking if any document is empty (reranker rejects empty docs)
            let has_empty_doc = docs.iter().any(|d| d.is_empty());
            if has_empty_doc {
                tracing::debug!("Skipping rerank: one or more hits have empty content and snippet");
                result
            } else {
                let doc_refs: Vec<&str> = docs.iter().map(|s| s.as_str()).collect();

                match rerank_texts(&*reranker, query, &doc_refs) {
                    Ok(scores) => {
                        // Update scores and re-sort hits
                        let mut scored_hits: Vec<_> = result
                            .hits
                            .into_iter()
                            .zip(scores)
                            .map(|(mut hit, score)| {
                                hit.score = score;
                                hit
                            })
                            .collect();
                        scored_hits.sort_by(|a, b| {
                            b.score
                                .partial_cmp(&a.score)
                                .unwrap_or(std::cmp::Ordering::Equal)
                        });

                        tracing::debug!(
                            reranker_id = reranker.id(),
                            hits_reranked = scored_hits.len(),
                            "Reranking complete"
                        );

                        crate::search::query::SearchResult {
                            hits: scored_hits,
                            wildcard_fallback: result.wildcard_fallback,
                            cache_stats: result.cache_stats,
                            suggestions: result.suggestions,
                            ann_stats: result.ann_stats,
                            total_count: result.total_count,
                        }
                    }
                    Err(e) => {
                        tracing::warn!(
                            error = %e,
                            "Reranking failed, returning original results"
                        );
                        result
                    }
                }
            }
        } else {
            result
        }
    } else {
        result
    };
    // Track reranking time (0 if not applied) (T7.4)
    let rerank_ms = if semantic_opts.rerank {
        rerank_start.elapsed().as_millis() as u64
    } else {
        0
    };

    // Check if search exceeded timeout - return partial results with timeout indicator
    let timed_out = timeout_duration.is_some_and(|t| start_time.elapsed() > t);

    // Build query explanation if requested
    let explanation = if explain {
        Some(
            QueryExplanation::analyze(query, &filters)
                .with_wildcard_fallback(result.wildcard_fallback),
        )
    } else {
        None
    };

    // Compute aggregations and create display result based on mode
    let (aggregations, display_result, total_matches, has_more_results, total_matches_exact) =
        if has_aggregation {
            // Compute aggregations from all fetched results
            let aggs = compute_aggregations(&result.hits, &agg_fields);
            let total = result.hits.len();

            // Apply offset and limit to get display hits.
            // When limit_val == 0 (meaning "no limit"), take all results.
            let agg_effective_limit = if limit_val == 0 {
                usize::MAX
            } else {
                limit_val
            };
            let display_hits: Vec<_> = result
                .hits
                .iter()
                .skip(offset_val)
                .take(agg_effective_limit)
                .cloned()
                .collect();

            let display = crate::search::query::SearchResult {
                hits: display_hits,
                wildcard_fallback: result.wildcard_fallback,
                cache_stats: result.cache_stats,
                suggestions: result.suggestions.clone(),
                ann_stats: result.ann_stats.clone(),
                total_count: result.total_count,
            };
            let has_more = total > offset_val + display.hits.len();
            (aggs, display, total, has_more, false)
        } else {
            // No aggregation - result was over-fetched by one to derive pagination state.
            // When limit_val == 0 (meaning "no limit"), take all results.
            let total_matches_exact = result.total_count.is_some();
            let has_more = cursor_page_limit > 0 && result.hits.len() > cursor_page_limit;
            let effective_limit = if cursor_page_limit == 0 {
                usize::MAX
            } else {
                cursor_page_limit
            };
            let display_hits: Vec<_> = result.hits.into_iter().take(effective_limit).collect();
            // Use the true total from Tantivy's Count collector when available;
            // fall back to the page-window lower bound for semantic/hybrid/cached paths.
            let known_total = result.total_count.unwrap_or_else(|| {
                offset_val
                    .saturating_add(display_hits.len())
                    .saturating_add(usize::from(has_more))
            });
            let display = crate::search::query::SearchResult {
                hits: display_hits,
                wildcard_fallback: result.wildcard_fallback,
                cache_stats: result.cache_stats,
                suggestions: result.suggestions,
                ann_stats: result.ann_stats,
                total_count: result.total_count,
            };
            (
                Aggregations::default(),
                display,
                known_total,
                has_more,
                total_matches_exact,
            )
        };

    let elapsed_ms = start_time.elapsed().as_millis() as u64;

    // Derive per-field budgets, preferring snippet > content > title
    let (snippet_budget, content_budget, title_budget, fallback_budget) = {
        let base = max_content_length;
        if let Some(tokens) = max_tokens {
            let char_budget = tokens.saturating_mul(4);
            let per_hit = char_budget / std::cmp::max(1, display_result.hits.len());
            let snippet = std::cmp::max(16, (per_hit as f64 * 0.5) as usize);
            let content = std::cmp::max(12, (per_hit as f64 * 0.35) as usize);
            let title = std::cmp::max(8, (per_hit as f64 * 0.15) as usize);
            (
                Some(snippet),
                Some(content),
                Some(title),
                base.map(|b| std::cmp::min(b, per_hit)),
            )
        } else {
            (base, base, base, base)
        }
    };

    let truncation_budgets = FieldBudgets {
        snippet: snippet_budget,
        content: content_budget,
        title: title_budget,
        fallback: fallback_budget,
    };

    // Gather state meta for robot output (index/db freshness)
    let state_meta = if robot_meta {
        Some(state_meta_json(
            &data_dir,
            &db_path,
            DEFAULT_STALE_THRESHOLD_SECS,
            true,
        ))
    } else {
        None
    };
    let index_freshness = state_meta.as_ref().and_then(state_index_freshness);
    let warning = index_freshness
        .as_ref()
        .and_then(|f: &serde_json::Value| f.get("stale"))
        .and_then(|v: &serde_json::Value| v.as_bool())
        .filter(|stale| *stale)
        .map(|_| {
            let age = index_freshness
                .as_ref()
                .and_then(|f: &serde_json::Value| f.get("age_seconds"))
                .and_then(|v: &serde_json::Value| v.as_u64()).map_or_else(|| "an unknown age".to_string(), |s| format!("{s} seconds"));
            let pending = index_freshness
                .as_ref()
                .and_then(|f: &serde_json::Value| f.get("pending_sessions"))
                .and_then(|v: &serde_json::Value| v.as_u64())
                .unwrap_or(0);
            format!(
                "Index may be stale (age: {age}; pending sessions: {pending}). Run `cass index --full` or enable watch mode for fresh results."
            )
        });

    let index_freshness_for_closure = index_freshness.clone();
    let state_meta_with_warning = state_meta.map(|mut meta| {
        if let Some(fresh) = index_freshness_for_closure
            && let serde_json::Value::Object(ref mut m) = meta
        {
            m.insert("index_freshness".to_string(), fresh);
        }
        if let Some(warn) = &warning
            && let serde_json::Value::Object(ref mut m) = meta
        {
            m.insert(
                "_warning".to_string(),
                serde_json::Value::String(warn.clone()),
            );
        }
        meta
    });

    if let Some(format) = effective_robot {
        // Robot output mode (JSON)
        output_robot_results(
            query,
            limit_val,
            cursor_page_limit,
            offset_val,
            &display_result,
            format,
            robot_meta,
            elapsed_ms,
            &fields,
            truncation_budgets,
            max_tokens,
            request_id.clone(),
            cursor.clone(),
            has_more_results,
            total_matches_exact,
            state_meta_with_warning,
            index_freshness,
            warning,
            &aggregations,
            total_matches,
            explanation.as_ref(),
            timed_out,
            timeout_ms,
            mode_meta,
            search_ms,
            rerank_ms,
        )?;
    } else if display_result.hits.is_empty() {
        eprintln!("No results found.");
    } else if let Some(display) = display_format {
        // Human-readable display formats
        output_display_results(&display_result.hits, display, wrap, query, highlight)?;
    } else {
        // Default plain text output
        for hit in &display_result.hits {
            println!("----------------------------------------------------------------");
            println!(
                "Score: {:.2} | Agent: {} | WS: {}",
                hit.score, hit.agent, hit.workspace
            );
            println!("Path: {}", hit.source_path);
            let snippet = hit.snippet.replace('\n', " ");
            let snippet = if highlight {
                highlight_matches(&snippet, query, "**", "**")
            } else {
                snippet
            };
            println!("Snippet: {}", apply_wrap(&snippet, wrap));
        }
        println!("----------------------------------------------------------------");
    }

    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn run_cli_pack(
    query: &str,
    agents: &[String],
    workspaces: &[String],
    limit: usize,
    robot_format: Option<RobotFormat>,
    fields: Option<Vec<String>>,
    max_tokens: usize,
    max_sessions: usize,
    max_evidence: usize,
    context_lines: usize,
    max_excerpt_chars: usize,
    request_id: Option<String>,
    display_format: Option<DisplayFormat>,
    data_dir_override: &Option<PathBuf>,
    db_override: Option<PathBuf>,
    time_filter: TimeFilter,
    source: Option<String>,
    sessions_from: Option<String>,
    mode: Option<crate::search::query::SearchMode>,
    freshness_policy: &str,
    freshness_window_seconds: i64,
    require_evidence: bool,
    explain_selection: bool,
    refresh: bool,
    timeout_ms: Option<u64>,
    _wrap: WrapConfig,
) -> CliResult<()> {
    use crate::search::pack_planner::{
        PackLexicalReadiness, PackPlanRequest, PackPlannerLimits, PackReadinessSnapshot,
        PackRenderFormat, PackRenderRequest, PackSemanticReadiness, pack_candidate_fetch_limit,
        plan_answer_pack, render_answer_pack, render_answer_pack_value,
    };
    use crate::search::query::{FieldMask, SearchClient, SearchClientOptions, SearchFilters};
    use crate::sources::provenance::SourceFilter;

    let start_time = Instant::now();
    let query = query.trim();
    if query.is_empty() {
        return Err(CliError {
            code: 2,
            kind: CliErrorKind::PackEmptyQuery.kind_str(),
            message: "pack query is empty after trimming whitespace".to_string(),
            hint: Some(
                "Provide a non-empty query, for example `cass pack \"checkout failure\" --robot`."
                    .to_string(),
            ),
            retryable: false,
        });
    }
    let render_format = resolve_pack_render_format(robot_format, display_format)?;
    let freshness_policy = parse_pack_freshness_policy(freshness_policy)?;
    if freshness_window_seconds <= 0 {
        return Err(CliError {
            code: 2,
            kind: CliErrorKind::PackInvalidLimit.kind_str(),
            message: format!(
                "invalid pack limit freshness_window_seconds={freshness_window_seconds} (must be positive)"
            ),
            hint: Some(
                "Set --freshness-window-seconds to a positive number of seconds.".to_string(),
            ),
            retryable: false,
        });
    }
    let limits = PackPlannerLimits {
        max_tokens,
        max_sessions,
        max_evidence,
        context_lines,
        max_excerpt_chars,
    };
    limits.validate().map_err(pack_invalid_limit_error)?;

    let data_dir = data_dir_override.clone().unwrap_or_else(default_data_dir);
    let index_path = crate::search::tantivy::expected_index_dir(&data_dir);
    let db_path = db_override
        .clone()
        .unwrap_or_else(|| data_dir.join("agent_search.db"));
    let db_exists = db_path.exists();

    let mut filters = SearchFilters::default();
    if !agents.is_empty() {
        filters.agents = HashSet::from_iter(agents.iter().cloned());
    }
    if !workspaces.is_empty() {
        filters.workspaces = HashSet::from_iter(workspaces.iter().cloned());
    }
    filters.created_from = time_filter.since;
    filters.created_to = time_filter.until;
    if let Some(ref source_str) = source {
        filters.source_filter = SourceFilter::parse(source_str);
    }
    if let Some(ref sessions_from_arg) = sessions_from {
        filters.session_paths = read_session_paths(sessions_from_arg).map_err(|e| CliError {
            code: 2,
            kind: CliErrorKind::SessionsFrom.kind_str(),
            message: format!("failed to read session paths: {e}"),
            hint: Some("Provide a file path or '-' for stdin".to_string()),
            retryable: false,
        })?;
    }
    validate_pack_fields(fields.as_ref())?;

    if refresh {
        refresh_index_inline(db_override.clone(), data_dir_override.clone());
    }

    let search_self_heal = ensure_lexical_assets_for_search(
        &data_dir,
        &db_path,
        &index_path,
        timeout_ms,
        start_time,
        false,
    )?;
    if search_self_heal.action != "skipped" {
        tracing::info!(
            action = search_self_heal.action,
            reason = search_self_heal.reason.as_deref(),
            indexed_docs = search_self_heal.indexed_docs,
            "pack lexical self-heal completed"
        );
    }

    let tantivy_index_initialized = crate::search::tantivy::searchable_index_exists(&index_path);
    let rebuild_active = probe_index_run_lock(&data_dir, &db_path).active;
    let client = SearchClient::open_with_options(
        &index_path,
        Some(&db_path),
        SearchClientOptions {
            enable_reload: false,
            enable_warm: false,
        },
    )
    .map_err(|e| CliError {
        code: 9,
        kind: CliErrorKind::OpenIndex.kind_str(),
        message: format!("failed to open index: {e}"),
        hint: Some("try cass index --full".to_string()),
        retryable: true,
    })?
    .ok_or_else(|| {
        pack_missing_index_error(
            &data_dir,
            &db_path,
            &index_path,
            db_exists,
            tantivy_index_initialized,
            rebuild_active,
        )
    })?;

    let requested_mode = mode.unwrap_or_default();
    let mut mode_meta = SearchModeMeta::new(requested_mode, mode.is_none());
    if matches!(requested_mode, crate::search::query::SearchMode::Semantic) {
        return Err(CliError {
            code: 15,
            kind: CliErrorKind::SemanticUnavailable.kind_str(),
            message: "cass pack cannot currently run semantic-only evidence selection".to_string(),
            hint: Some("Use --mode lexical or the default hybrid-preferred mode, which fails open to lexical evidence.".to_string()),
            retryable: true,
        });
    }
    if matches!(requested_mode, crate::search::query::SearchMode::Hybrid) {
        mode_meta
            .fall_back_to_lexical("pack semantic enrichment unavailable; using lexical evidence");
    }

    let timeout_duration = timeout_ms.map(Duration::from_millis);
    if let Some(timeout) = timeout_duration
        && start_time.elapsed() >= timeout
    {
        return Err(CliError {
            code: 10,
            kind: CliErrorKind::Timeout.kind_str(),
            message: format!(
                "Operation timed out after {}ms (before pack search started)",
                timeout.as_millis()
            ),
            hint: Some("Increase --timeout value or simplify query".to_string()),
            retryable: true,
        });
    }

    let candidate_limit = if limit == 0 {
        pack_candidate_fetch_limit(&limits).map_err(pack_invalid_limit_error)?
    } else {
        limit
    };
    let search_sparse_threshold = sparse_threshold_for_visible_limit(3, candidate_limit, false);
    let result = client
        .search_with_fallback(
            query,
            filters,
            candidate_limit,
            0,
            search_sparse_threshold,
            FieldMask::FULL,
        )
        .map_err(|e| CliError {
            code: 9,
            kind: CliErrorKind::Search.kind_str(),
            message: format!("pack search failed: {e}"),
            hint: Some(
                "Try `cass search <query> --robot --robot-meta` to inspect the search path."
                    .to_string(),
            ),
            retryable: true,
        })?;

    if let Some(timeout) = timeout_duration
        && start_time.elapsed() > timeout
    {
        return Err(CliError {
            code: 10,
            kind: CliErrorKind::Timeout.kind_str(),
            message: format!(
                "Operation timed out after {}ms while building answer pack",
                timeout.as_millis()
            ),
            hint: Some("Increase --timeout value or lower --limit/--max-evidence".to_string()),
            retryable: true,
        });
    }

    let query_term_count = pack_query_term_count(query);
    let query_phrase_count = pack_query_phrase_count(query);
    let source_explicitly_requested = source.is_some() || sessions_from.is_some();
    let candidates = result
        .hits
        .iter()
        .enumerate()
        .map(|(index, hit)| {
            let mut candidate = crate::search::pack_planner::PackCandidate::from_search_hit(
                hit,
                query_term_count,
                query_phrase_count,
            );
            candidate.hybrid_rank = Some(index + 1);
            candidate.source_explicitly_requested = source_explicitly_requested;
            candidate
        })
        .collect::<Vec<_>>();

    let generated_at_ms = Utc::now().timestamp_millis();
    let plan_request = PackPlanRequest {
        now_ms: generated_at_ms,
        limits: limits.clone(),
        freshness_policy,
        freshness_window_seconds,
        candidates,
        explain_selection,
    };
    let plan = plan_answer_pack(plan_request).map_err(pack_invalid_limit_error)?;

    if require_evidence && plan.evidence.is_empty() {
        return Err(CliError {
            code: 13,
            kind: CliErrorKind::NotFound.kind_str(),
            message: "no evidence matched the pack query".to_string(),
            hint: Some("Broaden the query or remove restrictive filters.".to_string()),
            retryable: false,
        });
    }

    let render_request = PackRenderRequest {
        query_text: query.to_string(),
        normalized_query: query.trim().to_string(),
        generated_at_ms,
        elapsed_ms: start_time.elapsed().as_millis() as u64,
        request_id,
        format: render_format,
        limits,
        search_mode: search_mode_label(mode_meta.realized).to_string(),
        fallback_mode: mode_meta.fallback_tier.map(str::to_string),
        semantic_joined: mode_meta.semantic_refinement(),
        freshness_policy,
        freshness_window_seconds,
        redaction_policy: "strict".to_string(),
        sensitive_output: false,
        skill_content_included: false,
        explain_selection,
        readiness: PackReadinessSnapshot {
            index_generation: search_self_heal
                .indexed_docs
                .map(|count| format!("indexed_docs:{count}")),
            lexical_readiness: if rebuild_active {
                PackLexicalReadiness::Rebuilding
            } else {
                PackLexicalReadiness::Ready
            },
            semantic_readiness: if mode_meta.fallback_tier.is_some() {
                PackSemanticReadiness::FallbackLexical
            } else {
                PackSemanticReadiness::Disabled
            },
            active_rebuild: rebuild_active,
            lock_state: rebuild_active.then(|| "index-run-lock-active".to_string()),
            missing_database: !db_path.exists(),
            source_sync_gaps: Vec::new(),
            recommended_action: None,
        },
    };

    match render_format {
        PackRenderFormat::Json | PackRenderFormat::CompactJson | PackRenderFormat::Toon => {
            let mut value =
                render_answer_pack_value(&plan, &render_request).map_err(|err| CliError {
                    code: 9,
                    kind: CliErrorKind::EncodeJson.kind_str(),
                    message: format!(
                        "failed to render answer pack as {}: {}",
                        err.format, err.message
                    ),
                    hint: None,
                    retryable: false,
                })?;
            value = filter_pack_fields(value, fields.as_ref())?;
            let output_format = match render_format {
                PackRenderFormat::Json => RobotFormat::Json,
                PackRenderFormat::CompactJson => RobotFormat::Compact,
                PackRenderFormat::Toon => RobotFormat::Toon,
                PackRenderFormat::Jsonl | PackRenderFormat::Markdown => unreachable!(),
            };
            output_structured_value(value, output_format)?;
        }
        PackRenderFormat::Jsonl | PackRenderFormat::Markdown => {
            if fields.is_some() && matches!(render_format, PackRenderFormat::Jsonl) {
                eprintln!("Warning: --fields is ignored for pack JSONL output.");
            }
            let rendered = render_answer_pack(&plan, &render_request).map_err(|err| CliError {
                code: 9,
                kind: CliErrorKind::EncodeJson.kind_str(),
                message: format!(
                    "failed to render answer pack as {}: {}",
                    err.format, err.message
                ),
                hint: None,
                retryable: false,
            })?;
            println!("{rendered}");
        }
    }

    Ok(())
}

fn resolve_pack_render_format(
    robot_format: Option<RobotFormat>,
    display_format: Option<DisplayFormat>,
) -> CliResult<crate::search::pack_planner::PackRenderFormat> {
    use crate::search::pack_planner::PackRenderFormat;

    if matches!(
        display_format,
        Some(DisplayFormat::Table | DisplayFormat::Lines)
    ) {
        return Err(CliError {
            code: 2,
            kind: CliErrorKind::PackUnsupportedFormat.kind_str(),
            message: "cass pack only supports markdown for human display".to_string(),
            hint: Some(
                "Use --display markdown, --json/--robot, or --robot-format json|compact|jsonl|toon."
                    .to_string(),
            ),
            retryable: false,
        });
    }

    match robot_format {
        Some(RobotFormat::Json) => Ok(PackRenderFormat::Json),
        Some(RobotFormat::Compact) => Ok(PackRenderFormat::CompactJson),
        Some(RobotFormat::Jsonl) => Ok(PackRenderFormat::Jsonl),
        Some(RobotFormat::Toon) => Ok(PackRenderFormat::Toon),
        Some(RobotFormat::Sessions) => Err(CliError {
            code: 2,
            kind: CliErrorKind::PackUnsupportedFormat.kind_str(),
            message: "cass pack does not support --robot-format sessions".to_string(),
            hint: Some(
                "Use `cass search --robot-format sessions | cass pack <query> --robot --sessions-from -`."
                    .to_string(),
            ),
            retryable: false,
        }),
        None => Ok(PackRenderFormat::Markdown),
    }
}

fn pack_invalid_limit_error(err: crate::search::pack_planner::PackPlannerLimitError) -> CliError {
    CliError {
        code: 2,
        kind: CliErrorKind::PackInvalidLimit.kind_str(),
        message: format!(
            "invalid pack limit {}={} (allowed {}..={})",
            err.field, err.value, err.min, err.max
        ),
        hint: Some(
            "Adjust --max-tokens, --max-sessions, --max-evidence, --context-lines, or --max-excerpt-chars."
                .to_string(),
        ),
        retryable: false,
    }
}

fn parse_pack_freshness_policy(
    value: &str,
) -> CliResult<crate::search::pack_planner::PackFreshnessPolicy> {
    match value {
        "prefer-recent" => Ok(crate::search::pack_planner::PackFreshnessPolicy::PreferRecent),
        "strict" => Ok(crate::search::pack_planner::PackFreshnessPolicy::Strict),
        "allow-stale" => Ok(crate::search::pack_planner::PackFreshnessPolicy::AllowStale),
        other => Err(CliError::usage(
            format!("invalid freshness policy: {other}"),
            Some("Use prefer-recent, strict, or allow-stale.".to_string()),
        )),
    }
}

fn pack_query_term_count(query: &str) -> usize {
    query
        .split_whitespace()
        .filter(|term| !term.trim_matches('"').is_empty())
        .count()
}

fn pack_query_phrase_count(query: &str) -> usize {
    query.matches('"').count() / 2
}

fn pack_missing_index_error(
    data_dir: &Path,
    db_path: &Path,
    index_path: &Path,
    db_exists: bool,
    tantivy_index_initialized: bool,
    rebuild_active: bool,
) -> CliError {
    let (message, hint) = if rebuild_active && !tantivy_index_initialized {
        (
            format!(
                "cass is already building the initial search index in {}. Pack generation will become available when that index run finishes.",
                data_dir.display()
            ),
            Some("Wait for the active 'cass index' run to finish, or inspect progress with 'cass status --json'.".to_string()),
        )
    } else if cass_not_initialized(db_exists, tantivy_index_initialized, rebuild_active) {
        (
            format!(
                "cass has not been initialized in {} yet, so pack generation cannot run until the first index completes.",
                data_dir.display()
            ),
            Some(cass_not_initialized_recommended_action()),
        )
    } else if db_exists && !tantivy_index_initialized {
        (
            format!(
                "Search index not found at {}. The archive database exists, but the Tantivy index has not been built yet.",
                index_path.display()
            ),
            Some("Run 'cass index --full' to build the search index for this archive.".to_string()),
        )
    } else if !db_exists && tantivy_index_initialized {
        (
            format!(
                "Search index exists at {}, but the archive database {} is missing.",
                index_path.display(),
                db_path.display()
            ),
            Some("Run 'cass index --full' to recreate the local archive database.".to_string()),
        )
    } else {
        (
            format!(
                "Index not found at {}. Run 'cass index --full' first.",
                index_path.display()
            ),
            Some(
                "Run 'cass index --full' to create the local archive and search index.".to_string(),
            ),
        )
    };
    CliError {
        code: 3,
        kind: CliErrorKind::MissingIndex.kind_str(),
        message,
        hint,
        retryable: true,
    }
}

fn filter_pack_fields(
    value: serde_json::Value,
    fields: Option<&Vec<String>>,
) -> CliResult<serde_json::Value> {
    let Some(fields) = fields else {
        return Ok(value);
    };
    let Some(field_mask) = expand_pack_field_mask(fields)? else {
        return Ok(value);
    };
    let mut matched_fields = Vec::new();
    let mut ignored_fields = field_mask.ignored_fields;
    for field in field_mask.fields {
        if pack_field_projects(&value, &field) {
            matched_fields.push(field);
        } else {
            ignored_fields.push(field);
        }
    }
    if matched_fields.is_empty() {
        return Err(pack_invalid_field_error(
            field_mask
                .requested_fields
                .first()
                .map(String::as_str)
                .unwrap_or(""),
        ));
    }

    let mut value = value;
    append_pack_field_mask_warnings(&mut value, &ignored_fields);

    let mut filtered = serde_json::Map::new();
    for field in matched_fields {
        let _ = merge_projected_pack_field(&mut filtered, &value, &field);
    }
    if !ignored_fields.is_empty() && !filtered.contains_key("_meta") {
        let _ = merge_projected_pack_field(&mut filtered, &value, "_meta.warnings");
    }
    Ok(serde_json::Value::Object(filtered))
}

fn validate_pack_fields(fields: Option<&Vec<String>>) -> CliResult<()> {
    if let Some(fields) = fields {
        let _ = expand_pack_field_mask(fields)?;
    }
    Ok(())
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct PackFieldMask {
    fields: BTreeSet<String>,
    ignored_fields: Vec<String>,
    requested_fields: Vec<String>,
}

fn expand_pack_field_mask(fields: &[String]) -> CliResult<Option<PackFieldMask>> {
    let mut set = BTreeSet::new();
    let mut ignored_fields = Vec::new();
    let mut requested_fields = Vec::new();
    for field in fields
        .iter()
        .map(|field| field.trim())
        .filter(|field| !field.is_empty())
    {
        requested_fields.push(field.to_string());
        match field {
            "*" | "all" => return Ok(None),
            "minimal" => {
                set.extend([
                    "schema_version".to_string(),
                    "query.text".to_string(),
                    "realized.search_mode".to_string(),
                    "pack.answer_outline".to_string(),
                    "evidence[].citation".to_string(),
                    "evidence[].excerpt".to_string(),
                    "omitted.count".to_string(),
                    "privacy.redaction_applied".to_string(),
                ]);
            }
            "summary" => {
                set.extend([
                    "schema_version".to_string(),
                    "_meta".to_string(),
                    "limits".to_string(),
                    "realized".to_string(),
                    "health".to_string(),
                    "freshness".to_string(),
                    "pack".to_string(),
                    "privacy".to_string(),
                    "warnings".to_string(),
                ]);
            }
            "meta" => {
                set.insert("_meta".to_string());
            }
            field @ ("schema_version" | "_meta" | "query" | "limits" | "realized" | "health"
            | "freshness" | "pack" | "evidence" | "omitted" | "privacy" | "warnings") => {
                set.insert(field.to_string());
            }
            field
                if pack_field_root(field)
                    .is_some_and(|root| PACK_TOP_LEVEL_FIELDS.contains(&root)) =>
            {
                set.insert(field.to_string());
            }
            other => {
                ignored_fields.push(other.to_string());
            }
        }
    }
    if set.is_empty() {
        if let Some(field) = ignored_fields.first() {
            Err(pack_invalid_field_error(field))
        } else {
            Ok(None)
        }
    } else {
        Ok(Some(PackFieldMask {
            fields: set,
            ignored_fields,
            requested_fields,
        }))
    }
}

const PACK_TOP_LEVEL_FIELDS: &[&str] = &[
    "schema_version",
    "_meta",
    "query",
    "limits",
    "realized",
    "health",
    "freshness",
    "pack",
    "evidence",
    "omitted",
    "privacy",
    "warnings",
];

fn pack_invalid_field_error(field: &str) -> CliError {
    CliError {
        code: 2,
        kind: CliErrorKind::PackInvalidField.kind_str(),
        message: format!("unknown pack field mask: {field}"),
        hint: Some(
            "Use minimal, summary, all, or top-level fields such as evidence, health, freshness, omitted, privacy."
                .to_string(),
        ),
        retryable: false,
    }
}

fn pack_field_root(field: &str) -> Option<&str> {
    let raw_root = field.split('.').next()?;
    let root = raw_root.strip_suffix("[]").unwrap_or(raw_root);
    (!root.is_empty()).then_some(root)
}

fn append_pack_field_mask_warnings(value: &mut serde_json::Value, ignored_fields: &[String]) {
    if ignored_fields.is_empty() {
        return;
    }

    let warnings = ignored_fields
        .iter()
        .map(|field| format!("unknown_pack_field_mask_ignored:{field}"))
        .collect::<Vec<_>>();
    for path in ["_meta", ""] {
        let Some(target) = pack_warning_array_mut(value, path) else {
            continue;
        };
        target.extend(warnings.iter().cloned().map(serde_json::Value::String));
    }
}

fn pack_warning_array_mut<'a>(
    value: &'a mut serde_json::Value,
    object_path: &str,
) -> Option<&'a mut Vec<serde_json::Value>> {
    let object = if object_path.is_empty() {
        value.as_object_mut()?
    } else {
        value.get_mut(object_path)?.as_object_mut()?
    };
    object
        .entry("warnings")
        .or_insert_with(|| serde_json::Value::Array(Vec::new()))
        .as_array_mut()
}

fn merge_projected_pack_field(
    target: &mut serde_json::Map<String, serde_json::Value>,
    source: &serde_json::Value,
    field: &str,
) -> bool {
    let Some(projected) = projected_pack_field(source, field) else {
        return false;
    };
    merge_json_object(target, projected);
    true
}

fn pack_field_projects(source: &serde_json::Value, field: &str) -> bool {
    projected_pack_field(source, field).is_some()
}

fn projected_pack_field(source: &serde_json::Value, field: &str) -> Option<serde_json::Value> {
    let segments = field.split('.').collect::<Vec<_>>();
    project_pack_json_path(source, &segments)
}

fn project_pack_json_path(
    source: &serde_json::Value,
    segments: &[&str],
) -> Option<serde_json::Value> {
    let (segment, rest) = segments.split_first()?;
    if let Some(key) = segment.strip_suffix("[]") {
        let array = source.get(key)?.as_array()?;
        let projected_array = if rest.is_empty() {
            array.clone()
        } else if array.is_empty() {
            Vec::new()
        } else {
            let mut any_projected = false;
            let projected = array
                .iter()
                .map(|item| {
                    let item_projected = project_pack_json_path(item, rest);
                    any_projected |= item_projected.is_some();
                    item_projected.unwrap_or_else(|| serde_json::Value::Object(Default::default()))
                })
                .collect::<Vec<_>>();
            if !any_projected {
                return None;
            }
            projected
        };
        return Some(pack_singleton_json_object(
            key,
            serde_json::Value::Array(projected_array),
        ));
    }

    let child = source.get(*segment)?;
    let projected_child = if rest.is_empty() {
        child.clone()
    } else {
        project_pack_json_path(child, rest)?
    };
    Some(pack_singleton_json_object(segment, projected_child))
}

fn pack_singleton_json_object(key: &str, value: serde_json::Value) -> serde_json::Value {
    let mut object = serde_json::Map::new();
    object.insert(key.to_string(), value);
    serde_json::Value::Object(object)
}

fn merge_json_object(
    target: &mut serde_json::Map<String, serde_json::Value>,
    projected: serde_json::Value,
) {
    let serde_json::Value::Object(projected) = projected else {
        return;
    };
    for (key, value) in projected {
        match target.get_mut(&key) {
            Some(existing) => merge_json_value(existing, value),
            None => {
                target.insert(key, value);
            }
        }
    }
}

fn merge_json_value(target: &mut serde_json::Value, incoming: serde_json::Value) {
    match (target, incoming) {
        (serde_json::Value::Object(target), serde_json::Value::Object(incoming)) => {
            for (key, value) in incoming {
                match target.get_mut(&key) {
                    Some(existing) => merge_json_value(existing, value),
                    None => {
                        target.insert(key, value);
                    }
                }
            }
        }
        (serde_json::Value::Array(target), serde_json::Value::Array(incoming)) => {
            for (idx, value) in incoming.into_iter().enumerate() {
                if let Some(existing) = target.get_mut(idx) {
                    merge_json_value(existing, value);
                } else {
                    target.push(value);
                }
            }
        }
        (target, incoming) => {
            *target = incoming;
        }
    }
}

#[cfg(test)]
mod pack_field_mask_tests {
    use super::*;

    fn sample_pack_value() -> serde_json::Value {
        serde_json::json!({
            "schema_version": "cass.pack.v1",
            "query": {
                "text": "checkout",
                "normalized": "checkout",
                "filters": {}
            },
            "_meta": {
                "request_id": "req-1",
                "generated_at_ms": 1,
                "elapsed_ms": 2,
                "partial": false,
                "format": "json",
                "warnings": []
            },
            "limits": {
                "max_tokens": 12000,
                "estimated_tokens": 10,
                "field_mask": "standard"
            },
            "realized": {
                "search_mode": "lexical",
                "fallback_mode": null,
                "semantic_joined": false
            },
            "pack": {
                "title": "checkout",
                "answer_outline": [{"rank": 1, "heading": "checkout", "evidence_ids": ["ev_1"]}],
                "handoff": [{"rank": 1, "text": "handoff"}]
            },
            "evidence": [{
                "id": "ev_1",
                "excerpt": "retry guard was missing",
                "citation": {"source_path": "/tmp/session.jsonl", "line_start": 4},
                "selection": {"score": 1.0}
            }],
            "omitted": {
                "count": 3,
                "items": [{"reason": "duplicate_content"}]
            },
            "privacy": {
                "redaction_applied": false,
                "redaction_policy": "strict"
            },
            "warnings": []
        })
    }

    fn fields(values: &[&str]) -> Vec<String> {
        values.iter().map(|value| value.to_string()).collect()
    }

    #[test]
    fn pack_minimal_field_mask_projects_documented_dotted_fields() {
        let fields = fields(&["minimal"]);
        let filtered = filter_pack_fields(sample_pack_value(), Some(&fields)).unwrap();

        assert_eq!(filtered["schema_version"], "cass.pack.v1");
        assert_eq!(filtered["query"], serde_json::json!({ "text": "checkout" }));
        assert_eq!(
            filtered["realized"],
            serde_json::json!({ "search_mode": "lexical" })
        );
        assert_eq!(
            filtered["pack"],
            serde_json::json!({
                "answer_outline": [{"rank": 1, "heading": "checkout", "evidence_ids": ["ev_1"]}]
            })
        );
        assert_eq!(
            filtered["evidence"],
            serde_json::json!([{
                "citation": {"source_path": "/tmp/session.jsonl", "line_start": 4},
                "excerpt": "retry guard was missing"
            }])
        );
        assert_eq!(filtered["omitted"], serde_json::json!({ "count": 3 }));
        assert_eq!(
            filtered["privacy"],
            serde_json::json!({ "redaction_applied": false })
        );
        assert!(filtered.get("_meta").is_none());
        assert!(filtered["evidence"][0].get("selection").is_none());
    }

    #[test]
    fn pack_explicit_dotted_mask_merges_array_item_fields() {
        let fields = fields(&["query.text", "evidence[].citation", "evidence[].excerpt"]);
        let filtered = filter_pack_fields(sample_pack_value(), Some(&fields)).unwrap();

        assert_eq!(filtered["query"], serde_json::json!({ "text": "checkout" }));
        assert_eq!(
            filtered["evidence"],
            serde_json::json!([{
                "citation": {"source_path": "/tmp/session.jsonl", "line_start": 4},
                "excerpt": "retry guard was missing"
            }])
        );
    }

    #[test]
    fn pack_field_mask_projection_is_order_and_duplicate_invariant() {
        let canonical = fields(&[
            "query.text",
            "realized.search_mode",
            "pack.answer_outline",
            "evidence[].citation",
            "evidence[].excerpt",
            "omitted.count",
            "privacy.redaction_applied",
        ]);
        let permuted = fields(&[
            "privacy.redaction_applied",
            "evidence[].excerpt",
            "query.text",
            "omitted.count",
            "pack.answer_outline",
            "evidence[].citation",
            "realized.search_mode",
        ]);
        let duplicated = fields(&[
            "query.text",
            "evidence[].citation",
            "query.text",
            "realized.search_mode",
            "pack.answer_outline",
            "evidence[].excerpt",
            "omitted.count",
            "privacy.redaction_applied",
            "evidence[].citation",
        ]);

        let expected = filter_pack_fields(sample_pack_value(), Some(&canonical)).unwrap();

        assert_eq!(
            filter_pack_fields(sample_pack_value(), Some(&permuted)).unwrap(),
            expected
        );
        assert_eq!(
            filter_pack_fields(sample_pack_value(), Some(&duplicated)).unwrap(),
            expected
        );
    }

    #[test]
    fn pack_mixed_valid_and_unknown_masks_warn_without_failing() {
        let fields = fields(&["query.text", "no_such_field"]);
        let filtered = filter_pack_fields(sample_pack_value(), Some(&fields)).unwrap();

        assert_eq!(filtered["query"], serde_json::json!({ "text": "checkout" }));
        assert_eq!(
            filtered["_meta"]["warnings"],
            serde_json::json!(["unknown_pack_field_mask_ignored:no_such_field"])
        );
    }

    #[test]
    fn pack_mixed_valid_and_unknown_dotted_masks_warn_without_failing() {
        let fields = fields(&["query.text", "query.nope"]);
        let filtered = filter_pack_fields(sample_pack_value(), Some(&fields)).unwrap();

        assert_eq!(filtered["query"], serde_json::json!({ "text": "checkout" }));
        assert_eq!(
            filtered["_meta"]["warnings"],
            serde_json::json!(["unknown_pack_field_mask_ignored:query.nope"])
        );
    }

    #[test]
    fn pack_all_invalid_field_masks_still_fail() {
        let fields = fields(&["no_such_field"]);
        let err = filter_pack_fields(sample_pack_value(), Some(&fields)).unwrap_err();

        assert_eq!(err.kind, "pack-invalid-field");
    }

    #[test]
    fn pack_all_invalid_dotted_field_masks_still_fail() {
        let fields = fields(&["query.nope"]);
        let err = filter_pack_fields(sample_pack_value(), Some(&fields)).unwrap_err();

        assert_eq!(err.kind, "pack-invalid-field");
    }
}

/// Output search results in human-readable display format
fn output_display_results(
    hits: &[crate::search::query::SearchHit],
    format: DisplayFormat,
    wrap: WrapConfig,
    query: &str,
    highlight: bool,
) -> CliResult<()> {
    match format {
        DisplayFormat::Table => {
            // Aligned columns with headers
            println!("{:<6} {:<12} {:<25} SNIPPET", "SCORE", "AGENT", "WORKSPACE");
            println!("{}", "-".repeat(80));
            for hit in hits {
                let workspace = truncate_start(&hit.workspace, 24);
                let snippet = hit.snippet.replace('\n', " ");
                let snippet = if highlight {
                    highlight_matches(&snippet, query, "**", "**")
                } else {
                    snippet
                };
                let snippet_display = truncate_end(&snippet, 50);
                println!(
                    "{:<6.2} {:<12} {:<25} {}",
                    hit.score, hit.agent, workspace, snippet_display
                );
            }
            println!("\n{} results", hits.len());
        }
        DisplayFormat::Lines => {
            // One-liner per result
            for hit in hits {
                let snippet = hit.snippet.replace('\n', " ");
                let snippet = if highlight {
                    highlight_matches(&snippet, query, "**", "**")
                } else {
                    snippet
                };
                let snippet_short = truncate_end(&snippet, 60);
                println!(
                    "[{:.1}] {} | {} | {}",
                    hit.score, hit.agent, hit.source_path, snippet_short
                );
            }
        }
        DisplayFormat::Markdown => {
            // Markdown with headers and code blocks
            println!("# Search Results\n");
            println!("Found **{}** results.\n", hits.len());
            for (i, hit) in hits.iter().enumerate() {
                println!("## {}. {} (score: {:.2})\n", i + 1, hit.agent, hit.score);
                println!("- **Workspace**: `{}`", hit.workspace);
                println!("- **Path**: `{}`", hit.source_path);
                if let Some(ts) = hit.created_at {
                    let dt = chrono::DateTime::from_timestamp_millis(ts).map_or_else(
                        || "unknown".to_string(),
                        |d| d.format("%Y-%m-%d %H:%M").to_string(),
                    );
                    println!("- **Created**: {dt}");
                }
                let snippet = if highlight {
                    // Use backticks for highlighting in markdown code blocks (shows as-is)
                    // But for non-code context, we'd use **bold**
                    highlight_matches(&hit.snippet, query, ">>>", "<<<")
                } else {
                    hit.snippet.clone()
                };
                let snippet = apply_wrap(&snippet, wrap);
                println!("\n```\n{snippet}\n```\n");
            }
        }
    }
    Ok(())
}

/// Expand field presets and return the resolved field list
fn expand_field_presets(fields: &Option<Vec<String>>) -> Option<Vec<String>> {
    fields.as_ref().map(|f| {
        f.iter()
            .flat_map(|field| match field.as_str() {
                "minimal" => vec![
                    "source_path".to_string(),
                    "line_number".to_string(),
                    "agent".to_string(),
                ],
                "summary" => vec![
                    "source_path".to_string(),
                    "line_number".to_string(),
                    "agent".to_string(),
                    "title".to_string(),
                    "score".to_string(),
                ],
                // Provenance preset (P3.4) - add source origin info to results
                "provenance" => vec![
                    "source_id".to_string(),
                    "origin_kind".to_string(),
                    "origin_host".to_string(),
                ],
                "*" | "all" => vec![], // Empty means include all - handled specially
                other => vec![other.to_string()],
            })
            .collect()
    })
}

fn resolve_field_mask(
    fields: &Option<Vec<String>>,
    max_content_length: Option<usize>,
    max_tokens: Option<usize>,
    visible_limit: usize,
    format: Option<RobotFormat>,
    display_format: Option<DisplayFormat>,
) -> crate::search::query::FieldMask {
    use crate::search::query::FieldMask;

    if matches!(format, Some(RobotFormat::Sessions)) {
        return FieldMask::new(false, false, false, false);
    }

    if format.is_none() && display_format.is_none() {
        return FieldMask::new(true, true, false, true);
    }

    if format.is_none() {
        return FieldMask::new(true, true, false, true);
    }

    let resolved_fields = expand_field_presets(fields);
    let wants_all = fields.is_none()
        || resolved_fields
            .as_ref()
            .is_some_and(|field_list| field_list.is_empty());
    let wants_snippet = wants_all
        || resolved_fields
            .as_ref()
            .is_some_and(|field_list| field_list.iter().any(|f| f == "snippet"));
    let wants_content = wants_all
        || resolved_fields
            .as_ref()
            .is_some_and(|field_list| field_list.iter().any(|f| f == "content"));
    let wants_title = wants_all
        || resolved_fields
            .as_ref()
            .is_some_and(|field_list| field_list.iter().any(|f| f == "title"));

    let needs_content_for_rendering = wants_content || wants_snippet;
    let allows_cache = needs_content_for_rendering;
    let preview_content_limit = if needs_content_for_rendering {
        preview_content_limit_for_search(max_content_length, max_tokens, visible_limit)
    } else {
        None
    };
    FieldMask::new(wants_content, wants_snippet, wants_title, allows_cache)
        .with_preview_content_limit(preview_content_limit)
}

const SEARCH_PREVIEW_CONTENT_LIMIT_MAX: usize = 400;
const TOKEN_BUDGET_DEFAULT_VISIBLE_HITS: usize = 20;
const TOKEN_BUDGET_SEARCH_MIN_HITS: usize = 20;
const TOKEN_BUDGET_SEARCH_MAX_HITS: usize = 4096;
const TOKEN_BUDGET_SEARCH_CHARS_PER_HIT: usize = 256;

fn token_budget_field_mask_visible_limit(
    max_tokens: Option<usize>,
    explicit_limit: usize,
) -> usize {
    if explicit_limit > 0 {
        explicit_limit
    } else if max_tokens.is_some() {
        TOKEN_BUDGET_DEFAULT_VISIBLE_HITS
    } else {
        explicit_limit
    }
}

fn token_budget_search_limit(max_tokens: Option<usize>) -> Option<usize> {
    let tokens = max_tokens?;
    let budget_chars = tokens.saturating_mul(4);
    let hits = budget_chars / TOKEN_BUDGET_SEARCH_CHARS_PER_HIT;
    Some(hits.clamp(TOKEN_BUDGET_SEARCH_MIN_HITS, TOKEN_BUDGET_SEARCH_MAX_HITS))
}

fn preview_content_limit_for_search(
    max_content_length: Option<usize>,
    max_tokens: Option<usize>,
    visible_limit: usize,
) -> Option<usize> {
    if let Some(max_chars) =
        max_content_length.filter(|max_chars| *max_chars <= SEARCH_PREVIEW_CONTENT_LIMIT_MAX)
    {
        return Some(max_chars);
    }

    let tokens = max_tokens?;
    let per_hit_chars = tokens.saturating_mul(4) / visible_limit.max(1);
    let content_chars = per_hit_chars.saturating_mul(35) / 100;
    let content_chars = content_chars.max(12);
    (content_chars <= SEARCH_PREVIEW_CONTENT_LIMIT_MAX).then_some(content_chars)
}

#[cfg(test)]
mod field_mask_resolution_tests {
    use super::*;

    #[test]
    fn snippet_projection_does_not_materialize_content_field() {
        let fields = Some(vec!["snippet".to_string()]);
        let mask = resolve_field_mask(&fields, None, None, 10, Some(RobotFormat::Json), None);

        assert!(mask.wants_snippet());
        assert!(!mask.needs_content());
        assert!(mask.allows_cache());
    }

    #[test]
    fn content_projection_materializes_content_field() {
        let fields = Some(vec!["content".to_string()]);
        let mask = resolve_field_mask(&fields, None, None, 10, Some(RobotFormat::Json), None);

        assert!(!mask.wants_snippet());
        assert!(mask.needs_content());
        assert!(mask.allows_cache());
    }

    #[test]
    fn small_token_budget_uses_preview_content_before_search_hydration() {
        let mask = resolve_field_mask(&None, None, Some(1024), 20, Some(RobotFormat::Json), None);

        assert!(mask.needs_content());
        assert!(mask.wants_snippet());
        assert_eq!(mask.preview_content_limit(), Some(71));
        assert!(
            !mask.allows_cache(),
            "preview-limited hits should not be cached as full-content results"
        );
    }

    #[test]
    fn large_token_budget_keeps_full_content_hydration() {
        let mask = resolve_field_mask(
            &None,
            None,
            Some(100_000),
            20,
            Some(RobotFormat::Json),
            None,
        );

        assert!(mask.needs_content());
        assert!(mask.wants_snippet());
        assert_eq!(mask.preview_content_limit(), None);
        assert!(mask.allows_cache());
    }

    #[test]
    fn no_limit_token_budget_uses_preview_limit_and_bounded_fetch() {
        let visible_limit = token_budget_field_mask_visible_limit(Some(1024), 0);
        let mask = resolve_field_mask(
            &None,
            None,
            Some(1024),
            visible_limit,
            Some(RobotFormat::Json),
            None,
        );

        assert_eq!(visible_limit, TOKEN_BUDGET_DEFAULT_VISIBLE_HITS);
        assert_eq!(mask.preview_content_limit(), Some(71));
        assert_eq!(
            token_budget_search_limit(Some(1024)),
            Some(TOKEN_BUDGET_SEARCH_MIN_HITS)
        );
        assert_eq!(
            token_budget_search_limit(Some(1_000_000)),
            Some(TOKEN_BUDGET_SEARCH_MAX_HITS)
        );
        assert_eq!(token_budget_search_limit(None), None);
    }
}

/// Filter a search hit to only include the requested fields
fn safe_robot_score_value(score: f32) -> serde_json::Value {
    serde_json::Value::from(if score.is_finite() { score as f64 } else { 0.0 })
}

fn normalized_robot_hit_source_id(hit: &crate::search::query::SearchHit) -> String {
    if let Some(source_id) = canonical_followup_source_id(Some(hit.source_id.as_str())) {
        return source_id;
    }
    if hit.origin_kind.trim().eq_ignore_ascii_case("local") {
        return crate::sources::provenance::LOCAL_SOURCE_ID.to_string();
    }
    hit.source_id.trim().to_string()
}

fn normalized_robot_hit_origin_kind(hit: &crate::search::query::SearchHit) -> String {
    let trimmed = hit.origin_kind.trim();
    if !trimmed.is_empty() {
        return trimmed.to_string();
    }
    if normalized_robot_hit_source_id(hit) == crate::sources::provenance::LOCAL_SOURCE_ID {
        return crate::sources::provenance::LOCAL_SOURCE_ID.to_string();
    }
    String::new()
}

fn normalized_robot_hit_origin_host(hit: &crate::search::query::SearchHit) -> Option<String> {
    hit.origin_host
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
}

fn normalized_robot_hit_for_output(
    hit: &crate::search::query::SearchHit,
) -> crate::search::query::SearchHit {
    let mut normalized = hit.clone();
    normalized.source_id = normalized_robot_hit_source_id(hit);
    normalized.origin_kind = normalized_robot_hit_origin_kind(hit);
    normalized.origin_host = normalized_robot_hit_origin_host(hit);
    if !normalized.score.is_finite() {
        normalized.score = 0.0;
    }
    normalized
}

fn projected_hit_field_value(
    hit: &crate::search::query::SearchHit,
    field: &str,
) -> Option<serde_json::Value> {
    match field {
        "score" => Some(safe_robot_score_value(hit.score)),
        "agent" => Some(serde_json::Value::String(hit.agent.clone())),
        "workspace" => Some(serde_json::Value::String(hit.workspace.clone())),
        "source_path" => Some(serde_json::Value::String(hit.source_path.clone())),
        "snippet" => Some(serde_json::Value::String(hit.snippet.clone())),
        "content" => Some(serde_json::Value::String(hit.content.clone())),
        "title" => Some(serde_json::Value::String(hit.title.clone())),
        "created_at" => serde_json::to_value(hit.created_at).ok(),
        "line_number" => serde_json::to_value(hit.line_number).ok(),
        "match_type" => serde_json::to_value(hit.match_type).ok(),
        // Provenance fields (P3.4)
        "source_id" => Some(serde_json::Value::String(normalized_robot_hit_source_id(
            hit,
        ))),
        "origin_kind" => Some(serde_json::Value::String(normalized_robot_hit_origin_kind(
            hit,
        ))),
        // Preserve SearchHit serialization semantics:
        // origin_host/workspace_original are omitted entirely when None.
        "origin_host" => normalized_robot_hit_origin_host(hit).map(serde_json::Value::String),
        "workspace_original" => hit
            .workspace_original
            .as_ref()
            .map(|value| serde_json::Value::String(value.clone())),
        _ => None,
    }
}

fn filter_hit_fields(
    hit: &crate::search::query::SearchHit,
    fields: &Option<Vec<String>>,
) -> serde_json::Value {
    // Sanitize NaN/Infinity score before serialization — serde_json rejects non-finite floats.
    let sanitize = |h: &crate::search::query::SearchHit| -> serde_json::Value {
        serde_json::to_value(normalized_robot_hit_for_output(h)).unwrap_or_default()
    };
    match fields {
        None => sanitize(hit),
        Some(field_list) if field_list.is_empty() => sanitize(hit),
        Some(field_list) => {
            let mut filtered = serde_json::Map::new();
            let known_fields = [
                "score",
                "agent",
                "workspace",
                "source_path",
                "snippet",
                "content",
                "title",
                "created_at",
                "line_number",
                "match_type",
                // Provenance fields (P3.4)
                "source_id",
                "origin_kind",
                "origin_host",
                "workspace_original",
            ];

            for field in field_list {
                if let Some(value) = projected_hit_field_value(hit, field) {
                    filtered.insert(field.clone(), value);
                } else if !known_fields.contains(&field.as_str()) {
                    // Warn about unknown fields.
                    warn!(unknown_field = %field, "Unknown field in --fields, ignoring");
                }
            }
            serde_json::Value::Object(filtered)
        }
    }
}

/// Truncate a string to `max_len` characters, UTF-8 safe, with ellipsis.
/// Returns `Some(truncated)` if truncation was needed, `None` otherwise.
///
/// `coding_agent_session_search-nj5eh`: pre-fix this function always
/// walked the full string with `s.chars().count()` to decide whether
/// truncation was needed, then walked it AGAIN with `take()` if it
/// was. For 100KB content with max_len=200 that was ~100K wasted
/// iterations per check. It also always cloned the string in the
/// no-truncation case (`s.to_string()`) even though callers like
/// `apply_content_truncation` only INSERT the result when truncation
/// happened — so for the 1000-hit × 3-field robot path the clone
/// produced ~MB of allocator pressure on the no-truncation hot path.
///
/// Post-fix: short-circuit char counting at `max_len + 1` (bounded
/// by `max_len`, independent of total string length) AND signal
/// "no truncation needed" via `None` so callers skip the wasted
/// allocation entirely. The truncation path captures the cut byte
/// index during the same walk used for short-circuit counting,
/// turning two passes into one.
fn truncate_content(s: &str, max_len: usize) -> Option<String> {
    let truncate_at = max_len.saturating_sub(3);
    let mut chars = s.char_indices();
    // Initialize cut_byte to 0 so the `truncate_at == 0` case (max_len < 3)
    // produces an empty prefix + "..." instead of accidentally using
    // `s.len()` as the cut. The in-loop assignment below overwrites
    // this when the loop reaches the truncate_at index.
    let mut cut_byte: Option<usize> = if truncate_at == 0 { Some(0) } else { None };
    for n in 0..max_len {
        let (byte_idx, _) = chars.next()?;
        if n == truncate_at {
            cut_byte = Some(byte_idx);
        }
    }
    chars.next()?;
    let cut = cut_byte.unwrap_or(s.len());
    let mut out = String::with_capacity(cut + 3);
    out.push_str(&s[..cut]);
    out.push_str("...");
    Some(out)
}

#[cfg(test)]
mod truncate_content_tests {
    use super::*;

    /// `coding_agent_session_search-nj5eh` regression: pin behavioral
    /// equivalence with the prior `(String, bool)` implementation
    /// across the boundary cases that determine when truncation
    /// fires.
    #[test]
    fn truncate_content_returns_none_when_chars_within_limit() {
        // Empty
        assert_eq!(truncate_content("", 10), None);
        // Strictly less than max_len
        assert_eq!(truncate_content("abc", 10), None);
        // Exactly max_len — boundary: pre-fix `char_count <= max_len`
        // returned (s.to_string(), false); post-fix returns None.
        assert_eq!(truncate_content("abcdefghij", 10), None);
    }

    #[test]
    fn truncate_content_returns_some_when_chars_exceed_limit() {
        // max_len + 1 — first char count beyond limit
        assert_eq!(
            truncate_content("abcdefghijk", 10).as_deref(),
            Some("abcdefg...")
        );
        // Significantly larger than max_len
        assert_eq!(
            truncate_content("abcdefghijklmnopqrstuvwxyz", 10).as_deref(),
            Some("abcdefg...")
        );
    }

    #[test]
    fn truncate_content_handles_max_len_below_ellipsis_budget() {
        // max_len < 3 — saturating_sub(3) yields 0; truncated prefix
        // is empty so output is just "...".
        assert_eq!(truncate_content("abcdef", 0).as_deref(), Some("..."));
        assert_eq!(truncate_content("abcdef", 1).as_deref(), Some("..."));
        assert_eq!(truncate_content("abcdef", 2).as_deref(), Some("..."));
    }

    #[test]
    fn truncate_content_is_utf8_safe_on_multibyte_boundaries() {
        // 4 emojis (each 4 bytes in UTF-8) + ASCII tail; max_len=4
        // means "exactly fits" and returns None.
        let s = "😀😀😀😀x";
        assert_eq!(truncate_content(s, 5), None);
        // max_len=4: 5 chars > 4 → truncate. saturating_sub(3)=1, so
        // cut at the first multibyte boundary (byte 4) and append "..."
        let truncated = truncate_content(s, 4).expect("must truncate when chars > max_len");
        assert_eq!(truncated, "😀...");
    }

    #[test]
    fn truncate_content_short_circuits_on_huge_input() {
        // 100KB ASCII string with max_len=10 — pre-fix walked all
        // 100K chars to count, then 7 more to take. Post-fix walks
        // exactly 11 chars (max_len + 1) before deciding. This test
        // doesn't measure perf but verifies CORRECTNESS on a large
        // input that exposed the original O(N) walk.
        let s = "a".repeat(100_000);
        assert_eq!(truncate_content(&s, 10).as_deref(), Some("aaaaaaa..."));
    }

    /// Pin the post-fix contract that `apply_content_truncation` relies
    /// on: `None` ↔ caller skips clone+insert. Pre-fix, the function
    /// always returned an owned String even in the no-truncation case,
    /// causing wasted allocations on the robot-mode hot path.
    #[test]
    fn truncate_content_avoids_allocation_on_no_truncation_path() {
        // The contract is: return None when no truncation happened.
        // Callers (apply_content_truncation) MUST be able to
        // distinguish via `Option::is_none` without inspecting the
        // string contents.
        assert!(truncate_content("short", 1024).is_none());
    }
}

/// Apply content truncation to a filtered hit JSON object
#[derive(Clone, Copy)]
struct FieldBudgets {
    snippet: Option<usize>,
    content: Option<usize>,
    title: Option<usize>,
    fallback: Option<usize>,
}

impl FieldBudgets {
    #[inline]
    fn has_any_limit(self) -> bool {
        self.snippet.is_some()
            || self.content.is_some()
            || self.title.is_some()
            || self.fallback.is_some()
    }
}

fn apply_content_truncation(hit: serde_json::Value, budgets: FieldBudgets) -> serde_json::Value {
    let serde_json::Value::Object(mut obj) = hit else {
        return hit;
    };

    let fields = [
        ("snippet", budgets.snippet.or(budgets.fallback)),
        ("content", budgets.content.or(budgets.fallback)),
        ("title", budgets.title.or(budgets.fallback)),
    ];

    for (field, budget) in fields {
        if let (Some(limit), Some(serde_json::Value::String(s))) = (budget, obj.get(field))
            && let Some(truncated) = truncate_content(s, limit)
        {
            obj.insert(field.to_string(), serde_json::Value::String(truncated));
            obj.insert(format!("{field}_truncated"), serde_json::Value::Bool(true));
        }
    }

    serde_json::Value::Object(obj)
}

/// Clamp hits to an approximate token budget (4 chars ≈ 1 token). Returns (hits, `est_tokens`, clamped?)
fn clamp_hits_to_budget(
    hits: Vec<serde_json::Value>,
    max_tokens: Option<usize>,
    estimate_tokens: bool,
) -> (Vec<serde_json::Value>, Option<usize>, bool) {
    let input_len = hits.len();
    let Some(tokens) = max_tokens else {
        let est = if estimate_tokens {
            serde_json::to_string(&hits)
                .map(|s| s.chars().count() / 4)
                .ok()
        } else {
            None
        };
        return (hits, est, false);
    };

    let budget_chars = tokens.saturating_mul(4);
    let mut acc_chars = 0usize;
    let mut kept: Vec<serde_json::Value> = Vec::new();
    for hit in hits {
        let len = serde_json::to_string(&hit)
            .map(|s| s.chars().count())
            .unwrap_or(0);
        if !kept.is_empty() && acc_chars + len > budget_chars {
            break;
        }
        acc_chars += len;
        kept.push(hit);
        if acc_chars >= budget_chars {
            break;
        }
    }
    let est = serde_json::to_string(&kept)
        .map(|s| s.chars().count() / 4)
        .ok();
    let clamped = kept.len() < input_len || est.is_some_and(|e| e > tokens);
    (kept, est, clamped)
}

fn robot_format_from_env() -> Option<RobotFormat> {
    dotenvy::var("CASS_OUTPUT_FORMAT")
        .ok()
        .and_then(|val| match val.trim().to_ascii_lowercase().as_str() {
            "json" => Some(RobotFormat::Json),
            "jsonl" => Some(RobotFormat::Jsonl),
            "compact" => Some(RobotFormat::Compact),
            "sessions" => Some(RobotFormat::Sessions),
            "toon" => Some(RobotFormat::Toon),
            _ => None,
        })
        .or_else(|| {
            dotenvy::var("TOON_DEFAULT_FORMAT").ok().and_then(|val| {
                match val.trim().to_ascii_lowercase().as_str() {
                    "toon" => Some(RobotFormat::Toon),
                    "json" => Some(RobotFormat::Json),
                    _ => None,
                }
            })
        })
}

#[derive(Debug, Clone)]
struct SearchModeMeta {
    requested: crate::search::query::SearchMode,
    realized: crate::search::query::SearchMode,
    defaulted: bool,
    fallback_tier: Option<&'static str>,
    fallback_reason: Option<String>,
}

impl SearchModeMeta {
    fn new(requested: crate::search::query::SearchMode, defaulted: bool) -> Self {
        Self {
            requested,
            realized: requested,
            defaulted,
            fallback_tier: None,
            fallback_reason: None,
        }
    }

    fn semantic_refinement(&self) -> bool {
        matches!(
            self.realized,
            crate::search::query::SearchMode::Semantic | crate::search::query::SearchMode::Hybrid
        ) && self.fallback_tier.is_none()
    }

    fn fail_open_on_semantic_unavailable(&self) -> bool {
        matches!(self.requested, crate::search::query::SearchMode::Hybrid)
    }

    fn fall_back_to_lexical(&mut self, reason: impl Into<String>) {
        self.realized = crate::search::query::SearchMode::Lexical;
        self.fallback_tier = Some("lexical");
        self.fallback_reason = Some(reason.into());
    }
}

fn search_mode_label(mode: crate::search::query::SearchMode) -> &'static str {
    match mode {
        crate::search::query::SearchMode::Lexical => "lexical",
        crate::search::query::SearchMode::Semantic => "semantic",
        crate::search::query::SearchMode::Hybrid => "hybrid",
    }
}

fn toon_encode_options_from_env() -> toon::EncodeOptions {
    let indent = match dotenvy::var("TOON_INDENT") {
        Ok(v) if !v.trim().is_empty() => match v.parse::<usize>() {
            Ok(n) => Some(n),
            Err(e) => {
                warn!("invalid TOON_INDENT={v}: {e} (ignoring)");
                None
            }
        },
        _ => None,
    };

    let key_folding = match dotenvy::var("TOON_KEY_FOLDING") {
        Ok(v) => match v.trim().to_ascii_lowercase().as_str() {
            "" | "off" | "0" | "false" => Some(toon::options::KeyFoldingMode::Off),
            "safe" => Some(toon::options::KeyFoldingMode::Safe),
            other => {
                warn!("invalid TOON_KEY_FOLDING={other} (expected off|safe); ignoring");
                None
            }
        },
        Err(_) => None,
    };

    toon::EncodeOptions {
        indent,
        delimiter: None,
        key_folding,
        flatten_depth: None,
        replacer: None,
    }
}

fn output_structured_value(payload: serde_json::Value, format: RobotFormat) -> CliResult<()> {
    match format {
        RobotFormat::Json => {
            println!(
                "{}",
                serde_json::to_string_pretty(&payload).unwrap_or_default()
            );
        }
        RobotFormat::Jsonl | RobotFormat::Compact | RobotFormat::Sessions => {
            println!("{}", serde_json::to_string(&payload).unwrap_or_default());
        }
        RobotFormat::Toon => {
            let toon_str = toon::encode(payload, Some(toon_encode_options_from_env()));
            print!("{toon_str}");
        }
    }
    Ok(())
}

fn encode_search_cursor(offset: usize, limit: usize) -> Option<String> {
    if limit == 0 {
        return None;
    }
    let payload = serde_json::json!({
        "offset": offset,
        "limit": limit,
    })
    .to_string();
    Some(BASE64_STANDARD.encode(payload))
}

struct SearchCursorManifestInput<'a> {
    requested_limit: usize,
    realized_limit: usize,
    offset: usize,
    returned_count: usize,
    search_page_count: usize,
    total_matches: usize,
    total_matches_exact: bool,
    has_more: bool,
    input_cursor_present: bool,
    next_cursor_present: bool,
    hits_clamped: bool,
    tokens_estimated: Option<usize>,
    max_tokens: Option<usize>,
    timed_out: bool,
    output_projection: &'a str,
    requested_fields: &'a Option<Vec<String>>,
    resolved_fields: &'a Option<Vec<String>>,
    search_mode_meta: &'a SearchModeMeta,
    cache_stats: &'a crate::search::query::CacheStats,
    index_freshness: Option<&'a serde_json::Value>,
}

fn search_cursor_manifest_json(input: SearchCursorManifestInput<'_>) -> serde_json::Value {
    let index_rebuilding = input
        .index_freshness
        .and_then(|freshness| freshness.get("rebuilding"))
        .and_then(serde_json::Value::as_bool)
        .unwrap_or(false);
    let continuation_safe = input.next_cursor_present && !input.timed_out && !index_rebuilding;
    let continuation_reason = if !input.has_more {
        "result window exhausted; no continuation cursor was emitted"
    } else if !input.next_cursor_present {
        "more results may exist, but no continuation cursor could be emitted for this response"
    } else if input.timed_out {
        "partial timeout results are best-effort; rerun before continuing for deterministic pagination"
    } else if index_rebuilding {
        "lexical index is rebuilding; cursor is best-effort until the generation is stable"
    } else if input.hits_clamped {
        "cursor offset advances by emitted hits after token-budget clamping"
    } else {
        "cursor offset advances by emitted hits; reuse the same query, filters, mode, and fields"
    };
    let count_precision = if input.total_matches_exact {
        "exact"
    } else {
        "lower_bound"
    };
    let count_reason = if input.total_matches_exact {
        "search backend returned an exact total without an extra recount"
    } else {
        "total_matches is a lower bound from the current result window; no expensive recount was requested"
    };
    let resolved_fields = match input.resolved_fields {
        None => serde_json::json!("all"),
        Some(fields) if fields.is_empty() => serde_json::json!("all"),
        Some(fields) => serde_json::json!(fields),
    };
    let requested_fields = match input.requested_fields {
        None => serde_json::Value::Null,
        Some(fields) => serde_json::json!(fields),
    };
    let index_freshness = input
        .index_freshness
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let lexical_shard_generation = input
        .cache_stats
        .reader_generation
        .map(|generation| generation.to_string());
    let reload_ms_total = input.cache_stats.reload_ms_total.min(u128::from(u64::MAX)) as u64;

    serde_json::json!({
        "schema_version": 1,
        "has_more": input.has_more,
        "count_precision": count_precision,
        "count_reason": count_reason,
        "continuation_safe": continuation_safe,
        "continuation_reason": continuation_reason,
        "input_cursor_present": input.input_cursor_present,
        "next_cursor_present": input.next_cursor_present,
        "offset": input.offset,
        "next_offset": if input.next_cursor_present {
            serde_json::json!(input.offset.saturating_add(input.returned_count))
        } else {
            serde_json::Value::Null
        },
        "requested_limit": input.requested_limit,
        "realized_limit": input.realized_limit,
        "returned_count": input.returned_count,
        "search_page_count": input.search_page_count,
        "total_matches": input.total_matches,
        "field_mask": {
            "requested": requested_fields,
            "resolved": resolved_fields,
            "projection": input.output_projection,
        },
        "token_budget": {
            "max_tokens": input.max_tokens,
            "tokens_estimated": input.tokens_estimated,
            "hits_clamped": input.hits_clamped,
        },
        "cache_generation": {
            "reader_generation": input.cache_stats.reader_generation,
            "reloads": input.cache_stats.reloads,
            "reload_ms_total": reload_ms_total,
            "policy": input.cache_stats.eviction_policy,
            "ghost_entries": input.cache_stats.ghost_entries,
            "admission_rejects": input.cache_stats.admission_rejects,
        },
        "index_generation": {
            "lexical_shard_generation": lexical_shard_generation,
            "freshness": index_freshness,
            "stale": input.index_freshness.and_then(|f| f.get("stale")).cloned().unwrap_or(serde_json::Value::Null),
            "rebuilding": index_rebuilding,
            "pending_sessions": input.index_freshness.and_then(|f| f.get("pending_sessions")).cloned().unwrap_or(serde_json::Value::Null),
        },
        "semantic_fallback": {
            "requested_search_mode": search_mode_label(input.search_mode_meta.requested),
            "realized_search_mode": search_mode_label(input.search_mode_meta.realized),
            "fallback_tier": input.search_mode_meta.fallback_tier,
            "fallback_reason": input.search_mode_meta.fallback_reason.clone(),
            "semantic_refinement": input.search_mode_meta.semantic_refinement(),
        },
    })
}

/// Output search results in robot-friendly format
#[allow(clippy::too_many_arguments, unused_variables)]
fn output_robot_results(
    query: &str,
    limit: usize,
    cursor_page_limit: usize,
    offset: usize,
    result: &crate::search::query::SearchResult,
    format: RobotFormat,
    include_meta: bool,
    elapsed_ms: u64,
    fields: &Option<Vec<String>>,
    truncation_budgets: FieldBudgets,
    max_tokens: Option<usize>,
    request_id: Option<String>,
    input_cursor: Option<String>,
    has_more_results: bool,
    total_matches_exact: bool,
    state_meta: Option<serde_json::Value>,
    index_freshness: Option<serde_json::Value>,
    warning: Option<String>,
    aggregations: &Aggregations,
    total_matches: usize,
    explanation: Option<&crate::search::query::QueryExplanation>,
    timed_out: bool,
    timeout_ms: Option<u64>,
    search_mode_meta: SearchModeMeta,
    search_ms: u64,
    rerank_ms: u64,
) -> CliResult<()> {
    use std::io::{BufWriter, Write};

    if matches!(format, RobotFormat::Sessions) {
        // Output unique session paths only, one per line.
        // This format is designed for chained searches via --sessions-from.
        use std::collections::BTreeSet;
        let paths: BTreeSet<&str> = result
            .hits
            .iter()
            .map(|hit| hit.source_path.as_str())
            .collect();
        for path in paths {
            println!("{path}");
        }
        return Ok(());
    }

    // Expand presets (minimal, summary, provenance, all, *)
    let resolved_fields = expand_field_presets(fields);

    // Filter hits to requested fields, and only apply truncation when limits are configured.
    let all_fields_requested = resolved_fields
        .as_ref()
        .is_none_or(|fields| fields.is_empty());
    let minimal_projection = resolved_fields.as_ref().is_some_and(|fields| {
        fields.len() == 3
            && fields[0] == "source_path"
            && fields[1] == "line_number"
            && fields[2] == "agent"
    });
    let summary_projection = resolved_fields.as_ref().is_some_and(|fields| {
        fields.len() == 5
            && fields[0] == "source_path"
            && fields[1] == "line_number"
            && fields[2] == "agent"
            && fields[3] == "title"
            && fields[4] == "score"
    });
    let needs_truncation = truncation_budgets.has_any_limit();
    let passthrough_all_fields = all_fields_requested;
    let output_projection = if minimal_projection {
        "minimal"
    } else if summary_projection {
        "summary"
    } else if passthrough_all_fields {
        "all"
    } else {
        "custom"
    };

    // Fast path: summary-field JSON output without optional metadata/features.
    // Avoid intermediary serde_json::Value maps and string clones per hit.
    if matches!(format, RobotFormat::Json)
        && summary_projection
        && !needs_truncation
        && max_tokens.is_none()
        && !include_meta
        && warning.is_none()
        && aggregations.is_empty()
        && result.suggestions.is_empty()
        && explanation.is_none()
        && !timed_out
    {
        use serde::ser::{SerializeMap, SerializeSeq};
        use serde::{Serialize, Serializer};

        struct SummaryHitCompat<'a>(&'a crate::search::query::SearchHit);

        impl Serialize for SummaryHitCompat<'_> {
            fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
            where
                S: Serializer,
            {
                let hit = self.0;
                let mut map = serializer.serialize_map(Some(5))?;
                map.serialize_entry("source_path", &hit.source_path)?;
                map.serialize_entry("line_number", &hit.line_number)?;
                map.serialize_entry("agent", &hit.agent)?;
                map.serialize_entry("title", &hit.title)?;
                let safe_score = safe_robot_score_value(hit.score);
                map.serialize_entry("score", &safe_score)?;
                map.end()
            }
        }

        fn serialize_summary_hits<S>(
            hits: &[crate::search::query::SearchHit],
            serializer: S,
        ) -> Result<S::Ok, S::Error>
        where
            S: Serializer,
        {
            let mut seq = serializer.serialize_seq(Some(hits.len()))?;
            for hit in hits {
                seq.serialize_element(&SummaryHitCompat(hit))?;
            }
            seq.end()
        }

        #[derive(serde::Serialize)]
        struct FastSummaryJsonPayload<'a> {
            query: &'a str,
            limit: usize,
            offset: usize,
            count: usize,
            total_matches: usize,
            #[serde(serialize_with = "serialize_summary_hits")]
            hits: &'a [crate::search::query::SearchHit],
            max_tokens: Option<usize>,
            request_id: Option<String>,
            cursor: Option<String>,
            hits_clamped: bool,
        }

        let payload = FastSummaryJsonPayload {
            query,
            limit,
            offset,
            count: result.hits.len(),
            total_matches,
            hits: &result.hits,
            max_tokens,
            request_id,
            cursor: input_cursor,
            hits_clamped: false,
        };
        let stdout = std::io::stdout();
        let mut out = BufWriter::new(stdout.lock());
        serde_json::to_writer_pretty(&mut out, &payload).map_err(|e| CliError {
            code: 9,
            kind: CliErrorKind::EncodeJson.kind_str(),
            message: format!("failed to encode json: {e}"),
            hint: None,
            retryable: false,
        })?;
        writeln!(&mut out).map_err(|e| CliError {
            code: 9,
            kind: CliErrorKind::EncodeJson.kind_str(),
            message: format!("failed to write trailing newline: {e}"),
            hint: None,
            retryable: false,
        })?;
        out.flush().map_err(|e| CliError {
            code: 9,
            kind: CliErrorKind::EncodeJson.kind_str(),
            message: format!("failed to flush buffered json output: {e}"),
            hint: None,
            retryable: false,
        })?;
        return Ok(());
    }

    // Fast path: full-field JSON output without optional metadata/features.
    // Serialize hits directly with compatibility formatting to avoid
    // materializing intermediary serde_json::Value hits.
    if matches!(format, RobotFormat::Json)
        && all_fields_requested
        && !needs_truncation
        && max_tokens.is_none()
        && !include_meta
        && warning.is_none()
        && aggregations.is_empty()
        && result.suggestions.is_empty()
        && explanation.is_none()
        && !timed_out
    {
        use serde::ser::{SerializeMap, SerializeSeq};
        use serde::{Serialize, Serializer};

        struct FullHitCompat<'a>(&'a crate::search::query::SearchHit);

        impl Serialize for FullHitCompat<'_> {
            fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
            where
                S: Serializer,
            {
                let hit = self.0;
                let normalized_source_id = normalized_robot_hit_source_id(hit);
                let normalized_origin_host = normalized_robot_hit_origin_host(hit);
                let mut fields = 12usize;
                if hit.workspace_original.is_some() {
                    fields += 1;
                }
                if normalized_origin_host.is_some() {
                    fields += 1;
                }
                let mut map = serializer.serialize_map(Some(fields))?;
                map.serialize_entry("title", &hit.title)?;
                map.serialize_entry("snippet", &hit.snippet)?;
                map.serialize_entry("content", &hit.content)?;
                let safe_score = safe_robot_score_value(hit.score);
                map.serialize_entry("score", &safe_score)?;
                map.serialize_entry("source_path", &hit.source_path)?;
                map.serialize_entry("agent", &hit.agent)?;
                map.serialize_entry("workspace", &hit.workspace)?;
                if let Some(ref workspace_original) = hit.workspace_original {
                    map.serialize_entry("workspace_original", workspace_original)?;
                }
                map.serialize_entry("created_at", &hit.created_at)?;
                map.serialize_entry("line_number", &hit.line_number)?;
                map.serialize_entry("match_type", &hit.match_type)?;
                let normalized_origin_kind = normalized_robot_hit_origin_kind(hit);
                map.serialize_entry("source_id", &normalized_source_id)?;
                map.serialize_entry("origin_kind", &normalized_origin_kind)?;
                if let Some(ref origin_host) = normalized_origin_host {
                    map.serialize_entry("origin_host", origin_host)?;
                }
                map.end()
            }
        }

        fn serialize_full_hits<S>(
            hits: &[crate::search::query::SearchHit],
            serializer: S,
        ) -> Result<S::Ok, S::Error>
        where
            S: Serializer,
        {
            let mut seq = serializer.serialize_seq(Some(hits.len()))?;
            for hit in hits {
                seq.serialize_element(&FullHitCompat(hit))?;
            }
            seq.end()
        }

        #[derive(serde::Serialize)]
        struct FastJsonPayload<'a> {
            query: &'a str,
            limit: usize,
            offset: usize,
            count: usize,
            total_matches: usize,
            #[serde(serialize_with = "serialize_full_hits")]
            hits: &'a [crate::search::query::SearchHit],
            max_tokens: Option<usize>,
            request_id: Option<String>,
            cursor: Option<String>,
            hits_clamped: bool,
        }

        let payload = FastJsonPayload {
            query,
            limit,
            offset,
            count: result.hits.len(),
            total_matches,
            hits: &result.hits,
            max_tokens,
            request_id,
            cursor: input_cursor,
            hits_clamped: false,
        };
        let stdout = std::io::stdout();
        let mut out = BufWriter::new(stdout.lock());
        serde_json::to_writer_pretty(&mut out, &payload).map_err(|e| CliError {
            code: 9,
            kind: CliErrorKind::EncodeJson.kind_str(),
            message: format!("failed to encode json: {e}"),
            hint: None,
            retryable: false,
        })?;
        writeln!(&mut out).map_err(|e| CliError {
            code: 9,
            kind: CliErrorKind::EncodeJson.kind_str(),
            message: format!("failed to write trailing newline: {e}"),
            hint: None,
            retryable: false,
        })?;
        out.flush().map_err(|e| CliError {
            code: 9,
            kind: CliErrorKind::EncodeJson.kind_str(),
            message: format!("failed to flush buffered json output: {e}"),
            hint: None,
            retryable: false,
        })?;
        return Ok(());
    }

    let filtered_hits: Vec<serde_json::Value> = if minimal_projection {
        result
            .hits
            .iter()
            .map(|hit| {
                serde_json::json!({
                    "source_path": hit.source_path.as_str(),
                    "line_number": hit.line_number,
                    "agent": hit.agent.as_str(),
                })
            })
            .collect()
    } else if summary_projection && !needs_truncation {
        result
            .hits
            .iter()
            .map(|hit| {
                let mut map = serde_json::Map::with_capacity(5);
                map.insert(
                    "source_path".to_string(),
                    serde_json::Value::String(hit.source_path.clone()),
                );
                map.insert(
                    "line_number".to_string(),
                    serde_json::to_value(hit.line_number).unwrap_or_default(),
                );
                map.insert(
                    "agent".to_string(),
                    serde_json::Value::String(hit.agent.clone()),
                );
                map.insert(
                    "title".to_string(),
                    serde_json::Value::String(hit.title.clone()),
                );
                map.insert("score".to_string(), safe_robot_score_value(hit.score));
                serde_json::Value::Object(map)
            })
            .collect()
    } else if passthrough_all_fields && !needs_truncation {
        // Sanitize NaN/Infinity scores before bulk serialization — serde_json
        // cannot represent non-finite floats, which would silently drop all hits.
        let sanitized: Vec<_> = result
            .hits
            .iter()
            .map(normalized_robot_hit_for_output)
            .collect();
        match serde_json::to_value(&sanitized).unwrap_or_default() {
            serde_json::Value::Array(values) => values,
            _ => Vec::new(),
        }
    } else if needs_truncation {
        result
            .hits
            .iter()
            .map(|hit| filter_hit_fields(hit, &resolved_fields))
            .map(|hit| apply_content_truncation(hit, truncation_budgets))
            .collect()
    } else {
        result
            .hits
            .iter()
            .map(|hit| filter_hit_fields(hit, &resolved_fields))
            .collect()
    };

    // Clamp hits to token budget if provided (approx 4 chars per token)
    let jsonl_meta_emitted = matches!(format, RobotFormat::Jsonl)
        && (include_meta
            || !aggregations.is_empty()
            || !result.suggestions.is_empty()
            || explanation.is_some());
    let estimate_tokens = max_tokens.is_some() || include_meta || jsonl_meta_emitted;
    let (filtered_hits, tokens_estimated, hits_clamped) =
        clamp_hits_to_budget(filtered_hits, max_tokens, estimate_tokens);
    let search_page_count = result.hits.len();
    let returned_count = filtered_hits.len();
    let clamped_unemitted_hits = returned_count < search_page_count;
    let cursor_has_more = has_more_results || clamped_unemitted_hits;
    let realized_cursor_limit = if cursor_page_limit == 0 {
        limit
    } else {
        cursor_page_limit
    };
    let next_cursor = if cursor_has_more && cursor_page_limit > 0 && returned_count > 0 {
        encode_search_cursor(offset.saturating_add(returned_count), cursor_page_limit)
    } else {
        None
    };
    let query_plan = crate::query_cost_planner::build_query_cost_plan(
        crate::query_cost_planner::QueryCostPlanInput {
            query_chars: query.chars().count(),
            requested_mode: search_mode_label(search_mode_meta.requested).to_string(),
            realized_mode: search_mode_label(search_mode_meta.realized).to_string(),
            fallback_tier: search_mode_meta.fallback_tier.map(str::to_string),
            fallback_reason: search_mode_meta.fallback_reason.clone(),
            semantic_refinement: search_mode_meta.semantic_refinement(),
            wildcard_fallback: result.wildcard_fallback,
            limit: realized_cursor_limit,
            offset,
            returned_count,
            total_matches,
            max_tokens,
            tokens_estimated,
            hits_clamped,
            timeout_ms,
            timed_out,
            input_cursor_present: input_cursor.is_some(),
            next_cursor_present: next_cursor.is_some(),
            output_projection: output_projection.to_string(),
            cache_hits: result.cache_stats.cache_hits,
            cache_misses: result.cache_stats.cache_miss,
            cache_shortfall: result.cache_stats.cache_shortfall,
            aggregation_count: usize::from(aggregations.agent.is_some())
                + usize::from(aggregations.workspace.is_some())
                + usize::from(aggregations.date.is_some())
                + usize::from(aggregations.match_type.is_some()),
        },
    );
    let query_plan_json = serde_json::to_value(&query_plan).unwrap_or(serde_json::Value::Null);
    let cursor_manifest_json = search_cursor_manifest_json(SearchCursorManifestInput {
        requested_limit: limit,
        realized_limit: realized_cursor_limit,
        offset,
        returned_count,
        search_page_count,
        total_matches,
        total_matches_exact,
        has_more: cursor_has_more,
        input_cursor_present: input_cursor.is_some(),
        next_cursor_present: next_cursor.is_some(),
        hits_clamped,
        tokens_estimated,
        max_tokens,
        timed_out,
        output_projection,
        requested_fields: fields,
        resolved_fields: &resolved_fields,
        search_mode_meta: &search_mode_meta,
        cache_stats: &result.cache_stats,
        index_freshness: index_freshness.as_ref(),
    });
    let index_rebuilding = index_freshness
        .as_ref()
        .and_then(|freshness| freshness.get("rebuilding"))
        .and_then(serde_json::Value::as_bool)
        .unwrap_or(false);
    let pending_sessions = index_freshness
        .as_ref()
        .and_then(|freshness| freshness.get("pending_sessions"))
        .and_then(serde_json::Value::as_u64);
    let explanation_cards = crate::explainability::search_robot_explanation_cards(
        crate::explainability::SearchRobotExplanationInput {
            requested_mode: search_mode_label(search_mode_meta.requested).to_string(),
            realized_mode: search_mode_label(search_mode_meta.realized).to_string(),
            fallback_tier: search_mode_meta.fallback_tier.map(str::to_string),
            fallback_reason: search_mode_meta.fallback_reason.clone(),
            semantic_refinement: search_mode_meta.semantic_refinement(),
            wildcard_fallback: result.wildcard_fallback,
            cache_policy: result.cache_stats.eviction_policy.to_string(),
            cache_hits: result.cache_stats.cache_hits,
            cache_misses: result.cache_stats.cache_miss,
            cache_shortfall: result.cache_stats.cache_shortfall,
            cache_evictions: result.cache_stats.eviction_count,
            cache_admission_rejects: result.cache_stats.admission_rejects,
            cache_ghost_entries: result.cache_stats.ghost_entries,
            index_rebuilding,
            pending_sessions,
        },
    );
    let explanation_cards_json =
        serde_json::to_value(&explanation_cards).unwrap_or_else(|_| serde_json::json!([]));

    // Serialize aggregations if present
    let agg_json = if aggregations.is_empty() {
        None
    } else {
        Some(serde_json::to_value(aggregations).unwrap_or_default())
    };

    match format {
        RobotFormat::Json => {
            let mut payload = serde_json::json!({
                "query": query,
                "limit": limit,
                "offset": offset,
                "count": filtered_hits.len(),
                "total_matches": total_matches,
                "hits": filtered_hits,
                "max_tokens": max_tokens,
                "request_id": request_id,
                "cursor": input_cursor,
                "hits_clamped": hits_clamped,
            });

            // Add suggestions if present
            if !result.suggestions.is_empty()
                && let serde_json::Value::Object(ref mut map) = payload
            {
                map.insert(
                    "suggestions".to_string(),
                    serde_json::to_value(&result.suggestions).unwrap_or_default(),
                );
            }

            // Add aggregations if present
            if let (Some(agg), serde_json::Value::Object(map)) = (&agg_json, &mut payload) {
                map.insert("aggregations".to_string(), agg.clone());
            }

            // Add query explanation if requested
            if let (Some(exp), serde_json::Value::Object(map)) = (explanation, &mut payload) {
                map.insert(
                    "explanation".to_string(),
                    serde_json::to_value(exp).unwrap_or_default(),
                );
            }

            // Add extended metadata if requested
            if include_meta && let serde_json::Value::Object(ref mut map) = payload {
                let mut meta = serde_json::json!({
                    "elapsed_ms": elapsed_ms,
                    "search_mode": search_mode_meta.realized,
                    "requested_search_mode": search_mode_meta.requested,
                    "mode_defaulted": search_mode_meta.defaulted,
                    "fallback_tier": search_mode_meta.fallback_tier,
                    "fallback_reason": search_mode_meta.fallback_reason.clone(),
                    "semantic_refinement": search_mode_meta.semantic_refinement(),
                    "wildcard_fallback": result.wildcard_fallback,
                    "cache_stats": {
                        "hits": result.cache_stats.cache_hits,
                        "misses": result.cache_stats.cache_miss,
                        "shortfall": result.cache_stats.cache_shortfall,
                        "prewarm_scheduled": result.cache_stats.prewarm_scheduled,
                        "prewarm_skipped_pressure": result.cache_stats.prewarm_skipped_pressure,
                    },
                    // Search pipeline timing breakdown (T7.4)
                    "timing": {
                        "search_ms": search_ms,
                        "rerank_ms": rerank_ms,
                        "other_ms": elapsed_ms.saturating_sub(search_ms).saturating_sub(rerank_ms),
                    },
                    "tokens_estimated": tokens_estimated,
                    "max_tokens": max_tokens,
                    "request_id": request_id,
                    "next_cursor": next_cursor,
                    "hits_clamped": hits_clamped,
                    "query_plan": query_plan_json.clone(),
                    "cursor_manifest": cursor_manifest_json.clone(),
                    "explanation_cards": explanation_cards_json.clone(),
                });
                if let Some(state) = state_meta
                    && let serde_json::Value::Object(ref mut m) = meta
                {
                    m.insert("state".to_string(), state);
                }
                if let Some(freshness) = index_freshness
                    && let serde_json::Value::Object(ref mut m) = meta
                {
                    m.insert("index_freshness".to_string(), freshness);
                }
                // Add timeout info to _meta if timeout was configured
                if let Some(timeout) = timeout_ms
                    && let serde_json::Value::Object(ref mut m) = meta
                {
                    m.insert("timeout_ms".to_string(), serde_json::json!(timeout));
                    m.insert("timed_out".to_string(), serde_json::json!(timed_out));
                    if timed_out {
                        m.insert("partial_results".to_string(), serde_json::json!(true));
                    }
                }
                // Add ANN stats to _meta if approximate search was used
                if let Some(ref ann_stats) = result.ann_stats
                    && let serde_json::Value::Object(ref mut m) = meta
                {
                    m.insert(
                        "ann_stats".to_string(),
                        serde_json::to_value(ann_stats).unwrap_or_default(),
                    );
                }
                map.insert("_meta".to_string(), meta);

                if let Some(warn) = &warning {
                    map.insert(
                        "_warning".to_string(),
                        serde_json::Value::String(warn.clone()),
                    );
                }
                // Add top-level timeout indicator if timed out
                if timed_out {
                    map.insert(
                        "_timeout".to_string(),
                        serde_json::json!({
                            "code": 10,
                            "kind": "timeout",
                            "message": format!("Operation exceeded timeout of {}ms", timeout_ms.unwrap_or(0)),
                            "retryable": true,
                            "partial_results": true
                        }),
                    );
                }
            }

            let stdout = std::io::stdout();
            let mut out = BufWriter::new(stdout.lock());
            serde_json::to_writer_pretty(&mut out, &payload).map_err(|e| CliError {
                code: 9,
                kind: CliErrorKind::EncodeJson.kind_str(),
                message: format!("failed to encode json: {e}"),
                hint: None,
                retryable: false,
            })?;
            writeln!(&mut out).map_err(|e| CliError {
                code: 9,
                kind: CliErrorKind::EncodeJson.kind_str(),
                message: format!("failed to write trailing newline: {e}"),
                hint: None,
                retryable: false,
            })?;
            out.flush().map_err(|e| CliError {
                code: 9,
                kind: CliErrorKind::EncodeJson.kind_str(),
                message: format!("failed to flush buffered json output: {e}"),
                hint: None,
                retryable: false,
            })?;
        }
        RobotFormat::Jsonl => {
            let stdout = std::io::stdout();
            let mut out = BufWriter::new(stdout.lock());

            // JSONL: one object per line, optional _meta header
            if include_meta
                || agg_json.is_some()
                || !result.suggestions.is_empty()
                || explanation.is_some()
            {
                let mut meta = serde_json::json!({
                    "_meta": {
                        "query": query,
                        "limit": limit,
                        "offset": offset,
                        "count": filtered_hits.len(),
                        "total_matches": total_matches,
                        "elapsed_ms": elapsed_ms,
                        "search_mode": search_mode_meta.realized,
                        "requested_search_mode": search_mode_meta.requested,
                        "mode_defaulted": search_mode_meta.defaulted,
                        "fallback_tier": search_mode_meta.fallback_tier,
                        "fallback_reason": search_mode_meta.fallback_reason.clone(),
                        "semantic_refinement": search_mode_meta.semantic_refinement(),
                        "wildcard_fallback": result.wildcard_fallback,
                        "cache_stats": {
                            "hits": result.cache_stats.cache_hits,
                            "misses": result.cache_stats.cache_miss,
                            "shortfall": result.cache_stats.cache_shortfall,
                            "prewarm_scheduled": result.cache_stats.prewarm_scheduled,
                            "prewarm_skipped_pressure": result.cache_stats.prewarm_skipped_pressure,
                        },
                        "tokens_estimated": tokens_estimated,
                        "max_tokens": max_tokens,
                        "request_id": request_id,
                        "next_cursor": next_cursor,
                        "hits_clamped": hits_clamped,
                        "query_plan": query_plan_json.clone(),
                        "cursor_manifest": cursor_manifest_json.clone(),
                        "explanation_cards": explanation_cards_json.clone(),
                    }
                });
                if let Some(state) = state_meta
                    && let serde_json::Value::Object(ref mut outer) = meta
                    && let Some(serde_json::Value::Object(m)) = outer.get_mut("_meta")
                {
                    m.insert("state".to_string(), state);
                }
                if let Some(freshness) = index_freshness
                    && let serde_json::Value::Object(ref mut outer) = meta
                    && let Some(serde_json::Value::Object(m)) = outer.get_mut("_meta")
                {
                    m.insert("index_freshness".to_string(), freshness);
                }
                // Add suggestions to meta line
                if !result.suggestions.is_empty()
                    && let serde_json::Value::Object(ref mut map) = meta
                {
                    map.insert(
                        "suggestions".to_string(),
                        serde_json::to_value(&result.suggestions).unwrap_or_default(),
                    );
                }
                // Add aggregations to meta line
                if let (Some(agg), serde_json::Value::Object(map)) = (&agg_json, &mut meta) {
                    map.insert("aggregations".to_string(), agg.clone());
                }
                // Add explanation to meta line
                if let (Some(exp), serde_json::Value::Object(map)) = (explanation, &mut meta) {
                    map.insert(
                        "explanation".to_string(),
                        serde_json::to_value(exp).unwrap_or_default(),
                    );
                }
                if let Some(warn) = &warning
                    && let Some(m) = meta.get_mut("_meta").and_then(|v| v.as_object_mut())
                {
                    m.insert(
                        "_warning".to_string(),
                        serde_json::Value::String(warn.clone()),
                    );
                }
                // Add timeout info to JSONL _meta
                if let Some(m) = meta.get_mut("_meta").and_then(|v| v.as_object_mut())
                    && let Some(timeout) = timeout_ms
                {
                    m.insert("timeout_ms".to_string(), serde_json::json!(timeout));
                    m.insert("timed_out".to_string(), serde_json::json!(timed_out));
                    if timed_out {
                        m.insert("partial_results".to_string(), serde_json::json!(true));
                    }
                }
                // Add top-level timeout indicator if timed out
                if timed_out && let serde_json::Value::Object(ref mut map) = meta {
                    map.insert(
                        "_timeout".to_string(),
                        serde_json::json!({
                            "code": 10,
                            "kind": "timeout",
                            "message": format!("Operation exceeded timeout of {}ms", timeout_ms.unwrap_or(0)),
                            "retryable": true,
                            "partial_results": true
                        }),
                    );
                }
                serde_json::to_writer(&mut out, &meta).map_err(|e| CliError {
                    code: 9,
                    kind: CliErrorKind::EncodeJson.kind_str(),
                    message: format!("failed to encode jsonl metadata: {e}"),
                    hint: None,
                    retryable: false,
                })?;
                writeln!(&mut out).map_err(|e| CliError {
                    code: 9,
                    kind: CliErrorKind::EncodeJson.kind_str(),
                    message: format!("failed to write jsonl metadata newline: {e}"),
                    hint: None,
                    retryable: false,
                })?;
            }
            // One hit per line (with field filtering applied)
            for hit in &filtered_hits {
                serde_json::to_writer(&mut out, hit).map_err(|e| CliError {
                    code: 9,
                    kind: CliErrorKind::EncodeJson.kind_str(),
                    message: format!("failed to encode jsonl hit: {e}"),
                    hint: None,
                    retryable: false,
                })?;
                writeln!(&mut out).map_err(|e| CliError {
                    code: 9,
                    kind: CliErrorKind::EncodeJson.kind_str(),
                    message: format!("failed to write jsonl newline: {e}"),
                    hint: None,
                    retryable: false,
                })?;
            }
            out.flush().map_err(|e| CliError {
                code: 9,
                kind: CliErrorKind::EncodeJson.kind_str(),
                message: format!("failed to flush buffered jsonl output: {e}"),
                hint: None,
                retryable: false,
            })?;
        }
        RobotFormat::Compact => {
            // Single-line compact JSON
            let mut payload = serde_json::json!({
                "query": query,
                "limit": limit,
                "offset": offset,
                "count": filtered_hits.len(),
                "total_matches": total_matches,
                "hits": filtered_hits,
                "max_tokens": max_tokens,
                "request_id": request_id,
                "cursor": input_cursor,
                "hits_clamped": hits_clamped,
            });

            // Add suggestions if present
            if !result.suggestions.is_empty()
                && let serde_json::Value::Object(ref mut map) = payload
            {
                map.insert(
                    "suggestions".to_string(),
                    serde_json::to_value(&result.suggestions).unwrap_or_default(),
                );
            }

            // Add aggregations if present
            if let (Some(agg), serde_json::Value::Object(map)) = (&agg_json, &mut payload) {
                map.insert("aggregations".to_string(), agg.clone());
            }

            // Add query explanation if requested
            if let (Some(exp), serde_json::Value::Object(map)) = (explanation, &mut payload) {
                map.insert(
                    "explanation".to_string(),
                    serde_json::to_value(exp).unwrap_or_default(),
                );
            }

            if include_meta && let serde_json::Value::Object(ref mut map) = payload {
                let mut meta = serde_json::json!({
                    "elapsed_ms": elapsed_ms,
                    "search_mode": search_mode_meta.realized,
                    "requested_search_mode": search_mode_meta.requested,
                    "mode_defaulted": search_mode_meta.defaulted,
                    "fallback_tier": search_mode_meta.fallback_tier,
                    "fallback_reason": search_mode_meta.fallback_reason.clone(),
                    "semantic_refinement": search_mode_meta.semantic_refinement(),
                    "wildcard_fallback": result.wildcard_fallback,
                    "tokens_estimated": tokens_estimated,
                    "max_tokens": max_tokens,
                    "request_id": request_id,
                    "next_cursor": next_cursor,
                    "hits_clamped": hits_clamped,
                    "query_plan": query_plan_json.clone(),
                    "cursor_manifest": cursor_manifest_json.clone(),
                    "explanation_cards": explanation_cards_json.clone(),
                });
                if let Some(state) = state_meta
                    && let serde_json::Value::Object(ref mut m) = meta
                {
                    m.insert("state".to_string(), state);
                }
                if let Some(freshness) = index_freshness
                    && let serde_json::Value::Object(ref mut m) = meta
                {
                    m.insert("index_freshness".to_string(), freshness);
                }
                // Add timeout info to _meta if timeout was configured
                if let Some(timeout) = timeout_ms
                    && let serde_json::Value::Object(ref mut m) = meta
                {
                    m.insert("timeout_ms".to_string(), serde_json::json!(timeout));
                    m.insert("timed_out".to_string(), serde_json::json!(timed_out));
                    if timed_out {
                        m.insert("partial_results".to_string(), serde_json::json!(true));
                    }
                }
                // Add ANN stats to _meta if approximate search was used
                if let Some(ref ann_stats) = result.ann_stats
                    && let serde_json::Value::Object(ref mut m) = meta
                {
                    m.insert(
                        "ann_stats".to_string(),
                        serde_json::to_value(ann_stats).unwrap_or_default(),
                    );
                }
                map.insert("_meta".to_string(), meta);
                if let Some(warn) = &warning {
                    map.insert(
                        "_warning".to_string(),
                        serde_json::Value::String(warn.clone()),
                    );
                }
                // Add top-level timeout indicator if timed out
                if timed_out {
                    map.insert(
                        "_timeout".to_string(),
                        serde_json::json!({
                            "code": 10,
                            "kind": "timeout",
                            "message": format!("Operation exceeded timeout of {}ms", timeout_ms.unwrap_or(0)),
                            "retryable": true,
                            "partial_results": true
                        }),
                    );
                }
            }

            let out = serde_json::to_string(&payload).map_err(|e| CliError {
                code: 9,
                kind: CliErrorKind::EncodeJson.kind_str(),
                message: format!("failed to encode json: {e}"),
                hint: None,
                retryable: false,
            })?;
            println!("{out}");
        }
        RobotFormat::Toon => {
            // TOON: Token-Optimized Object Notation
            // Encodes via toon crate for token-efficient output
            let mut payload = serde_json::json!({
                "query": query,
                "limit": limit,
                "offset": offset,
                "count": filtered_hits.len(),
                "total_matches": total_matches,
                "hits": filtered_hits,
                "max_tokens": max_tokens,
                "request_id": request_id,
                "cursor": input_cursor,
                "hits_clamped": hits_clamped,
            });

            // Add suggestions if present
            if !result.suggestions.is_empty()
                && let serde_json::Value::Object(ref mut map) = payload
            {
                map.insert(
                    "suggestions".to_string(),
                    serde_json::to_value(&result.suggestions).unwrap_or_default(),
                );
            }

            // Add aggregations if present
            if let (Some(agg), serde_json::Value::Object(map)) = (&agg_json, &mut payload) {
                map.insert("aggregations".to_string(), agg.clone());
            }

            // Add query explanation if requested
            if let (Some(exp), serde_json::Value::Object(map)) = (explanation, &mut payload) {
                map.insert(
                    "explanation".to_string(),
                    serde_json::to_value(exp).unwrap_or_default(),
                );
            }

            if include_meta && let serde_json::Value::Object(ref mut map) = payload {
                let mut meta = serde_json::json!({
                    "elapsed_ms": elapsed_ms,
                    "search_mode": search_mode_meta.realized,
                    "requested_search_mode": search_mode_meta.requested,
                    "mode_defaulted": search_mode_meta.defaulted,
                    "fallback_tier": search_mode_meta.fallback_tier,
                    "fallback_reason": search_mode_meta.fallback_reason.clone(),
                    "semantic_refinement": search_mode_meta.semantic_refinement(),
                    "wildcard_fallback": result.wildcard_fallback,
                    "tokens_estimated": tokens_estimated,
                    "max_tokens": max_tokens,
                    "request_id": request_id,
                    "next_cursor": next_cursor,
                    "hits_clamped": hits_clamped,
                    "query_plan": query_plan_json.clone(),
                    "cursor_manifest": cursor_manifest_json.clone(),
                    "explanation_cards": explanation_cards_json.clone(),
                });
                if let Some(state) = state_meta
                    && let serde_json::Value::Object(ref mut m) = meta
                {
                    m.insert("state".to_string(), state);
                }
                if let Some(freshness) = index_freshness
                    && let serde_json::Value::Object(ref mut m) = meta
                {
                    m.insert("index_freshness".to_string(), freshness);
                }
                if let Some(timeout) = timeout_ms
                    && let serde_json::Value::Object(ref mut m) = meta
                {
                    m.insert("timeout_ms".to_string(), serde_json::json!(timeout));
                    m.insert("timed_out".to_string(), serde_json::json!(timed_out));
                    if timed_out {
                        m.insert("partial_results".to_string(), serde_json::json!(true));
                    }
                }
                // Add ANN stats to _meta if approximate search was used
                if let Some(ref ann_stats) = result.ann_stats
                    && let serde_json::Value::Object(ref mut m) = meta
                {
                    m.insert(
                        "ann_stats".to_string(),
                        serde_json::to_value(ann_stats).unwrap_or_default(),
                    );
                }
                map.insert("_meta".to_string(), meta);
                if let Some(warn) = &warning {
                    map.insert(
                        "_warning".to_string(),
                        serde_json::Value::String(warn.clone()),
                    );
                }
                if timed_out {
                    map.insert(
                        "_timeout".to_string(),
                        serde_json::json!({
                            "code": 10,
                            "kind": "timeout",
                            "message": format!("Operation exceeded timeout of {}ms", timeout_ms.unwrap_or(0)),
                            "retryable": true,
                            "partial_results": true
                        }),
                    );
                }
            }

            let json_str = serde_json::to_string(&payload).map_err(|e| CliError {
                code: 9,
                kind: CliErrorKind::EncodeJson.kind_str(),
                message: format!("failed to encode json: {e}"),
                hint: None,
                retryable: false,
            })?;

            let toon_str = toon::encode(payload, Some(toon_encode_options_from_env()));

            // Preserve the existing "compact JSON" behavior by first ensuring the payload is
            // valid JSON (serde_json::to_string above). We don't need the string itself here.
            drop(json_str);
            print!("{toon_str}");
        }
        RobotFormat::Sessions => {
            unreachable!("RobotFormat::Sessions is handled above to avoid building hit payloads");
        }
    }

    Ok(())
}

fn source_filter_where_clause(
    source_filter: Option<&crate::sources::provenance::SourceFilter>,
) -> (String, Option<String>) {
    let normalized_source_sql = normalized_source_identity_sql_expr("c.source_id", "c.origin_host");
    match source_filter {
        None | Some(crate::sources::provenance::SourceFilter::All) => (String::new(), None),
        Some(crate::sources::provenance::SourceFilter::Local) => (
            format!(
                " WHERE {normalized_source_sql} = '{local}'",
                local = crate::sources::provenance::LOCAL_SOURCE_ID,
            ),
            None,
        ),
        Some(crate::sources::provenance::SourceFilter::Remote) => (
            format!(
                " WHERE {normalized_source_sql} != '{local}'",
                local = crate::sources::provenance::LOCAL_SOURCE_ID,
            ),
            None,
        ),
        Some(crate::sources::provenance::SourceFilter::SourceId(id)) => (
            format!(" WHERE {normalized_source_sql} = ?"),
            Some(
                canonical_followup_source_id(Some(id.as_str()))
                    .unwrap_or_else(|| id.trim().to_string()),
            ),
        ),
    }
}

fn stats_message_count_sql(source_where: &str) -> String {
    if source_where.is_empty() {
        "SELECT COUNT(*) FROM messages".to_string()
    } else {
        format!(
            "SELECT COUNT(*) FROM messages m JOIN conversations c ON m.conversation_id = c.id{source_where}"
        )
    }
}

fn stats_workspace_count_sql(source_where: &str) -> String {
    if source_where.is_empty() {
        "SELECT c.workspace_id, COUNT(*) FROM conversations c WHERE c.workspace_id IS NOT NULL GROUP BY c.workspace_id ORDER BY COUNT(*) DESC".to_string()
    } else {
        format!(
            "SELECT c.workspace_id, COUNT(*) FROM conversations c{source_where} AND c.workspace_id IS NOT NULL GROUP BY c.workspace_id ORDER BY COUNT(*) DESC"
        )
    }
}

fn append_source_filter_condition(
    sql: &mut String,
    params: &mut Vec<frankensqlite::compat::ParamValue>,
    source_filter: &crate::sources::provenance::SourceFilter,
) {
    let normalized_source_sql = normalized_source_identity_sql_expr("c.source_id", "c.origin_host");
    match source_filter {
        crate::sources::provenance::SourceFilter::All => {}
        crate::sources::provenance::SourceFilter::Local => {
            sql.push_str(&format!(
                " AND {normalized_source_sql} = '{local}'",
                local = crate::sources::provenance::LOCAL_SOURCE_ID,
            ));
        }
        crate::sources::provenance::SourceFilter::Remote => {
            sql.push_str(&format!(
                " AND {normalized_source_sql} != '{local}'",
                local = crate::sources::provenance::LOCAL_SOURCE_ID,
            ));
        }
        crate::sources::provenance::SourceFilter::SourceId(id) => {
            sql.push_str(&format!(
                " AND {normalized_source_sql} = ?{}",
                params.len() + 1
            ));
            params.push(
                canonical_followup_source_id(Some(id.as_str()))
                    .unwrap_or_else(|| id.trim().to_string())
                    .into(),
            );
        }
    }
}

fn run_stats(
    data_dir_override: &Option<PathBuf>,
    db_override: Option<PathBuf>,
    output_format: Option<RobotFormat>,
    source: Option<&str>,
    by_source: bool,
) -> CliResult<()> {
    use crate::sources::provenance::SourceFilter;

    use frankensqlite::compat::{ParamValue, RowExt};

    let data_dir = data_dir_override.clone().unwrap_or_else(default_data_dir);
    let db_path = db_override.unwrap_or_else(|| data_dir.join("agent_search.db"));
    let conn = open_franken_cli_read_db(db_path.clone(), "stats", Duration::from_secs(30))?;

    // Parse source filter (P3.7)
    let source_filter = source.map(SourceFilter::parse);

    // Build WHERE clause for source filtering
    let (source_where, source_param): (String, Option<String>) =
        source_filter_where_clause(source_filter.as_ref());

    // Helper: build params slice from optional source param
    let make_params = |param: &Option<String>| -> Vec<ParamValue> {
        match param {
            Some(p) => vec![ParamValue::from(p.as_str())],
            None => vec![],
        }
    };

    // Get counts and statistics with source filter
    let params = make_params(&source_param);
    let conversation_sql = format!("SELECT COUNT(*) FROM conversations c{source_where}");
    let message_sql = stats_message_count_sql(&source_where);

    let mut conversation_count: i64 =
        franken_query_row_map_retry(&conn, &conversation_sql, &params, |r| r.get_typed(0))
            .unwrap_or(0);

    let mut message_count: i64 =
        franken_query_row_map_retry(&conn, &message_sql, &params, |r| r.get_typed(0)).unwrap_or(0);
    if conversation_count == 0 {
        conversation_count = fresh_franken_count_retry(
            &db_path,
            "stats",
            Duration::from_secs(30),
            &conversation_sql,
            &params,
        )
        .unwrap_or(0);
    }
    if message_count == 0 {
        message_count = fresh_franken_count_retry(
            &db_path,
            "stats",
            Duration::from_secs(30),
            &message_sql,
            &params,
        )
        .unwrap_or(0);
    }

    let agent_lookup: HashMap<i64, String> =
        franken_query_map_collect_retry(&conn, "SELECT id, slug FROM agents", &[], |r| {
            Ok((r.get_typed::<i64>(0)?, r.get_typed::<String>(1)?))
        })
        .map_err(|e| CliError::unknown(format!("query: {e}")))?
        .into_iter()
        .collect();

    let agent_sql = format!(
        "SELECT c.agent_id, COUNT(*) FROM conversations c{source_where} GROUP BY c.agent_id ORDER BY COUNT(*) DESC"
    );
    let agent_count_rows: Vec<(Option<i64>, i64)> =
        franken_query_map_collect_retry(&conn, &agent_sql, &params, |r| {
            Ok((r.get_typed::<Option<i64>>(0)?, r.get_typed::<i64>(1)?))
        })
        .map_err(|e| CliError::unknown(format!("query: {e}")))?;
    let agent_rows: Vec<(String, i64)> = agent_count_rows
        .into_iter()
        .map(|(agent_id, count)| {
            let agent = agent_id
                .and_then(|id| agent_lookup.get(&id).cloned())
                .unwrap_or_else(|| "unknown".to_string());
            (agent, count)
        })
        .collect();

    let workspace_lookup: HashMap<i64, String> =
        franken_query_map_collect_retry(&conn, "SELECT id, path FROM workspaces", &[], |r| {
            Ok((r.get_typed::<i64>(0)?, r.get_typed::<String>(1)?))
        })
        .map_err(|e| CliError::unknown(format!("query: {e}")))?
        .into_iter()
        .collect();

    let ws_sql = stats_workspace_count_sql(&source_where);
    let workspace_count_rows: Vec<(i64, i64)> =
        franken_query_map_collect_retry(&conn, &ws_sql, &params, |r| {
            Ok((r.get_typed::<i64>(0)?, r.get_typed::<i64>(1)?))
        })
        .map_err(|e| CliError::unknown(format!("query: {e}")))?;
    let ws_rows: Vec<(String, i64)> = workspace_count_rows
        .into_iter()
        .filter_map(|(workspace_id, count)| {
            workspace_lookup
                .get(&workspace_id)
                .cloned()
                .map(|path| (path, count))
        })
        .take(10)
        .collect();

    // Get date range with source filter.
    // Note: source_where already includes a leading " WHERE ...", so when it is present we must
    // append additional conditions with " AND ..." (not another WHERE).
    let date_sql = if source_where.is_empty() {
        "SELECT MIN(started_at), MAX(started_at) FROM conversations c WHERE started_at IS NOT NULL"
            .to_string()
    } else {
        format!(
            "SELECT MIN(started_at), MAX(started_at) FROM conversations c{source_where} AND started_at IS NOT NULL"
        )
    };
    let (oldest, newest): (Option<i64>, Option<i64>) =
        franken_query_row_map_retry(&conn, &date_sql, &params, |r| {
            Ok((r.get_typed(0)?, r.get_typed(1)?))
        })
        .unwrap_or((None, None));

    // Get per-source breakdown if requested (P3.7)
    let source_rows: Vec<(String, i64, i64)> = if by_source {
        let normalized_source_sql =
            normalized_source_identity_sql_expr("c.source_id", "c.origin_host");
        let source_sql = format!(
            "SELECT {normalized_source_sql} as source_id, COUNT(DISTINCT c.id) as convs, COUNT(m.id) as msgs
             FROM conversations c
             LEFT JOIN messages m ON m.conversation_id = c.id
             {source_where}
             GROUP BY {normalized_source_sql}
             ORDER BY convs DESC"
        );
        franken_query_map_collect_retry(&conn, &source_sql, &params, |r| {
            Ok((
                r.get_typed::<String>(0)?,
                r.get_typed::<i64>(1)?,
                r.get_typed::<i64>(2)?,
            ))
        })
        .map_err(|e| CliError::unknown(format!("query: {e}")))?
    } else {
        Vec::new()
    };

    let structured_format = output_format.or_else(robot_format_from_env).map(|fmt| {
        if matches!(fmt, RobotFormat::Sessions) {
            RobotFormat::Compact
        } else {
            fmt
        }
    });

    if let Some(fmt) = structured_format {
        let mut payload = serde_json::json!({
            "conversations": conversation_count,
            "messages": message_count,
            "by_agent": agent_rows.iter().map(|(a, c)| serde_json::json!({"agent": a, "count": c})).collect::<Vec<_>>(),
            "top_workspaces": ws_rows.iter().map(|(w, c)| serde_json::json!({"workspace": w, "count": c})).collect::<Vec<_>>(),
            "date_range": {
                "oldest": oldest.and_then(|ts| chrono::DateTime::from_timestamp_millis(ts).map(|d| d.to_rfc3339())),
                "newest": newest.and_then(|ts| chrono::DateTime::from_timestamp_millis(ts).map(|d| d.to_rfc3339())),
            },
            "db_path": db_path.display().to_string(),
        });

        // Add source filter info if specified (P3.7)
        if let Some(ref filter) = source_filter {
            payload["source_filter"] = serde_json::json!(filter.to_string());
        }

        // Add by_source breakdown if requested (P3.7)
        if by_source && !source_rows.is_empty() {
            payload["by_source"] = serde_json::json!(
                source_rows
                    .iter()
                    .map(|(s, convs, msgs)| {
                        serde_json::json!({
                            "source_id": s,
                            "conversations": convs,
                            "messages": msgs
                        })
                    })
                    .collect::<Vec<_>>()
            );
        }

        return output_structured_value(payload, fmt);
    }

    // Header with source filter indicator
    let title = if let Some(ref filter) = source_filter {
        format!("CASS Index Statistics (source: {})", filter)
    } else {
        "CASS Index Statistics".to_string()
    };
    println!("{title}");
    println!("{}", "=".repeat(title.len()));
    println!("Database: {}", db_path.display());
    println!();

    // Show by_source breakdown if requested (P3.7)
    if by_source && !source_rows.is_empty() {
        println!("By Source:");
        println!("  {:20} {:>10} {:>12}", "Source", "Convs", "Messages");
        println!("  {}", "-".repeat(44));
        for (src, convs, msgs) in &source_rows {
            println!("  {:20} {:>10} {:>12}", src, convs, msgs);
        }
        println!();
    }

    println!("Totals:");
    println!("  Conversations: {conversation_count}");
    println!("  Messages: {message_count}");
    println!();
    println!("By Agent:");
    for (agent, count) in &agent_rows {
        println!("  {agent}: {count}");
    }
    println!();
    if !ws_rows.is_empty() {
        println!("Top Workspaces:");
        for (ws, count) in &ws_rows {
            println!("  {ws}: {count}");
        }
        println!();
    }
    if let (Some(old), Some(new)) = (oldest, newest)
        && let (Some(old_dt), Some(new_dt)) = (
            chrono::DateTime::from_timestamp_millis(old),
            chrono::DateTime::from_timestamp_millis(new),
        )
    {
        println!(
            "Date Range: {} to {}",
            old_dt.format("%Y-%m-%d"),
            new_dt.format("%Y-%m-%d")
        );
    }

    Ok(())
}

fn run_diag(
    data_dir_override: &Option<PathBuf>,
    db_override: Option<PathBuf>,
    output_format: Option<RobotFormat>,
    quarantine: bool,
    verbose: bool,
) -> CliResult<()> {
    use frankensqlite::compat::RowExt;
    use frankensqlite::params;
    use std::fs;

    let version = env!("CARGO_PKG_VERSION");
    let data_dir = data_dir_override.clone().unwrap_or_else(default_data_dir);
    let db_path = db_override.unwrap_or_else(|| data_dir.join("agent_search.db"));
    // Use the actual versioned lexical index path without creating it during diagnostics.
    let index_path = crate::search::tantivy::expected_index_dir(&data_dir);

    // Check database existence and get stats
    let (db_exists, db_size, conversation_count, message_count) = if db_path.exists() {
        let size = fs::metadata(&db_path).map(|m| m.len()).unwrap_or(0);
        let (convs, msgs) = match open_franken_cli_read_db(
            db_path.clone(),
            "diagnostics",
            CLI_DIAG_DB_OPEN_TIMEOUT,
        ) {
            Ok(conn) => {
                let mut convs: i64 = franken_query_row_map_retry(
                    &conn,
                    "SELECT COUNT(*) FROM conversations",
                    params![],
                    |r| r.get_typed(0),
                )
                .unwrap_or(0);
                let mut msgs: i64 = franken_query_row_map_retry(
                    &conn,
                    "SELECT COUNT(*) FROM messages",
                    params![],
                    |r| r.get_typed(0),
                )
                .unwrap_or(0);
                if convs == 0 {
                    convs = fresh_franken_count_retry(
                        &db_path,
                        "diagnostics",
                        CLI_DIAG_DB_OPEN_TIMEOUT,
                        "SELECT COUNT(*) FROM conversations",
                        params![],
                    )
                    .unwrap_or(0);
                }
                if msgs == 0 {
                    msgs = fresh_franken_count_retry(
                        &db_path,
                        "diagnostics",
                        CLI_DIAG_DB_OPEN_TIMEOUT,
                        "SELECT COUNT(*) FROM messages",
                        params![],
                    )
                    .unwrap_or(0);
                }
                (convs, msgs)
            }
            Err(e) => {
                tracing::warn!("failed to open database for diagnostics: {e}");
                (-1, -1)
            }
        };
        (true, size, convs, msgs)
    } else {
        (false, 0, 0, 0)
    };

    // Check index existence
    let (index_exists, index_size) = if crate::search::tantivy::searchable_index_exists(&index_path)
    {
        let size = fs_dir_size(&index_path);
        (true, size)
    } else {
        (false, 0)
    };

    // Agent search paths - compute path once, then check existence
    let home = dirs::home_dir().unwrap_or_default();
    let config_dir = dirs::config_dir().unwrap_or_default();

    let agent_paths: Vec<(String, PathBuf, bool)> = diagnostics_connector_paths(&home, &config_dir)
        .into_iter()
        .map(|(name, path)| {
            let exists = path.exists();
            (name, path, exists)
        })
        .collect();
    let mut connector_paths_by_name: HashMap<String, Vec<PathBuf>> = HashMap::new();
    for (name, path, exists) in &agent_paths {
        if *exists {
            connector_paths_by_name
                .entry(public_connector_slug(name).to_string())
                .or_default()
                .push(path.clone());
        }
    }
    let connector_rows: Vec<(String, String, bool)> = capabilities_connector_names()
        .into_iter()
        .map(|name| {
            let path = connector_paths_by_name
                .get(&name)
                .and_then(|paths| paths.first())
                .map(|path| path.display().to_string())
                .unwrap_or_else(|| "(not detected)".to_string());
            let found = path != "(not detected)";
            (name, path, found)
        })
        .collect();

    let platform = std::env::consts::OS;
    let arch = std::env::consts::ARCH;
    let quarantine_report =
        quarantine.then(|| collect_diag_quarantine_report(&data_dir, &index_path));

    let structured_format = output_format.or_else(robot_format_from_env).map(|fmt| {
        if matches!(fmt, RobotFormat::Sessions) {
            RobotFormat::Compact
        } else {
            fmt
        }
    });

    if let Some(fmt) = structured_format {
        let mut payload = serde_json::json!({
            "version": version,
            "platform": { "os": platform, "arch": arch },
            "paths": {
                "data_dir": data_dir.display().to_string(),
                "db_path": db_path.display().to_string(),
                "index_path": index_path.display().to_string(),
            },
            "database": {
                "exists": db_exists,
                "size_bytes": db_size,
                "conversations": conversation_count,
                "messages": message_count,
            },
            "index": {
                "exists": index_exists,
                "size_bytes": index_size,
            },
            "connectors": connector_rows.iter().map(|(name, path, found)| {
                serde_json::json!({
                    "name": name,
                    "path": path,
                    "found": found,
                })
            }).collect::<Vec<_>>(),
        });
        if let Some(report) = quarantine_report.as_ref() {
            payload["quarantine"] = serde_json::json!(report);
        }
        return output_structured_value(payload, fmt);
    }

    println!("CASS Diagnostic Report");
    println!("======================");
    println!();
    println!("Version: {version}");
    println!("Platform: {platform} ({arch})");
    println!();
    println!("Paths:");
    println!("  Data directory: {}", data_dir.display());
    println!("  Database: {}", db_path.display());
    println!("  Tantivy index: {}", index_path.display());
    println!();
    println!("Database Status:");
    if db_exists {
        println!("  Status: OK");
        if verbose {
            println!("  Size: {}", format_bytes(db_size));
        }
        println!("  Conversations: {conversation_count}");
        println!("  Messages: {message_count}");
    } else {
        println!("  Status: NOT FOUND");
        println!("  Hint: Run 'cass index --full' to create the database");
    }
    println!();
    println!("Index Status:");
    if index_exists {
        println!("  Status: OK");
        if verbose {
            println!("  Size: {}", format_bytes(index_size));
        }
    } else {
        println!("  Status: NOT FOUND");
        println!("  Hint: Run 'cass index --full' to create the index");
    }
    println!();
    println!("Connector Search Paths:");
    for (name, path, found) in &connector_rows {
        let status = if *found { "✓" } else { "✗" };
        println!("  {} {}: {}", status, name, path);
    }
    if let Some(report) = quarantine_report.as_ref() {
        println!();
        println!("Quarantine:");
        println!(
            "  Failed seed bundles: {}",
            report.summary.failed_seed_bundle_count
        );
        println!(
            "  Retained publish backups: {}",
            report.summary.retained_publish_backup_count
        );
        println!(
            "  Quarantined lexical generations: {}",
            report.summary.lexical_quarantined_generation_count
        );
        println!(
            "  Quarantined lexical shards: {}",
            report.summary.lexical_quarantined_shard_count
        );
        println!(
            "  Total retained bytes: {}",
            report.summary.total_retained_bytes
        );
        println!(
            "  Retained publish backup cap: {}",
            report.summary.retained_publish_backup_retention_limit
        );
        println!(
            "  GC-eligible assets: {}",
            report.summary.gc_eligible_asset_count
        );
        println!("  GC-eligible bytes: {}", report.summary.gc_eligible_bytes);
        println!(
            "  Inspection-required assets: {}",
            report.summary.inspection_required_asset_count
        );
        println!(
            "  Inspection-required bytes: {}",
            report.summary.inspection_required_bytes
        );
        if !report.failed_seed_bundle_files.is_empty() {
            println!("  Failed seed bundle files:");
            for artifact in &report.failed_seed_bundle_files {
                println!(
                    "    - {} ({} bytes, age_s={}, last_read_ms={}, gc={}, reason={})",
                    artifact.path,
                    artifact.size_bytes,
                    format_optional_u64(artifact.age_seconds),
                    format_optional_i64(artifact.last_read_at_ms),
                    artifact.safe_to_gc,
                    artifact.gc_reason
                );
            }
        }
        if !report.retained_publish_backups.is_empty() {
            println!("  Retained publish backups:");
            for artifact in &report.retained_publish_backups {
                println!(
                    "    - {} ({} bytes, age_s={}, last_read_ms={}, gc={}, reason={})",
                    artifact.path,
                    artifact.size_bytes,
                    format_optional_u64(artifact.age_seconds),
                    format_optional_i64(artifact.last_read_at_ms),
                    artifact.safe_to_gc,
                    artifact.gc_reason
                );
            }
        }
        if !report.lexical_generations.is_empty() {
            println!("  Quarantined lexical generations:");
            for generation in &report.lexical_generations {
                println!(
                    "    - {} [{}] shards={}/{} bytes={} age_s={} last_read_ms={} reclaimable_bytes={} inspection_required={} gc={} reason={}",
                    generation.path,
                    generation.publish_state,
                    generation.quarantined_shards,
                    generation.total_shards,
                    generation.artifact_bytes,
                    format_optional_u64(generation.age_seconds),
                    format_optional_i64(generation.last_read_at_ms),
                    generation.reclaimable_bytes,
                    generation.inspection_required,
                    generation.safe_to_gc,
                    generation.gc_reason
                );
            }
        }
        if verbose && !report.warnings.is_empty() {
            println!("  Scan warnings:");
            for warning in &report.warnings {
                println!("    - {warning}");
            }
        }
    }

    Ok(())
}

