fn doctor_repair_mode_policy(mode: DoctorRepairMode) -> &'static DoctorRepairModePolicy {
    DOCTOR_REPAIR_MODE_POLICY_TABLE
        .iter()
        .find(|policy| policy.mode == mode)
        .expect("doctor repair mode policy table must cover every mode")
}

fn doctor_repair_mode_allows_asset_mutation(
    mode: DoctorRepairMode,
    asset_class: DoctorAssetClass,
) -> bool {
    doctor_repair_mode_allows_asset_operation_mutation(
        mode,
        asset_class,
        DoctorAssetOperation::PruneReclaim,
    )
}

fn doctor_repair_mode_allows_asset_operation_mutation(
    mode: DoctorRepairMode,
    asset_class: DoctorAssetClass,
    operation: DoctorAssetOperation,
) -> bool {
    let policy = doctor_repair_mode_policy(mode);
    if !policy.mutates
        || !policy.allowed_mutation_asset_classes.contains(&asset_class)
        || !doctor_asset_allows_operation(asset_class, operation)
    {
        return false;
    }
    if operation == DoctorAssetOperation::PruneReclaim {
        return doctor_asset_safe_to_gc(asset_class, true);
    }
    true
}

fn doctor_repair_mode_policy_report() -> Vec<DoctorRepairModePolicyReport> {
    DOCTOR_REPAIR_MODE_POLICY_TABLE
        .iter()
        .map(|policy| DoctorRepairModePolicyReport {
            mode: policy.mode,
            mutates: policy.mutates,
            robot_allowed: policy.robot_allowed,
            approval_requirement: policy.approval_requirement,
            allowed_mutation_asset_classes: policy.allowed_mutation_asset_classes.to_vec(),
            required_fields: policy.required_fields.to_vec(),
            stdout_contract: policy.stdout_contract,
            stderr_contract: policy.stderr_contract,
            aborts_on: policy.aborts_on.to_vec(),
            notes: policy.notes,
        })
        .collect()
}

fn doctor_operation_outcome_policy(
    kind: DoctorOperationOutcomeKind,
) -> &'static DoctorOperationOutcomePolicy {
    DOCTOR_OPERATION_OUTCOME_POLICY_TABLE
        .iter()
        .find(|policy| policy.kind == kind)
        .expect("doctor operation outcome policy table must cover every kind")
}

fn doctor_operation_outcome_contract_report() -> Vec<DoctorOperationOutcomePolicyReport> {
    DOCTOR_OPERATION_OUTCOME_POLICY_TABLE
        .iter()
        .map(|policy| DoctorOperationOutcomePolicyReport {
            kind: policy.kind,
            reason: policy.reason,
            action_taken: policy.action_taken,
            action_not_taken: policy.action_not_taken,
            safe_to_retry: policy.safe_to_retry,
            requires_override: policy.requires_override,
            data_loss_risk: policy.data_loss_risk,
            next_command: policy.next_command,
            artifact_manifest_path: policy.artifact_manifest_path,
            exit_code_kind: policy.exit_code_kind,
        })
        .collect()
}

fn doctor_operation_outcome_from_policy(
    kind: DoctorOperationOutcomeKind,
) -> DoctorOperationOutcomeReport {
    let policy = doctor_operation_outcome_policy(kind);
    DoctorOperationOutcomeReport {
        kind,
        reason: policy.reason.to_string(),
        action_taken: policy.action_taken.to_string(),
        action_not_taken: policy.action_not_taken.to_string(),
        safe_to_retry: policy.safe_to_retry,
        requires_override: policy.requires_override,
        data_loss_risk: policy.data_loss_risk,
        next_command: policy.next_command.map(str::to_string),
        artifact_manifest_path: policy.artifact_manifest_path.map(str::to_string),
        exit_code_kind: policy.exit_code_kind,
    }
}

fn doctor_operation_outcome_with_details(
    kind: DoctorOperationOutcomeKind,
    reason: String,
    action_taken: String,
    action_not_taken: String,
    data_loss_risk: DoctorDataLossRisk,
    next_command: Option<String>,
    artifact_manifest_path: Option<String>,
) -> DoctorOperationOutcomeReport {
    let mut report = doctor_operation_outcome_from_policy(kind);
    report.reason = reason;
    report.action_taken = action_taken;
    report.action_not_taken = action_not_taken;
    report.data_loss_risk = data_loss_risk;
    report.next_command = next_command;
    report.artifact_manifest_path = artifact_manifest_path;
    report
}

fn doctor_operation_outcome_kind_label(kind: DoctorOperationOutcomeKind) -> &'static str {
    match kind {
        DoctorOperationOutcomeKind::OkNoActionNeeded => "ok-no-action-needed",
        DoctorOperationOutcomeKind::OkReadOnlyDiagnosed => "ok-read-only-diagnosed",
        DoctorOperationOutcomeKind::Fixed => "fixed",
        DoctorOperationOutcomeKind::PartiallyFixed => "partially-fixed",
        DoctorOperationOutcomeKind::RepairBlocked => "repair-blocked",
        DoctorOperationOutcomeKind::RepairRefused => "repair-refused",
        DoctorOperationOutcomeKind::RepairIncomplete => "repair-incomplete",
        DoctorOperationOutcomeKind::VerificationFailed => "verification-failed",
        DoctorOperationOutcomeKind::CleanupDryRunOnly => "cleanup-dry-run-only",
        DoctorOperationOutcomeKind::CleanupRefused => "cleanup-refused",
        DoctorOperationOutcomeKind::AutoRunSkipped => "auto-run-skipped",
        DoctorOperationOutcomeKind::SupportBundleOnly => "support-bundle-only",
        DoctorOperationOutcomeKind::BaselineDiffOnly => "baseline-diff-only",
        DoctorOperationOutcomeKind::RequiresManualReview => "requires-manual-review",
    }
}

fn doctor_data_loss_risk_label(risk: DoctorDataLossRisk) -> &'static str {
    match risk {
        DoctorDataLossRisk::None => "none",
        DoctorDataLossRisk::Low => "low",
        DoctorDataLossRisk::Medium => "medium",
        DoctorDataLossRisk::High => "high",
        DoctorDataLossRisk::Unknown => "unknown",
    }
}

fn print_doctor_human_line(wrap: WrapConfig, line: impl AsRef<str>) {
    println!("{}", apply_wrap(line.as_ref(), wrap));
}

fn doctor_human_highest_incident_risk(
    incidents: &[DoctorRootCauseIncident],
    extract: impl Fn(&DoctorRootCauseIncident) -> DoctorDataLossRisk,
) -> DoctorDataLossRisk {
    incidents
        .iter()
        .map(extract)
        .max_by_key(|risk| doctor_data_loss_risk_rank(*risk))
        .unwrap_or(DoctorDataLossRisk::None)
}

fn doctor_human_semantic_fallback_summary(
    derived_semantic_assets: &DoctorDerivedSemanticAssetReport,
) -> Option<String> {
    if !matches!(
        derived_semantic_assets.asset_class,
        DoctorAssetClass::ModelCache
            | DoctorAssetClass::DerivedSemanticIndex
            | DoctorAssetClass::MemoCache
    ) {
        return None;
    }
    if derived_semantic_assets.fallback_mode != "lexical"
        || derived_semantic_assets.semantic_status == "ready"
    {
        return None;
    }

    Some(format!(
        "Semantic search: {}. This is derived-search state, not archive damage; cass will not download models during doctor. Next optional command: cass models install --json, then cass index --semantic --json.",
        derived_semantic_assets.recommended_action
    ))
}

struct DoctorHumanRiskSummaryInput<'a> {
    wrap: WrapConfig,
    doctor_status: &'a str,
    health_class: DoctorHealth,
    risk_level: &'a str,
    recommended_action: Option<&'a String>,
    incidents: &'a [DoctorRootCauseIncident],
    sole_copy_warnings: &'a [DoctorSoleCopyWarning],
    derived_semantic_assets: &'a DoctorDerivedSemanticAssetReport,
    repair_plan: Option<&'a DoctorRepairPlanPreviewReport>,
    cleanup_apply_result: Option<&'a DiagCleanupApplyResult>,
    operation_outcome: &'a DoctorOperationOutcomeReport,
    not_initialized: bool,
}

fn print_doctor_human_risk_summary(input: DoctorHumanRiskSummaryInput<'_>) {
    use colored::Colorize;

    let archive_risk = if input.not_initialized {
        DoctorDataLossRisk::Unknown
    } else {
        doctor_human_highest_incident_risk(input.incidents, |incident| incident.archive_risk_level)
    };
    let derived_risk = if input.not_initialized {
        DoctorDataLossRisk::Unknown
    } else {
        doctor_human_highest_incident_risk(input.incidents, |incident| incident.derived_risk_level)
    };
    let next_action = input
        .operation_outcome
        .next_command
        .as_deref()
        .or(input.recommended_action.map(String::as_str));

    println!();
    print_doctor_human_line(input.wrap, "Risk and next actions:".bold().to_string());
    print_doctor_human_line(
        input.wrap,
        format!(
            "  status: {}; health={}; risk={}; archive_risk={}; derived_index_risk={}",
            input.doctor_status,
            doctor_serde_label(input.health_class),
            input.risk_level,
            doctor_data_loss_risk_label(archive_risk),
            doctor_data_loss_risk_label(derived_risk)
        ),
    );
    print_doctor_human_line(
        input.wrap,
        "  Safety: doctor will not delete source session logs, raw mirrors, archive DBs, SQLite sidecars, backups, receipts, configs, bookmarks, or source evidence automatically.",
    );

    if input.sole_copy_warnings.is_empty() {
        print_doctor_human_line(
            input.wrap,
            "  Sole-copy warning: none identified by the current coverage ledger.",
        );
    } else {
        print_doctor_human_line(
            input.wrap,
            format!(
                "  Sole-copy warning: cass may be the only remaining archival copy for {} conversation(s); back up the cass data directory before any source-only rebuild, cleanup, restore, or repair.",
                input.sole_copy_warnings.len()
            ),
        );
    }

    if !input.not_initialized
        && let Some(summary) = doctor_human_semantic_fallback_summary(input.derived_semantic_assets)
    {
        print_doctor_human_line(input.wrap, format!("  {summary}"));
    }

    if let Some(action) = next_action {
        print_doctor_human_line(input.wrap, format!("  Next safe command: {action}"));
    }

    if let Some(plan) = input.repair_plan {
        print_doctor_human_line(input.wrap, "Repair plan:".bold().to_string());
        print_doctor_human_line(
            input.wrap,
            format!("  plan_fingerprint: {}", plan.plan_fingerprint),
        );
        print_doctor_human_line(
            input.wrap,
            format!("  exact apply command: {}", plan.exact_apply_command),
        );
        print_doctor_human_line(
            input.wrap,
            "  Receipt expectation: apply emits fingerprinted receipts, event-log evidence, and artifact checksums before doctor claims success.",
        );
    }

    if let Some(result) = input.cleanup_apply_result {
        print_doctor_human_line(input.wrap, "Cleanup receipt:".bold().to_string());
        print_doctor_human_line(
            input.wrap,
            format!(
                "  approval_fingerprint: {}; applied={}; reclaimed_bytes={}",
                result.approval_fingerprint, result.applied, result.reclaimed_bytes
            ),
        );
        print_doctor_human_line(
            input.wrap,
            format!(
                "  receipt plan_fingerprint: {}; receipt outcome={}",
                result.receipt.plan_fingerprint,
                doctor_serde_label(result.receipt.outcome_kind)
            ),
        );
    }
}

fn print_doctor_operation_outcome_human(outcome: &DoctorOperationOutcomeReport, wrap: WrapConfig) {
    use colored::Colorize;

    println!();
    print_doctor_human_line(wrap, "Operation outcome:".bold().to_string());
    print_doctor_human_line(
        wrap,
        format!(
            "  kind: {}",
            doctor_operation_outcome_kind_label(outcome.kind).bold()
        ),
    );
    print_doctor_human_line(wrap, format!("  reason: {}", outcome.reason));
    print_doctor_human_line(wrap, format!("  action_taken: {}", outcome.action_taken));
    print_doctor_human_line(
        wrap,
        format!("  action_not_taken: {}", outcome.action_not_taken),
    );
    print_doctor_human_line(
        wrap,
        format!(
            "  data_loss_risk: {}",
            doctor_data_loss_risk_label(outcome.data_loss_risk)
        ),
    );
    if let Some(next_command) = &outcome.next_command {
        print_doctor_human_line(wrap, format!("  next_command: {next_command}"));
    }
    if let Some(artifact_manifest_path) = &outcome.artifact_manifest_path {
        print_doctor_human_line(
            wrap,
            format!("  artifact_manifest_path: {artifact_manifest_path}"),
        );
    }
}

