#[derive(Debug)]
struct DoctorMutationLockGuard {
    file: std::fs::File,
}

impl Drop for DoctorMutationLockGuard {
    fn drop(&mut self) {
        let _ = fs2::FileExt::unlock(&self.file);
    }
}

#[derive(Debug, Clone)]
enum DoctorMutationLockObservation {
    Absent {
        path: PathBuf,
    },
    Available {
        path: PathBuf,
        metadata: BTreeMap<String, String>,
    },
    Active {
        path: PathBuf,
        metadata: BTreeMap<String, String>,
    },
    Acquired {
        path: PathBuf,
        metadata: BTreeMap<String, String>,
    },
    Unavailable {
        path: PathBuf,
        reason: String,
    },
}

impl DoctorMutationLockObservation {
    fn path(&self) -> &Path {
        match self {
            Self::Absent { path }
            | Self::Available { path, .. }
            | Self::Active { path, .. }
            | Self::Acquired { path, .. }
            | Self::Unavailable { path, .. } => path,
        }
    }

    fn blocks_mutation(&self) -> bool {
        matches!(self, Self::Active { .. } | Self::Unavailable { .. })
    }
}

const DOCTOR_STORAGE_MIN_FREE_BYTES: u64 = 1024 * 1024 * 1024;
const CASS_TEST_DOCTOR_STORAGE_AVAILABLE_BYTES: &str = "CASS_TEST_DOCTOR_STORAGE_AVAILABLE_BYTES";
const CASS_TEST_DOCTOR_CANDIDATE_PROMOTION_FAILPOINT: &str =
    "CASS_TEST_DOCTOR_CANDIDATE_PROMOTION_FAILPOINT";
const CASS_TEST_DOCTOR_RENAME_FAILURE: &str = "CASS_TEST_DOCTOR_RENAME_FAILURE";
