fn collect_diag_quarantine_report(data_dir: &Path, index_path: &Path) -> DiagQuarantineReport {
    collect_diag_quarantine_report_inner(data_dir, index_path, true)
}

fn collect_diag_quarantine_report_without_cleanup_plan(
    data_dir: &Path,
    index_path: &Path,
) -> DiagQuarantineReport {
    collect_diag_quarantine_report_inner(data_dir, index_path, false)
}

fn collect_diag_quarantine_report_inner(
    data_dir: &Path,
    index_path: &Path,
    include_cleanup_plan: bool,
) -> DiagQuarantineReport {
    use crate::indexer::lexical_generation::{
        LexicalCleanupDryRunPlan, LexicalGenerationPublishState,
    };

    let mut report = DiagQuarantineReport::default();
    report.summary.lexical_generation_build_state_counts =
        lexical_generation_build_state_zero_counts();
    report.summary.lexical_generation_publish_state_counts =
        lexical_generation_publish_state_zero_counts();
    let now = std::time::SystemTime::now();

    let backups_dir = data_dir.join("backups");
    match std::fs::read_dir(&backups_dir) {
        Ok(entries) => {
            for entry in entries.flatten() {
                let path = entry.path();
                let Some(name) = path.file_name().and_then(|name| name.to_str()) else {
                    continue;
                };
                if !name.contains(".failed-baseline-seed.bak") {
                    continue;
                }
                let observation = observe_diag_path(&path, now, &mut report.warnings);
                report
                    .failed_seed_bundle_files
                    .push(DiagQuarantineArtifact {
                        asset_safety: doctor_asset_safety(DoctorAssetClass::FailedSeedBundle),
                        path: path.display().to_string(),
                        size_bytes: observation.size_bytes,
                        age_seconds: observation.age_seconds,
                        last_read_at_ms: observation.last_read_at_ms,
                        safe_to_gc: false,
                        gc_reason: "failed baseline seed quarantine requires operator inspection"
                            .to_string(),
                    });
                report
                    .quarantined_artifacts
                    .push(DiagQuarantineInspectionArtifact {
                        asset_safety: doctor_asset_safety(DoctorAssetClass::FailedSeedBundle),
                        artifact_kind: "failed_seed_bundle_file".to_string(),
                        path: path.display().to_string(),
                        generation_id: None,
                        shard_id: None,
                        publish_state: None,
                        shard_state: None,
                        size_bytes: observation.size_bytes,
                        age_seconds: observation.age_seconds,
                        last_read_at_ms: observation.last_read_at_ms,
                        safe_to_gc: false,
                        gc_reason: "failed baseline seed quarantine requires operator inspection"
                            .to_string(),
                    });
            }
        }
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => {}
        Err(err) => report.warnings.push(format!(
            "failed to read backup quarantine directory {}: {err}",
            backups_dir.display()
        )),
    }

    let retained_publish_dir = index_path
        .parent()
        .unwrap_or(index_path)
        .join(".lexical-publish-backups");
    let retention_limit = diag_retained_publish_backup_limit();
    report.summary.retained_publish_backup_retention_limit = retention_limit;
    match std::fs::read_dir(&retained_publish_dir) {
        Ok(entries) => {
            let mut retained_entries: Vec<(PathBuf, DiagPathObservation)> = Vec::new();
            for entry in entries.flatten() {
                let path = entry.path();
                retained_entries.push((
                    path.clone(),
                    observe_diag_path(&path, now, &mut report.warnings),
                ));
            }
            retained_entries.sort_by(|left, right| {
                right
                    .1
                    .modified_at
                    .unwrap_or(std::time::SystemTime::UNIX_EPOCH)
                    .cmp(
                        &left
                            .1
                            .modified_at
                            .unwrap_or(std::time::SystemTime::UNIX_EPOCH),
                    )
                    .then_with(|| left.0.cmp(&right.0))
            });
            for (index, (path, observation)) in retained_entries.into_iter().enumerate() {
                let safe_to_gc = doctor_asset_safe_to_gc(
                    DoctorAssetClass::RetainedPublishBackup,
                    index >= retention_limit,
                );
                let gc_reason = if safe_to_gc {
                    format!(
                        "retained lexical publish backup falls outside retention cap ({retention_limit})"
                    )
                } else {
                    format!(
                        "retained lexical publish backup is still protected by retention cap ({retention_limit})"
                    )
                };
                report
                    .retained_publish_backups
                    .push(DiagQuarantineArtifact {
                        asset_safety: doctor_asset_safety(DoctorAssetClass::RetainedPublishBackup),
                        path: path.display().to_string(),
                        size_bytes: observation.size_bytes,
                        age_seconds: observation.age_seconds,
                        last_read_at_ms: observation.last_read_at_ms,
                        safe_to_gc,
                        gc_reason,
                    });
            }
        }
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => {}
        Err(err) => report.warnings.push(format!(
            "failed to read retained publish backups at {}: {err}",
            retained_publish_dir.display()
        )),
    }

    let lexical_manifest_root = diag_lexical_manifest_scan_root(index_path);
    let lexical_manifest_entries = collect_diag_lexical_manifest_entries(
        &lexical_manifest_root,
        now,
        &mut report.warnings,
        &mut report.summary,
    );

    let lexical_cleanup_plan = include_cleanup_plan.then(|| {
        LexicalCleanupDryRunPlan::from_manifests(
            lexical_manifest_entries.iter().map(|entry| &entry.manifest),
        )
    });
    let lexical_cleanup_apply_gate = lexical_cleanup_plan
        .as_ref()
        .map(|plan| plan.apply_gate(false));
    let inspection_required_ids: HashSet<String> = lexical_cleanup_plan
        .as_ref()
        .map(|plan| {
            plan.inspection_required_generation_ids()
                .into_iter()
                .collect()
        })
        .unwrap_or_default();
    let lexical_inventory_by_generation: HashMap<_, _> = lexical_cleanup_plan
        .as_ref()
        .map(|plan| {
            plan.inventories
                .iter()
                .map(|inventory| (inventory.generation_id.clone(), inventory.clone()))
                .collect()
        })
        .unwrap_or_default();
    let cleanup_reclaim_candidate_count = lexical_cleanup_plan
        .as_ref()
        .map(|plan| plan.reclaim_candidates.len())
        .unwrap_or(0);
    let cleanup_reclaimable_bytes = lexical_cleanup_plan
        .as_ref()
        .map(|plan| plan.total_reclaimable_bytes)
        .unwrap_or(0);
    let cleanup_retained_bytes = lexical_cleanup_plan
        .as_ref()
        .map(|plan| plan.total_retained_bytes)
        .unwrap_or(0);

    for entry in lexical_manifest_entries {
        if !matches!(
            entry.manifest.publish_state,
            LexicalGenerationPublishState::Quarantined
        ) && entry.quarantined_shards == 0
        {
            continue;
        }
        let observation = match entry.observation {
            Some(observation) => observation,
            None => observe_diag_path(&entry.path, now, &mut report.warnings),
        };
        let inventory = lexical_inventory_by_generation.get(&entry.manifest.generation_id);
        let reclaimable_bytes = inventory
            .map(|inventory| inventory.reclaimable_bytes)
            .unwrap_or(0);
        let inspection_required = inspection_required_ids.contains(&entry.manifest.generation_id);
        let candidate_safe_to_gc = reclaimable_bytes > 0
            && inventory
                .map(|inventory| inventory.reclaimable_bytes >= inventory.artifact_bytes)
                .unwrap_or(false)
            && !inspection_required;
        let safe_to_gc = doctor_asset_safe_to_gc(
            DoctorAssetClass::QuarantinedLexicalGeneration,
            candidate_safe_to_gc,
        );
        let gc_reason = if !include_cleanup_plan {
            "cleanup planning not run during bounded doctor check".to_string()
        } else if safe_to_gc {
            format!(
                "cleanup dry-run marks the full retained generation reclaimable ({} bytes)",
                reclaimable_bytes
            )
        } else if candidate_safe_to_gc {
            "asset taxonomy retains quarantined lexical generations for operator inspection"
                .to_string()
        } else if inspection_required {
            "cleanup dry-run requires inspection before garbage collection".to_string()
        } else if reclaimable_bytes == 0 {
            "cleanup dry-run exposes no reclaimable bytes for this quarantined generation"
                .to_string()
        } else {
            format!(
                "cleanup dry-run only marks {} of {} bytes reclaimable",
                reclaimable_bytes, observation.size_bytes
            )
        };
        if matches!(
            entry.manifest.publish_state,
            LexicalGenerationPublishState::Quarantined
        ) {
            report
                .quarantined_artifacts
                .push(DiagQuarantineInspectionArtifact {
                    asset_safety: doctor_asset_safety(
                        DoctorAssetClass::QuarantinedLexicalGeneration,
                    ),
                    artifact_kind: "lexical_generation".to_string(),
                    path: entry.path.display().to_string(),
                    generation_id: Some(entry.manifest.generation_id.clone()),
                    shard_id: None,
                    publish_state: Some(lexical_publish_state_label(entry.manifest.publish_state)),
                    shard_state: None,
                    size_bytes: observation.size_bytes,
                    age_seconds: observation.age_seconds,
                    last_read_at_ms: observation.last_read_at_ms,
                    safe_to_gc,
                    gc_reason: gc_reason.clone(),
                });
        }
        for shard in entry.manifest.shards.iter().filter(|shard| {
            matches!(
                shard.state,
                crate::indexer::lexical_generation::LexicalShardLifecycleState::Quarantined
            )
        }) {
            report
                .quarantined_artifacts
                .push(DiagQuarantineInspectionArtifact {
                    asset_safety: doctor_asset_safety(DoctorAssetClass::QuarantinedLexicalShard),
                    artifact_kind: "lexical_shard".to_string(),
                    path: entry.path.display().to_string(),
                    generation_id: Some(entry.manifest.generation_id.clone()),
                    shard_id: Some(shard.shard_id.clone()),
                    publish_state: Some(lexical_publish_state_label(entry.manifest.publish_state)),
                    shard_state: Some(lexical_shard_state_label(shard.state)),
                    size_bytes: shard.artifact_bytes,
                    age_seconds: observation.age_seconds,
                    last_read_at_ms: observation.last_read_at_ms,
                    safe_to_gc: false,
                    gc_reason: shard.quarantine_reason.clone().unwrap_or_else(|| {
                        "quarantined lexical shard requires operator inspection".to_string()
                    }),
                });
        }
        report.lexical_generations.push(DiagQuarantinedGeneration {
            asset_safety: doctor_asset_safety(DoctorAssetClass::QuarantinedLexicalGeneration),
            path: entry.path.display().to_string(),
            generation_id: entry.manifest.generation_id,
            publish_state: lexical_publish_state_label(entry.manifest.publish_state),
            quarantined_shards: entry.quarantined_shards,
            total_shards: entry.manifest.shards.len(),
            artifact_bytes: observation.size_bytes,
            updated_at_ms: entry.manifest.updated_at_ms,
            age_seconds: observation.age_seconds,
            last_read_at_ms: observation.last_read_at_ms,
            reclaimable_bytes,
            inspection_required,
            safe_to_gc,
            gc_reason,
        });
    }

    report
        .failed_seed_bundle_files
        .sort_by(|left, right| left.path.cmp(&right.path));
    report
        .lexical_generations
        .sort_by(|left, right| left.path.cmp(&right.path));
    report.quarantined_artifacts.sort_by(|left, right| {
        left.path
            .cmp(&right.path)
            .then_with(|| left.artifact_kind.cmp(&right.artifact_kind))
            .then_with(|| left.generation_id.cmp(&right.generation_id))
            .then_with(|| left.shard_id.cmp(&right.shard_id))
    });

    report.summary.failed_seed_bundle_count = report.failed_seed_bundle_files.len();
    report.summary.retained_publish_backup_count = report.retained_publish_backups.len();
    report.summary.lexical_quarantined_generation_count = report.lexical_generations.len();
    report.summary.lexical_quarantined_shard_count = report
        .lexical_generations
        .iter()
        .map(|generation| generation.quarantined_shards)
        .sum();
    report.summary.total_retained_bytes = report
        .failed_seed_bundle_files
        .iter()
        .map(|artifact| artifact.size_bytes)
        .sum::<u64>()
        + report
            .retained_publish_backups
            .iter()
            .map(|artifact| artifact.size_bytes)
            .sum::<u64>()
        + report
            .lexical_generations
            .iter()
            .map(|generation| generation.artifact_bytes)
            .sum::<u64>();
    report.summary.gc_eligible_asset_count = report
        .failed_seed_bundle_files
        .iter()
        .filter(|artifact| artifact.safe_to_gc)
        .count()
        + report
            .retained_publish_backups
            .iter()
            .filter(|artifact| artifact.safe_to_gc)
            .count()
        + report
            .lexical_generations
            .iter()
            .filter(|generation| generation.safe_to_gc)
            .count()
        + cleanup_reclaim_candidate_count;
    report.summary.gc_eligible_bytes = report
        .failed_seed_bundle_files
        .iter()
        .filter(|artifact| artifact.safe_to_gc)
        .map(|artifact| artifact.size_bytes)
        .sum::<u64>()
        + report
            .retained_publish_backups
            .iter()
            .filter(|artifact| artifact.safe_to_gc)
            .map(|artifact| artifact.size_bytes)
            .sum::<u64>()
        + report
            .lexical_generations
            .iter()
            .filter(|generation| generation.safe_to_gc)
            .map(|generation| generation.artifact_bytes)
            .sum::<u64>()
        + cleanup_reclaimable_bytes;
    report.summary.inspection_required_asset_count = report.failed_seed_bundle_files.len()
        + report
            .lexical_generations
            .iter()
            .filter(|generation| generation.inspection_required)
            .count();
    report.summary.inspection_required_bytes = report
        .failed_seed_bundle_files
        .iter()
        .map(|artifact| artifact.size_bytes)
        .sum::<u64>()
        + report
            .lexical_generations
            .iter()
            .filter(|generation| generation.inspection_required)
            .map(|generation| generation.artifact_bytes)
            .sum::<u64>();
    if let (Some(lexical_cleanup_plan), Some(lexical_cleanup_apply_gate)) =
        (lexical_cleanup_plan, lexical_cleanup_apply_gate)
    {
        report.summary.cleanup_dry_run_generation_count = lexical_cleanup_plan.generation_count;
        report.summary.cleanup_dry_run_reclaim_candidate_count = cleanup_reclaim_candidate_count;
        report.summary.cleanup_dry_run_reclaimable_bytes = cleanup_reclaimable_bytes;
        report.summary.cleanup_dry_run_retained_bytes = cleanup_retained_bytes;
        report.summary.cleanup_dry_run_protected_generation_count =
            lexical_cleanup_plan.protected_generation_ids.len();
        report.summary.cleanup_dry_run_active_generation_count =
            lexical_cleanup_plan.active_generation_ids.len();
        report.summary.cleanup_dry_run_inspection_required_count =
            lexical_cleanup_plan.inspection_required_count;
        report.summary.cleanup_dry_run_approval_fingerprint =
            lexical_cleanup_plan.approval_fingerprint.clone();
        report.summary.cleanup_apply_allowed = lexical_cleanup_apply_gate.apply_allowed;
        report.lexical_cleanup_apply_gate = Some(lexical_cleanup_apply_gate);
        report.lexical_cleanup_dry_run = Some(lexical_cleanup_plan);
    }

    report
}

fn collect_diag_lexical_manifest_entries(
    manifest_root: &Path,
    now: std::time::SystemTime,
    warnings: &mut Vec<String>,
    summary: &mut DiagQuarantineSummary,
) -> Vec<DiagLexicalManifestEntry> {
    use crate::indexer::lexical_generation::{
        LEXICAL_GENERATION_MANIFEST_FILE, LexicalGenerationPublishState,
        LexicalShardLifecycleState, load_manifest,
    };

    let mut lexical_manifest_entries = Vec::new();
    match manifest_root.try_exists() {
        Ok(true) => {}
        Ok(false) => return lexical_manifest_entries,
        Err(err) => {
            warnings.push(format!(
                "failed to inspect lexical generation manifest root {}: {err}",
                manifest_root.display()
            ));
            return lexical_manifest_entries;
        }
    }

    for entry in walkdir::WalkDir::new(manifest_root).follow_links(false) {
        let entry = match entry {
            Ok(entry) => entry,
            Err(err) => {
                warnings.push(format!(
                    "failed to walk lexical generation manifests under {}: {err}",
                    manifest_root.display()
                ));
                continue;
            }
        };
        if !entry.file_type().is_file() {
            continue;
        }
        if entry.file_name().to_string_lossy() != LEXICAL_GENERATION_MANIFEST_FILE {
            continue;
        }
        let Some(generation_dir) = entry.path().parent() else {
            continue;
        };
        match load_manifest(generation_dir) {
            Ok(Some(manifest)) => {
                let quarantined_shards = manifest
                    .shards
                    .iter()
                    .filter(|shard| matches!(shard.state, LexicalShardLifecycleState::Quarantined))
                    .count();
                summary.lexical_generation_count =
                    summary.lexical_generation_count.saturating_add(1);
                *summary
                    .lexical_generation_build_state_counts
                    .entry(lexical_generation_build_state_label(manifest.build_state).to_string())
                    .or_insert(0) += 1;
                *summary
                    .lexical_generation_publish_state_counts
                    .entry(lexical_publish_state_label(manifest.publish_state).to_string())
                    .or_insert(0) += 1;
                let needs_observation = matches!(
                    manifest.publish_state,
                    LexicalGenerationPublishState::Quarantined
                ) || quarantined_shards > 0;
                let observation =
                    needs_observation.then(|| observe_diag_path(generation_dir, now, warnings));
                lexical_manifest_entries.push(DiagLexicalManifestEntry {
                    path: generation_dir.to_path_buf(),
                    observation,
                    manifest,
                    quarantined_shards,
                });
            }
            Ok(None) => {}
            Err(err) => warnings.push(format!(
                "failed to load lexical quarantine manifest at {}: {err}",
                entry.path().display()
            )),
        }
    }

    lexical_manifest_entries
}

fn diag_lexical_manifest_scan_root(index_path: &Path) -> PathBuf {
    index_path.parent().unwrap_or(index_path).to_path_buf()
}

fn planned_cleanup_apply_actions(
    before: &DiagQuarantineReport,
    plan: &crate::indexer::lexical_generation::LexicalCleanupDryRunPlan,
    apply_gate: &crate::indexer::lexical_generation::LexicalCleanupApplyGate,
    lexical_manifest_entries: &[DiagLexicalManifestEntry],
) -> Vec<DiagCleanupApplyAction> {
    use crate::indexer::lexical_generation::LexicalCleanupDisposition;

    let mut actions = Vec::new();
    for artifact in before
        .retained_publish_backups
        .iter()
        .filter(|artifact| artifact.safe_to_gc)
    {
        let asset_class = DoctorAssetClass::RetainedPublishBackup;
        actions.push(DiagCleanupApplyAction {
            asset_safety: doctor_asset_safety(asset_class),
            artifact_kind: "retained_publish_backup".to_string(),
            path: artifact.path.clone(),
            generation_id: None,
            shard_id: None,
            disposition: None,
            reason: artifact.gc_reason.clone(),
            planned_reclaimable_bytes: artifact.size_bytes,
            reclaimed_bytes: 0,
            applied: false,
            skipped: false,
            skip_reason: None,
            mutation_receipt: None,
        });
    }

    if !apply_gate.apply_allowed {
        return actions;
    }

    let inventories_by_generation: HashMap<_, _> = plan
        .inventories
        .iter()
        .map(|inventory| (inventory.generation_id.clone(), inventory.clone()))
        .collect();
    for entry in lexical_manifest_entries {
        let Some(inventory) = inventories_by_generation.get(&entry.manifest.generation_id) else {
            continue;
        };
        if inventory.reclaimable_bytes == 0 {
            continue;
        }
        let asset_class = doctor_asset_class_for_cleanup_disposition(inventory.disposition);
        let generation_fully_reclaimable = inventory.retained_bytes == 0
            && inventory.reclaimable_bytes >= inventory.artifact_bytes;
        let generation_disposition_reclaimable = matches!(
            inventory.disposition,
            LexicalCleanupDisposition::SupersededReclaimable
                | LexicalCleanupDisposition::FailedReclaimable
        );
        let skip_reason =
            (!generation_fully_reclaimable || !generation_disposition_reclaimable).then(|| {
                format!(
                    "cleanup apply only prunes whole lexical generations in this slice; retained_bytes={} disposition={}",
                    inventory.retained_bytes,
                    lexical_cleanup_disposition_label(inventory.disposition)
                )
            });
        actions.push(DiagCleanupApplyAction {
            asset_safety: doctor_asset_safety(asset_class),
            artifact_kind: "lexical_generation".to_string(),
            path: entry.path.display().to_string(),
            generation_id: Some(entry.manifest.generation_id.clone()),
            shard_id: None,
            disposition: Some(inventory.disposition),
            reason: inventory.reason.clone(),
            planned_reclaimable_bytes: inventory.reclaimable_bytes,
            reclaimed_bytes: 0,
            applied: false,
            skipped: skip_reason.is_some(),
            skip_reason,
            mutation_receipt: None,
        });
    }
    doctor_sorted_cleanup_actions(&actions)
}

fn cleanup_plan_has_mutating_actions(actions: &[DiagCleanupApplyAction]) -> bool {
    actions
        .iter()
        .any(|action| !action.skipped && action.planned_reclaimable_bytes > 0)
}

fn apply_diag_quarantine_cleanup(
    data_dir: &Path,
    db_path: &Path,
    index_path: &Path,
    rebuild_active: bool,
    provided_approval_fingerprint: Option<&str>,
) -> DiagCleanupApplyResult {
    use crate::indexer::lexical_generation::LexicalCleanupDisposition;

    let before = collect_diag_quarantine_report(data_dir, index_path);
    let plan = before
        .lexical_cleanup_dry_run
        .clone()
        .expect("quarantine collection always attaches a lexical cleanup dry-run plan");
    let apply_gate = plan.apply_gate_with_fingerprint(true, provided_approval_fingerprint);
    let safe_retained_publish_backup_count = before
        .retained_publish_backups
        .iter()
        .filter(|artifact| artifact.safe_to_gc)
        .count();
    let mut scan_warnings = Vec::new();
    let mut scan_summary = DiagQuarantineSummary {
        lexical_generation_build_state_counts: lexical_generation_build_state_zero_counts(),
        lexical_generation_publish_state_counts: lexical_generation_publish_state_zero_counts(),
        ..DiagQuarantineSummary::default()
    };
    let lexical_manifest_root = diag_lexical_manifest_scan_root(index_path);
    let lexical_manifest_entries = collect_diag_lexical_manifest_entries(
        &lexical_manifest_root,
        std::time::SystemTime::now(),
        &mut scan_warnings,
        &mut scan_summary,
    );
    let planned_actions =
        planned_cleanup_apply_actions(&before, &plan, &apply_gate, &lexical_manifest_entries);
    let retained_only_cleanup_planned =
        safe_retained_publish_backup_count > 0 && !plan.has_reclaimable_artifacts();
    let no_cleanup_targets =
        safe_retained_publish_backup_count == 0 && !plan.has_reclaimable_artifacts();
    let mut blocked_reasons = if no_cleanup_targets {
        Vec::new()
    } else {
        apply_gate.blocked_reasons.clone()
    };
    let mut blocker_codes = if no_cleanup_targets {
        Vec::new()
    } else {
        apply_gate.blocker_codes.clone()
    };
    if retained_only_cleanup_planned {
        blocker_codes.retain(|code| {
            *code != crate::indexer::lexical_generation::LexicalCleanupApplyBlocker::NoReclaimableCandidates
        });
        blocked_reasons.retain(|reason| reason != "no reclaimable cleanup candidates");
    }
    let cleanup_fingerprint_approved = apply_gate.approval_fingerprint_matches;

    let mut result = DiagCleanupApplyResult {
        mode: DoctorRepairMode::CleanupApply,
        approval_requirement: DoctorApprovalRequirement::ApprovalFingerprint,
        requested: true,
        operation_started_at_ms: Some(doctor_now_ms()),
        approval_fingerprint: plan.approval_fingerprint.clone(),
        apply_allowed: !rebuild_active
            && cleanup_fingerprint_approved
            && (safe_retained_publish_backup_count > 0 || apply_gate.apply_allowed),
        blocked_reasons,
        blocker_codes,
        before_generation_count: plan.generation_count,
        before_reclaim_candidate_count: plan.reclaim_candidates.len(),
        before_reclaimable_bytes: plan.total_reclaimable_bytes,
        before_retained_bytes: plan.total_retained_bytes,
        before_inventory: cleanup_apply_inventory_from_report(&before),
        planned_actions,
        forensic_bundle: doctor_forensic_bundle_uncaptured("not_required_no_mutation_planned"),
        warnings: scan_warnings,
        ..DiagCleanupApplyResult::default()
    };

    if rebuild_active {
        result
            .blocked_reasons
            .push("active index rebuild lock prevents cleanup apply".to_string());
        result
            .warnings
            .push("cleanup apply skipped because an index rebuild lock is active".to_string());
    }

    if !rebuild_active
        && result.apply_allowed
        && cleanup_plan_has_mutating_actions(&result.planned_actions)
    {
        let pre_mutation_plan = build_cleanup_doctor_plan(&result, data_dir, db_path, index_path);
        result.forensic_bundle = capture_doctor_forensic_bundle(DoctorForensicBundleCaptureInput {
            operation_id: &result.approval_fingerprint,
            data_dir,
            db_path,
            index_path,
            plan: Some(&pre_mutation_plan),
            quarantine_report: Some(&before),
            extra_file_artifacts: &[],
        });
        if result.forensic_bundle.status != "captured" {
            let reason = result
                .forensic_bundle
                .blocked_reason
                .clone()
                .unwrap_or_else(|| "forensic bundle capture did not complete".to_string());
            let blocked_reason =
                format!("forensic bundle capture failed before cleanup mutation: {reason}");
            result.blocked_reasons.push(blocked_reason.clone());
            result.warnings.push(blocked_reason.clone());
            result.apply_allowed = false;
            for mut action in result.planned_actions.clone() {
                if !action.skipped {
                    action.skipped = true;
                    action.skip_reason = Some(blocked_reason.clone());
                    result.skipped_asset_count = result.skipped_asset_count.saturating_add(1);
                }
                result.actions.push(action);
            }
            let after = collect_diag_quarantine_report(data_dir, index_path);
            fill_cleanup_after_summary(&mut result, &after);
            finalize_cleanup_apply_contract(&mut result, data_dir, db_path, index_path);
            return result;
        }
    }

    if rebuild_active {
        let after = collect_diag_quarantine_report(data_dir, index_path);
        fill_cleanup_after_summary(&mut result, &after);
        finalize_cleanup_apply_contract(&mut result, data_dir, db_path, index_path);
        return result;
    }

    if !result.apply_allowed {
        if cleanup_plan_has_mutating_actions(&result.planned_actions) {
            let skip_reason = if result.blocked_reasons.is_empty() {
                "cleanup apply refused by safety gate".to_string()
            } else {
                result.blocked_reasons.join("; ")
            };
            for mut action in result.planned_actions.clone() {
                if !action.skipped {
                    action.skipped = true;
                    action.skip_reason = Some(skip_reason.clone());
                    result.skipped_asset_count = result.skipped_asset_count.saturating_add(1);
                }
                result.actions.push(action);
            }
        }
        let after = collect_diag_quarantine_report(data_dir, index_path);
        fill_cleanup_after_summary(&mut result, &after);
        finalize_cleanup_apply_contract(&mut result, data_dir, db_path, index_path);
        return result;
    }

    for artifact in before
        .retained_publish_backups
        .iter()
        .filter(|artifact| artifact.safe_to_gc)
    {
        let path = PathBuf::from(&artifact.path);
        let asset_class = DoctorAssetClass::RetainedPublishBackup;
        let mut action = DiagCleanupApplyAction {
            asset_safety: doctor_asset_safety(asset_class),
            artifact_kind: "retained_publish_backup".to_string(),
            path: artifact.path.clone(),
            generation_id: None,
            shard_id: None,
            disposition: None,
            reason: artifact.gc_reason.clone(),
            planned_reclaimable_bytes: artifact.size_bytes,
            reclaimed_bytes: 0,
            applied: false,
            skipped: false,
            skip_reason: None,
            mutation_receipt: None,
        };

        let action_id = doctor_cleanup_action_id(&action);
        let mut mutation_receipt = execute_doctor_fs_mutation(DoctorFsMutationRequest {
            operation_id: &result.approval_fingerprint,
            action_id: &action_id,
            mutation_kind: DoctorFsMutationKind::PruneCleanupTarget,
            mode: DoctorRepairMode::CleanupApply,
            asset_class,
            source_path: None,
            target_path: &path,
            data_dir,
            db_path,
            index_path,
            staging_root: None,
            expected_source_blake3: None,
            planned_bytes: action.planned_reclaimable_bytes,
            required_min_age_seconds: None,
        });
        mutation_receipt.forensic_bundle = result.forensic_bundle.clone();
        match mutation_receipt.status {
            DoctorActionStatus::Applied => {
                let reclaimed_bytes = mutation_receipt.affected_bytes;
                action.reclaimed_bytes = reclaimed_bytes;
                action.applied = true;
                result.pruned_asset_count = result.pruned_asset_count.saturating_add(1);
                result.reclaimed_bytes = result.reclaimed_bytes.saturating_add(reclaimed_bytes);
                tracing::info!(
                    target: "cass::doctor::cleanup",
                    artifact_kind = "retained_publish_backup",
                    path = %path.display(),
                    reclaimed_bytes,
                    "pruned retained lexical publish backup outside retention cap"
                );
            }
            _ => {
                let err = mutation_receipt.blocked_reasons.join("; ");
                action.skipped = true;
                action.skip_reason = Some(err.clone());
                result.skipped_asset_count = result.skipped_asset_count.saturating_add(1);
                result.warnings.push(err);
            }
        }
        action.mutation_receipt = Some(mutation_receipt);

        result.actions.push(action);
    }

    let inventories_by_generation: HashMap<_, _> = plan
        .inventories
        .iter()
        .map(|inventory| (inventory.generation_id.clone(), inventory.clone()))
        .collect();

    if apply_gate.apply_allowed {
        for entry in lexical_manifest_entries {
            let Some(inventory) = inventories_by_generation.get(&entry.manifest.generation_id)
            else {
                continue;
            };
            if inventory.reclaimable_bytes == 0 {
                continue;
            }

            let asset_class = doctor_asset_class_for_cleanup_disposition(inventory.disposition);
            let mut action = DiagCleanupApplyAction {
                asset_safety: doctor_asset_safety(asset_class),
                artifact_kind: "lexical_generation".to_string(),
                path: entry.path.display().to_string(),
                generation_id: Some(entry.manifest.generation_id.clone()),
                shard_id: None,
                disposition: Some(inventory.disposition),
                reason: inventory.reason.clone(),
                planned_reclaimable_bytes: inventory.reclaimable_bytes,
                reclaimed_bytes: 0,
                applied: false,
                skipped: false,
                skip_reason: None,
                mutation_receipt: None,
            };

            let generation_fully_reclaimable = inventory.retained_bytes == 0
                && inventory.reclaimable_bytes >= inventory.artifact_bytes;
            let generation_disposition_reclaimable = matches!(
                inventory.disposition,
                LexicalCleanupDisposition::SupersededReclaimable
                    | LexicalCleanupDisposition::FailedReclaimable
            );

            if !generation_fully_reclaimable || !generation_disposition_reclaimable {
                let reason = format!(
                    "cleanup apply only prunes whole lexical generations in this slice; retained_bytes={} disposition={}",
                    inventory.retained_bytes,
                    lexical_cleanup_disposition_label(inventory.disposition)
                );
                action.skipped = true;
                action.skip_reason = Some(reason.clone());
                result.skipped_asset_count = result.skipped_asset_count.saturating_add(1);
                result.warnings.push(reason);
                result.actions.push(action);
                continue;
            }

            let action_id = doctor_cleanup_action_id(&action);
            let mut mutation_receipt = execute_doctor_fs_mutation(DoctorFsMutationRequest {
                operation_id: &result.approval_fingerprint,
                action_id: &action_id,
                mutation_kind: DoctorFsMutationKind::PruneCleanupTarget,
                mode: DoctorRepairMode::CleanupApply,
                asset_class,
                source_path: None,
                target_path: &entry.path,
                data_dir,
                db_path,
                index_path,
                staging_root: None,
                expected_source_blake3: None,
                planned_bytes: action.planned_reclaimable_bytes,
                required_min_age_seconds: None,
            });
            mutation_receipt.forensic_bundle = result.forensic_bundle.clone();
            match mutation_receipt.status {
                DoctorActionStatus::Applied => {
                    let reclaimed_bytes = mutation_receipt.affected_bytes;
                    action.reclaimed_bytes = reclaimed_bytes;
                    action.applied = true;
                    result.pruned_asset_count = result.pruned_asset_count.saturating_add(1);
                    result.reclaimed_bytes = result.reclaimed_bytes.saturating_add(reclaimed_bytes);
                    tracing::info!(
                        target: "cass::doctor::cleanup",
                        artifact_kind = "lexical_generation",
                        generation_id = %entry.manifest.generation_id,
                        disposition = lexical_cleanup_disposition_label(inventory.disposition),
                        path = %entry.path.display(),
                        planned_reclaimable_bytes = inventory.reclaimable_bytes,
                        reclaimed_bytes,
                        "pruned reclaimable lexical generation"
                    );
                }
                _ => {
                    let err = mutation_receipt.blocked_reasons.join("; ");
                    action.skipped = true;
                    action.skip_reason = Some(err.clone());
                    result.skipped_asset_count = result.skipped_asset_count.saturating_add(1);
                    result.warnings.push(err);
                }
            }
            action.mutation_receipt = Some(mutation_receipt);

            result.actions.push(action);
        }
    } else if plan.has_reclaimable_artifacts() {
        result.warnings.push(format!(
            "lexical cleanup apply skipped because dry-run gate blocked apply: {}",
            apply_gate.blocked_reasons.join("; ")
        ));
    }

    let after = collect_diag_quarantine_report(data_dir, index_path);
    fill_cleanup_after_summary(&mut result, &after);
    result.applied = result.pruned_asset_count > 0;
    finalize_cleanup_apply_contract(&mut result, data_dir, db_path, index_path);
    result
}

fn fill_cleanup_after_summary(result: &mut DiagCleanupApplyResult, after: &DiagQuarantineReport) {
    result.after_inventory = cleanup_apply_inventory_from_report(after);
    if let Some(plan) = after.lexical_cleanup_dry_run.as_ref() {
        result.after_generation_count = plan.generation_count;
        result.after_reclaim_candidate_count = plan.reclaim_candidates.len();
        result.after_reclaimable_bytes = plan.total_reclaimable_bytes;
        result.after_retained_bytes = plan.total_retained_bytes;
    }
}

fn cleanup_apply_inventory_from_report(report: &DiagQuarantineReport) -> DiagCleanupApplyInventory {
    let (lexical_cleanup_inventories, reclaim_candidates) = report
        .lexical_cleanup_dry_run
        .as_ref()
        .map(|plan| (plan.inventories.clone(), plan.reclaim_candidates.clone()))
        .unwrap_or_default();

    DiagCleanupApplyInventory {
        summary: report.summary.clone(),
        failed_seed_bundle_files: report.failed_seed_bundle_files.clone(),
        retained_publish_backups: report.retained_publish_backups.clone(),
        quarantined_artifacts: report.quarantined_artifacts.clone(),
        lexical_cleanup_inventories,
        reclaim_candidates,
    }
}

fn doctor_fs_mutation_receipt_for_request(
    request: &DoctorFsMutationRequest<'_>,
) -> DoctorFsMutationReceipt {
    DoctorFsMutationReceipt {
        schema_version: 1,
        operation_id: request.operation_id.to_string(),
        action_id: request.action_id.to_string(),
        mutation_kind: request.mutation_kind,
        fallback_kind: None,
        mode: request.mode,
        asset_class: request.asset_class,
        source_path: request
            .source_path
            .map(|source| source.display().to_string()),
        redacted_source_path: request
            .source_path
            .map(|source| doctor_redacted_path(&source.display().to_string(), request.data_dir)),
        target_path: request.target_path.display().to_string(),
        redacted_target_path: doctor_redacted_path(
            &request.target_path.display().to_string(),
            request.data_dir,
        ),
        staging_root: request.staging_root.map(|root| root.display().to_string()),
        redacted_staging_root: request
            .staging_root
            .map(|root| doctor_redacted_path(&root.display().to_string(), request.data_dir)),
        expected_source_blake3: request.expected_source_blake3.map(ToString::to_string),
        actual_source_blake3: None,
        actual_target_blake3: None,
        planned_bytes: request.planned_bytes,
        affected_bytes: 0,
        status: DoctorActionStatus::Blocked,
        blocked_reasons: Vec::new(),
        precondition_checks: Vec::new(),
        forensic_bundle: doctor_forensic_bundle_uncaptured(
            "not_captured_for_non_doctor_mutation_executor_call",
        ),
    }
}

fn execute_doctor_fs_mutation(request: DoctorFsMutationRequest<'_>) -> DoctorFsMutationReceipt {
    let receipt = doctor_fs_mutation_receipt_for_request(&request);
    match request.mutation_kind {
        DoctorFsMutationKind::PruneCleanupTarget => {
            execute_doctor_prune_cleanup_target(request, receipt)
        }
        DoctorFsMutationKind::RemoveStaleLegacyIndexLock => {
            execute_doctor_remove_stale_legacy_index_lock(request, receipt)
        }
        DoctorFsMutationKind::CopyFileToStaging => {
            execute_doctor_copy_file_to_staging(request, receipt)
        }
        DoctorFsMutationKind::WriteFileToStaging => {
            let mut receipt = receipt;
            receipt.blocked_reasons.push(
                "write file mutations require execute_doctor_fs_write_mutation with an explicit payload"
                    .to_string(),
            );
            receipt
        }
        DoctorFsMutationKind::PromoteStagedFile => {
            execute_doctor_promote_staged_file(request, receipt)
        }
        DoctorFsMutationKind::RestoreStagedFile => {
            execute_doctor_restore_staged_file(request, receipt)
        }
        DoctorFsMutationKind::MoveFileToQuarantine => {
            execute_doctor_move_file_to_quarantine(request, receipt)
        }
    }
}

#[allow(dead_code)]
fn execute_doctor_fs_write_mutation(
    request: DoctorFsWriteMutationRequest<'_>,
) -> DoctorFsMutationReceipt {
    let mut receipt = DoctorFsMutationReceipt {
        schema_version: 1,
        operation_id: request.operation_id.to_string(),
        action_id: request.action_id.to_string(),
        mutation_kind: DoctorFsMutationKind::WriteFileToStaging,
        fallback_kind: None,
        mode: request.mode,
        asset_class: request.asset_class,
        source_path: None,
        redacted_source_path: None,
        target_path: request.target_path.display().to_string(),
        redacted_target_path: doctor_redacted_path(
            &request.target_path.display().to_string(),
            request.data_dir,
        ),
        staging_root: Some(request.staging_root.display().to_string()),
        redacted_staging_root: Some(doctor_redacted_path(
            &request.staging_root.display().to_string(),
            request.data_dir,
        )),
        expected_source_blake3: None,
        actual_source_blake3: None,
        actual_target_blake3: None,
        planned_bytes: request.planned_bytes,
        affected_bytes: 0,
        status: DoctorActionStatus::Blocked,
        blocked_reasons: Vec::new(),
        precondition_checks: vec!["mutation_kind_write_file_to_staging".to_string()],
        forensic_bundle: doctor_forensic_bundle_uncaptured(
            "not_captured_for_non_doctor_mutation_executor_call",
        ),
    };

    if !doctor_repair_mode_allows_asset_operation_mutation(
        request.mode,
        request.asset_class,
        DoctorFsMutationKind::WriteFileToStaging.asset_operation(),
    ) {
        receipt.blocked_reasons.push(format!(
            "refusing to write staging asset class {:?}: mode {:?} does not allow staging write mutation",
            request.asset_class, request.mode
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("mode_allows_asset_operation".to_string());

    let payload_len = request.payload.len() as u64;
    if request.planned_bytes != payload_len {
        receipt.blocked_reasons.push(format!(
            "refusing to write staging target {}: planned_bytes={} does not match payload_bytes={payload_len}",
            request.target_path.display(),
            request.planned_bytes
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("planned_bytes_match_payload".to_string());

    let payload_blake3 = blake3::hash(request.payload).to_hex().to_string();
    if request.expected_payload_blake3 != payload_blake3 {
        receipt.blocked_reasons.push(format!(
            "refusing to write staging target {}: expected payload blake3 {}, observed {payload_blake3}",
            request.target_path.display(),
            request.expected_payload_blake3
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("expected_payload_blake3_matched".to_string());

    let Some(target_parent) = request.target_path.parent() else {
        receipt.blocked_reasons.push(format!(
            "refusing to write staging target without parent {}",
            request.target_path.display()
        ));
        return receipt;
    };
    if !target_parent.is_dir() {
        receipt.blocked_reasons.push(format!(
            "refusing to write staging target with missing parent {}",
            target_parent.display()
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("target_parent_exists".to_string());

    if !doctor_staging_target_path_is_safe(
        request.target_path,
        request.staging_root,
        request.data_dir,
    ) {
        receipt.blocked_reasons.push(format!(
            "refusing to write unsafe staging target {}",
            request.target_path.display()
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("target_path_confined_to_staging_root".to_string());

    match std::fs::symlink_metadata(request.target_path) {
        Ok(_) => {
            receipt.blocked_reasons.push(format!(
                "refusing to write over existing staging target {}",
                request.target_path.display()
            ));
            return receipt;
        }
        Err(err) if err.kind() == io::ErrorKind::NotFound => {}
        Err(err) => {
            receipt.blocked_reasons.push(format!(
                "refusing to write staging target {}: could not verify target absence: {err}",
                request.target_path.display()
            ));
            return receipt;
        }
    }
    receipt
        .precondition_checks
        .push("target_does_not_exist".to_string());

    let write_result = std::fs::OpenOptions::new()
        .write(true)
        .create_new(true)
        .open(request.target_path)
        .and_then(|mut file| {
            use std::io::Write as _;
            file.write_all(request.payload)
        });
    match write_result {
        Ok(()) => {
            receipt.affected_bytes = payload_len;
            receipt
                .precondition_checks
                .push("filesystem_write_completed".to_string());
        }
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(format!(
                "failed to write staging target {}: {err}",
                request.target_path.display()
            ));
            return receipt;
        }
    }

    let target_blake3 = match file_blake3_hex(request.target_path) {
        Ok(hash) => hash,
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(err);
            return receipt;
        }
    };
    receipt.actual_target_blake3 = Some(target_blake3.clone());
    if target_blake3 != payload_blake3 {
        receipt.status = DoctorActionStatus::Failed;
        receipt.blocked_reasons.push(format!(
            "written staging target {} hash mismatch: expected payload blake3 {payload_blake3}, observed target blake3 {target_blake3}",
            request.target_path.display()
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("target_blake3_matched_payload".to_string());

    match sync_file(request.target_path, "written staging target") {
        Ok(()) => {
            receipt
                .precondition_checks
                .push("target_file_sync_completed".to_string());
        }
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(err);
            return receipt;
        }
    }

    match sync_directory(target_parent) {
        Ok(()) => {
            receipt.status = DoctorActionStatus::Applied;
            receipt
                .precondition_checks
                .push("target_parent_sync_completed".to_string());
        }
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(err);
        }
    }
    receipt
}

fn execute_doctor_prune_cleanup_target(
    request: DoctorFsMutationRequest<'_>,
    mut receipt: DoctorFsMutationReceipt,
) -> DoctorFsMutationReceipt {
    receipt
        .precondition_checks
        .push("mutation_kind_prune_cleanup_target".to_string());

    if !doctor_repair_mode_allows_asset_operation_mutation(
        request.mode,
        request.asset_class,
        request.mutation_kind.asset_operation(),
    ) {
        receipt.blocked_reasons.push(format!(
            "refusing to prune asset class {:?}: cleanup_apply mode does not allow this mutation",
            request.asset_class
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("mode_allows_asset_class".to_string());

    if !doctor_asset_safe_to_gc(request.asset_class, true) {
        receipt.blocked_reasons.push(format!(
            "refusing to prune asset class {:?}: taxonomy does not allow automatic reclaim",
            request.asset_class
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("taxonomy_allows_automatic_reclaim".to_string());

    if !cleanup_target_path_is_safe(
        request.target_path,
        request.data_dir,
        request.db_path,
        request.index_path,
    ) {
        receipt.blocked_reasons.push(format!(
            "refusing to prune unsafe cleanup target {}",
            request.target_path.display()
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("path_confined_to_reclaimable_cleanup_target".to_string());

    let reclaimed_bytes = fs_dir_size(request.target_path);
    let remove_result = if request.target_path.is_dir() {
        std::fs::remove_dir_all(request.target_path)
    } else {
        std::fs::remove_file(request.target_path)
    };
    match remove_result {
        Ok(()) => {
            receipt.affected_bytes = reclaimed_bytes;
            receipt.status = DoctorActionStatus::Applied;
            receipt
                .precondition_checks
                .push("filesystem_remove_completed".to_string());
        }
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(format!(
                "failed to prune cleanup target {}: {err}",
                request.target_path.display()
            ));
        }
    }
    receipt
}

fn execute_doctor_remove_stale_legacy_index_lock(
    request: DoctorFsMutationRequest<'_>,
    mut receipt: DoctorFsMutationReceipt,
) -> DoctorFsMutationReceipt {
    receipt
        .precondition_checks
        .push("mutation_kind_remove_stale_legacy_index_lock".to_string());

    if !doctor_repair_mode_allows_asset_operation_mutation(
        request.mode,
        request.asset_class,
        request.mutation_kind.asset_operation(),
    ) {
        receipt.blocked_reasons.push(format!(
            "refusing to remove legacy index lock asset class {:?}: mode {:?} does not allow this mutation",
            request.asset_class, request.mode
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("mode_allows_asset_class".to_string());

    if request.asset_class != DoctorAssetClass::ReclaimableDerivedCache {
        receipt.blocked_reasons.push(format!(
            "refusing to remove legacy index lock as asset class {:?}: expected reclaimable derived cache",
            request.asset_class
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("asset_class_is_reclaimable_derived_cache".to_string());

    if !legacy_index_lock_path_is_safe(request.target_path, request.data_dir) {
        receipt.blocked_reasons.push(format!(
            "refusing to remove unsafe legacy index lock target {}",
            request.target_path.display()
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("path_confined_to_legacy_index_lock".to_string());

    if let Some(required_min_age_seconds) = request.required_min_age_seconds {
        let Some(age_seconds) = path_age_seconds(request.target_path) else {
            receipt.blocked_reasons.push(format!(
                "refusing to remove legacy index lock {}: could not verify file age",
                request.target_path.display()
            ));
            return receipt;
        };
        if age_seconds <= required_min_age_seconds {
            receipt.blocked_reasons.push(format!(
                "refusing to remove legacy index lock {}: age_seconds={age_seconds} is not greater than required_min_age_seconds={required_min_age_seconds}",
                request.target_path.display()
            ));
            return receipt;
        }
        receipt.precondition_checks.push(format!(
            "file_age_seconds_exceeds_{required_min_age_seconds}"
        ));
    }

    let reclaimed_bytes = fs_dir_size(request.target_path);
    match std::fs::remove_file(request.target_path) {
        Ok(()) => {
            receipt.affected_bytes = reclaimed_bytes;
            receipt.status = DoctorActionStatus::Applied;
            receipt
                .precondition_checks
                .push("filesystem_remove_completed".to_string());
        }
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(format!(
                "failed to remove legacy index lock {}: {err}",
                request.target_path.display()
            ));
        }
    }
    receipt
}

fn execute_doctor_copy_file_to_staging(
    request: DoctorFsMutationRequest<'_>,
    mut receipt: DoctorFsMutationReceipt,
) -> DoctorFsMutationReceipt {
    receipt
        .precondition_checks
        .push("mutation_kind_copy_file_to_staging".to_string());

    if !doctor_repair_mode_allows_asset_operation_mutation(
        request.mode,
        request.asset_class,
        request.mutation_kind.asset_operation(),
    ) {
        receipt.blocked_reasons.push(format!(
            "refusing to copy asset class {:?}: mode {:?} does not allow copy mutation",
            request.asset_class, request.mode
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("mode_allows_asset_operation".to_string());

    let Some(source_path) = request.source_path else {
        receipt
            .blocked_reasons
            .push("refusing to copy without a source path".to_string());
        return receipt;
    };
    let Some(staging_root) = request.staging_root else {
        receipt
            .blocked_reasons
            .push("refusing to copy without an approved staging root".to_string());
        return receipt;
    };

    if !doctor_copy_source_path_is_safe(source_path, request.data_dir) {
        receipt.blocked_reasons.push(format!(
            "refusing to copy unsafe source path {}",
            source_path.display()
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("source_path_confined_to_data_dir".to_string());

    let Some(parent) = request.target_path.parent() else {
        receipt.blocked_reasons.push(format!(
            "refusing to copy staging target without parent {}",
            request.target_path.display()
        ));
        return receipt;
    };
    if !parent.is_dir() {
        receipt.blocked_reasons.push(format!(
            "refusing to copy staging target with missing parent {}",
            parent.display()
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("target_parent_exists".to_string());

    if !doctor_staging_target_path_is_safe(request.target_path, staging_root, request.data_dir) {
        receipt.blocked_reasons.push(format!(
            "refusing to copy to unsafe staging target {}",
            request.target_path.display()
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("target_path_confined_to_staging_root".to_string());

    match std::fs::symlink_metadata(request.target_path) {
        Ok(_) => {
            receipt.blocked_reasons.push(format!(
                "refusing to overwrite existing staging target {}",
                request.target_path.display()
            ));
            return receipt;
        }
        Err(err) if err.kind() == io::ErrorKind::NotFound => {}
        Err(err) => {
            receipt.blocked_reasons.push(format!(
                "refusing to copy staging target {}: could not verify target absence: {err}",
                request.target_path.display()
            ));
            return receipt;
        }
    }
    receipt
        .precondition_checks
        .push("target_does_not_exist".to_string());

    let source_blake3 = match file_blake3_hex(source_path) {
        Ok(hash) => hash,
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(err);
            return receipt;
        }
    };
    receipt.actual_source_blake3 = Some(source_blake3.clone());
    receipt
        .precondition_checks
        .push("source_blake3_recorded".to_string());

    if let Some(expected) = request.expected_source_blake3
        && expected != source_blake3
    {
        receipt.blocked_reasons.push(format!(
            "refusing to copy source {}: expected blake3 {expected}, observed {source_blake3}",
            source_path.display()
        ));
        return receipt;
    }
    if request.expected_source_blake3.is_some() {
        receipt
            .precondition_checks
            .push("expected_source_blake3_matched".to_string());
    }

    match std::fs::copy(source_path, request.target_path) {
        Ok(bytes) => {
            receipt.affected_bytes = bytes;
            receipt
                .precondition_checks
                .push("filesystem_copy_completed".to_string());
        }
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(format!(
                "failed to copy {} to {}: {err}",
                source_path.display(),
                request.target_path.display()
            ));
            return receipt;
        }
    }

    let target_blake3 = match file_blake3_hex(request.target_path) {
        Ok(hash) => hash,
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(err);
            return receipt;
        }
    };
    receipt.actual_target_blake3 = Some(target_blake3.clone());
    if target_blake3 != source_blake3 {
        receipt.status = DoctorActionStatus::Failed;
        receipt.blocked_reasons.push(format!(
            "copied staging target {} hash mismatch: expected source blake3 {source_blake3}, observed target blake3 {target_blake3}",
            request.target_path.display()
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("target_blake3_matched_source".to_string());

    match sync_file(request.target_path, "copied staging target") {
        Ok(()) => {
            receipt
                .precondition_checks
                .push("target_file_sync_completed".to_string());
        }
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(err);
            return receipt;
        }
    }

    match sync_directory(parent) {
        Ok(()) => {
            receipt.status = DoctorActionStatus::Applied;
            receipt
                .precondition_checks
                .push("target_parent_sync_completed".to_string());
        }
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(err);
        }
    }
    receipt
}

fn execute_doctor_promote_staged_file(
    request: DoctorFsMutationRequest<'_>,
    mut receipt: DoctorFsMutationReceipt,
) -> DoctorFsMutationReceipt {
    receipt
        .precondition_checks
        .push("mutation_kind_promote_staged_file".to_string());

    if !doctor_repair_mode_allows_asset_operation_mutation(
        request.mode,
        request.asset_class,
        request.mutation_kind.asset_operation(),
    ) {
        receipt.blocked_reasons.push(format!(
            "refusing to promote asset class {:?}: mode {:?} does not allow promote mutation",
            request.asset_class, request.mode
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("mode_allows_asset_operation".to_string());

    let Some(source_path) = request.source_path else {
        receipt
            .blocked_reasons
            .push("refusing to promote without a staged source path".to_string());
        return receipt;
    };
    let Some(staging_root) = request.staging_root else {
        receipt
            .blocked_reasons
            .push("refusing to promote without an approved staging root".to_string());
        return receipt;
    };
    let Some(expected_source_blake3) = request.expected_source_blake3 else {
        receipt
            .blocked_reasons
            .push("refusing to promote without expected source blake3".to_string());
        return receipt;
    };

    if !doctor_staged_source_path_is_safe(source_path, staging_root, request.data_dir) {
        receipt.blocked_reasons.push(format!(
            "refusing to promote unsafe staged source path {}",
            source_path.display()
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("source_path_confined_to_staging_root".to_string());

    let Some(source_parent) = source_path.parent() else {
        receipt.blocked_reasons.push(format!(
            "refusing to promote source without parent {}",
            source_path.display()
        ));
        return receipt;
    };
    let Some(target_parent) = request.target_path.parent() else {
        receipt.blocked_reasons.push(format!(
            "refusing to promote target without parent {}",
            request.target_path.display()
        ));
        return receipt;
    };
    if !target_parent.is_dir() {
        receipt.blocked_reasons.push(format!(
            "refusing to promote target with missing parent {}",
            target_parent.display()
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("target_parent_exists".to_string());

    if !doctor_staged_rename_target_path_is_safe(
        request.target_path,
        staging_root,
        request.data_dir,
    ) {
        receipt.blocked_reasons.push(format!(
            "refusing to promote to unsafe target {}",
            request.target_path.display()
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("target_path_confined_to_data_dir".to_string());

    match std::fs::symlink_metadata(request.target_path) {
        Ok(_) => {
            receipt.blocked_reasons.push(format!(
                "refusing to promote over existing target {}",
                request.target_path.display()
            ));
            return receipt;
        }
        Err(err) if err.kind() == io::ErrorKind::NotFound => {}
        Err(err) => {
            receipt.blocked_reasons.push(format!(
                "refusing to promote target {}: could not verify target absence: {err}",
                request.target_path.display()
            ));
            return receipt;
        }
    }
    receipt
        .precondition_checks
        .push("target_does_not_exist".to_string());

    let source_blake3 = match file_blake3_hex(source_path) {
        Ok(hash) => hash,
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(err);
            return receipt;
        }
    };
    receipt.actual_source_blake3 = Some(source_blake3.clone());
    receipt
        .precondition_checks
        .push("source_blake3_recorded".to_string());

    if expected_source_blake3 != source_blake3 {
        receipt.blocked_reasons.push(format!(
            "refusing to promote source {}: expected blake3 {expected_source_blake3}, observed {source_blake3}",
            source_path.display()
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("expected_source_blake3_matched".to_string());

    let source_bytes = std::fs::metadata(source_path)
        .map(|metadata| metadata.len())
        .unwrap_or(request.planned_bytes);
    match doctor_move_file_with_cross_device_fallback(
        source_path,
        request.target_path,
        &source_blake3,
        source_bytes,
        "promote",
        "promoted target",
    ) {
        Ok(move_method) => {
            receipt.affected_bytes = source_bytes;
            receipt.fallback_kind = Some(move_method.receipt_fallback_kind().to_string());
            receipt
                .precondition_checks
                .push(move_method.receipt_precondition_check().to_string());
        }
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(err);
            return receipt;
        }
    }

    let target_blake3 = match file_blake3_hex(request.target_path) {
        Ok(hash) => hash,
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(err);
            return receipt;
        }
    };
    receipt.actual_target_blake3 = Some(target_blake3.clone());
    if target_blake3 != source_blake3 {
        receipt.status = DoctorActionStatus::Failed;
        receipt.blocked_reasons.push(format!(
            "promoted target {} hash mismatch: expected source blake3 {source_blake3}, observed target blake3 {target_blake3}",
            request.target_path.display()
        ));
        return receipt;
    }
    receipt
        .precondition_checks
        .push("target_blake3_matched_source".to_string());

    match sync_file(request.target_path, "promoted target") {
        Ok(()) => {
            receipt
                .precondition_checks
                .push("target_file_sync_completed".to_string());
        }
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(err);
            return receipt;
        }
    }

    match sync_directory(source_parent).and_then(|()| sync_directory(target_parent)) {
        Ok(()) => {
            receipt.status = DoctorActionStatus::Applied;
            receipt
                .precondition_checks
                .push("source_and_target_parent_sync_completed".to_string());
        }
        Err(err) => {
            receipt.status = DoctorActionStatus::Failed;
            receipt.blocked_reasons.push(err);
        }
    }
    receipt
}

